INSERT INTO `article` VALUES (15,'澳洲留学奖学金政策正逐步放宽','澳洲留学奖学金政策正在逐步放宽，新开设奖学金的专业大多是工程专业，所以建议学生不要片面地集中去报读会计、国际贸易等热门的商科专业，选择一些工程、设计等技术含量相对较高、学术要求更严格的专业将会更有利于将来的发展。',NULL,NULL,0,NULL,0,'2013-08-09 14:28:01',0,15),(9,'留学这些事：打工那些事','《留学这些事》新老留学生对话分享各自的打工经历！','/articlePic/9.png','N',0,'N',0,'2013-08-07 15:19:14',0,21),(12,'留学这些事：如何移民澳洲','来自新澳东国际咨询服务中心的梁维东老师做客解答你所关注的“移民”问题','/articlePic/12.png','N',0,'N',2,'2013-08-07 16:23:41',0,21),(11,'留学这些事：澳洲留学择校攻略','新澳东国际咨询服务中心移民首席顾问梁维东老师给大家带来澳洲择校及专业选择的完全攻略。','/articlePic/11.png','N',0,'N',3,'2013-08-07 16:21:16',0,21),(13,'留学这些事：如何找到专业工作','新澳东国际咨询服务中心的资深顾问梁维东老师根据澳洲就业环境给想在澳洲找专业工作的留学生们一些实用的建议。','/articlePic/13.png','N',0,'N',1,'2013-08-07 16:25:54',0,21),(16,'2009留学市场的走势分析','',NULL,NULL,0,NULL,0,'2013-08-09 14:42:39',0,15),(17,'优良体系成就澳洲教育特色及优势','与其它西方国家相比，澳大利亚是个安全的地方，环境舒适，安宁，学生可以安心学习，并可自由旅行。澳大利亚是个多元文化汇萃的国家，种族多元化也是很多院校的特色。澳大利亚的学校不但十分欢迎海外留学生，而且很关注学生不同的需要。',NULL,NULL,0,NULL,0,'2013-08-09 14:45:12',0,15),(18,'留学澳洲的五大优势','澳洲具有的五大优势：教育质量，经济体系，生活环境，留学费用，移民政策',NULL,NULL,0,NULL,0,'2013-08-09 14:49:31',0,15),(19,'相比其他国家为什么选澳洲留学','相比于其他几个主要的留学国家，澳大利亚具有吸引国际学生的显著优势。',NULL,NULL,0,NULL,0,'2013-08-09 14:50:43',0,15),(20,'澳洲的教育拥有相当高的国际声誉','澳洲的大学在教育和培训各方面，都拥有相当高的国际声誉。',NULL,NULL,0,NULL,0,'2013-08-09 14:51:37',0,15),(21,'2009年留学澳洲的七个新动向','2009年留学澳洲的七个新动向',NULL,NULL,0,NULL,0,'2013-08-09 14:52:28',0,15),(22,'澳大利亚教育概况','自从澳大利亚联邦建立以来，澳大利亚的教育经历了巨大的变化。',NULL,NULL,0,NULL,0,'2013-08-09 14:54:00',0,15),(23,'聪明人首选澳大利亚留学','中国人留学为了啥，90%以上都是为了毕业后移民找工作享受生活，有几个有资格移民却最后回到中国的。',NULL,NULL,0,NULL,0,'2013-08-09 14:55:38',0,15),(24,'澳高等教育系统全球排第八 受益于留学生','据澳大利亚媒体报道，一项针对高等教育系统进行排名的研究显示，尽管澳洲在教育资源方面投入较低，但是毕业生人数以及研究成果却不凡，因此在全球排名第8位。',NULL,NULL,0,NULL,0,'2013-08-09 14:57:39',0,15),(25,'“平价方案”2款 澳洲留学省10万','相对美英等国昂贵的留学成本，以及令人堪忧的就业前景，身处南半球的澳大利亚反倒成为一个利于安心留学的平静港湾，成为诸多中国学生海外留学的上选。',NULL,NULL,0,NULL,0,'2013-08-09 14:59:49',0,16),(26,'专家高考之后话留学：择校之前先定位','举几个我曾经咨询过的赴澳洲留学案例，来进一步说明不同类型的学生应该如何定位留学方向。',NULL,NULL,0,NULL,0,'2013-08-09 15:00:39',0,16),(27,'对白领人群留学澳洲的指导建议','白领人群也会成为赴澳留学的一支生力军。因为对学历的渴望、知识的渴望会比刚毕业就要留学的学生会更迫切一些，资金也已经到位了, 所以这部分学生在选择留学的时候会更积极。',NULL,NULL,0,NULL,0,'2013-08-09 15:02:12',0,16),(28,'赴澳就读中学情况简介','澳大利亚的中小学是十二年制，一年级到六年级为小学，七年级到十二年级是中学。其中七年级到九年级为初中部（相当于中国的初一到初三），九年级到十二年级为高中部（相当于中国的高一到高三）。十二年级是特殊的一年，因为在这一年中，中学生们要做中学毕业的准备，并参加中学毕业考试。这个中学毕业考试的成绩是做为进入大学的唯一参考成绩。',NULL,NULL,0,NULL,0,'2013-08-09 15:03:25',0,16),(29,'高中生规划出国留学五点精析','由于不少家庭今年银根紧缩，相对于美、英等，澳大利亚、加拿大等国家由于费用相对便宜，而备受家长青睐。专家建议，这些“低龄高中生”在准备留学前，最好能提前半年就做专业咨询。',NULL,NULL,0,NULL,0,'2013-08-09 15:05:35',0,16),(30,'中学生留学澳洲,何时申请最合适?','对于有送孩子出国留学的家长，对于有目标和勇气出国读书的中学生来讲，什么时间是办理出国留学手续最合适的时机呢？选择什么样的国家送孩子出国读中学最好呢？该怎么安排国外的语言和中学课程的学习计划，最经济最省时间呢？',NULL,NULL,0,NULL,0,'2013-08-09 15:06:54',0,16),(31,'维州公立中学值得你选择的原因','对国际留学生而言，选择一个合适的学校就读无疑是他们留学生涯中最重要的一个决定。我们相信，维多利亚州的政府公立中学有以下值得你选择她的原因。',NULL,NULL,0,NULL,0,'2013-08-09 15:08:10',0,16),(32,'哪些学生适合读澳洲TAFE课程','究竟什么样的人群适合选择到澳大利亚读TAFE 课程？是否所有的学生都适合TAFE 课程？不同的人群如何选择正确的TAFE专业？已经成为越来越多准留学生的困惑。',NULL,NULL,0,NULL,0,'2013-08-09 15:09:43',0,16),(33,'最适合的课程才是最好的课程','我从事留学生办理工作7年，经手的案例很多，成功的、失败的，都与境内办理之前的选择有很大关系，希望与大家探讨、学习，寻找最适合的课程，‘最适合的课程才是最好的课程’',NULL,NULL,0,NULL,0,'2013-08-09 15:11:32',0,16),(34,'大学生留学方案','澳大利亚高等教育概况',NULL,NULL,0,NULL,0,'2013-08-09 15:13:26',0,16),(35,'中学生留学方案','澳大利亚的中小学是十二年制，一年级到六年级为小学，七年级到十二年级是中学。其中七年级到九年级为初中部（相当于中国的初一到初三），十年级到十二年级为高中部（相当于中国的高一到高三）。十二年级是特殊的一年，因为在这一年中，中学生们要做中学毕业的准备，并参加中学毕业考试。这个中学毕业考试的成绩是做为进入大学的唯一参考成绩。',NULL,NULL,0,NULL,0,'2013-08-09 15:18:01',0,16),(36,'浅谈澳洲大学排名及相关','看到很多人在这里谈论澳洲大学的排名，哪个学校的会计好，本人觉得没有什么实际价值。故发表一些浅显的看法。',NULL,NULL,0,NULL,0,'2013-08-09 15:23:00',0,17),(37,'如何选择澳大利亚传媒专业','“传媒”这个词应该来自于英文的medium，汉语词典里的解释很简单，意思就是传播媒介（指广播、电视、报刊，网络等）。近几年，随着留学业的不断发展，越来越多的人开始有机会接触到传媒这门学科，那么关于传媒学我们到底可以从中学习到什么，将来又可以从事什么样的工作呢？',NULL,NULL,0,NULL,0,'2013-08-09 15:24:22',0,17),(38,'走出澳大利亚大学排名的误区','近日了解到很多学生和家长垂询赴澳留学事宜时，经常问到澳洲某大学在国内的名次，旨在了解学校水平的高下。但澳大利亚教育当局从未给自己的大学排过名，因为这是一桩十分困难的事，不仅涉及到相当复杂的数据统计和准确的评估，而且评估往往会搀杂种种说不清道不明的主观因素，容易失之偏颇。',NULL,NULL,0,NULL,0,'2013-08-09 15:25:13',0,17),(39,'除八大外哪些大学联盟有特色','一提起澳大利亚的高等院校，通常人们都会想到“八大”。“八大”是澳大利亚最顶尖的八所大学组成的大学集团的简称，在澳大利亚的大学中享有崇高的地位。“八大”的成员包括：阿德雷德大学、澳大利亚国立大学、墨尔本大学、蒙纳士大学、新南威尔士大学、昆士兰大学、悉尼大学、西澳大利亚大学。',NULL,NULL,0,NULL,0,'2013-08-09 15:26:31',0,17),(40,'世界百强名校——澳洲拉筹伯大学','拉筹伯大学建校于1964年，是澳大利亚最大的、发展最快的、由政府出资兴办的一流大学之一。目前，拉筹伯大学拥有超过26,000在校学生，其中包括来自60多个国家的3,000名国际学生。拉筹伯大学因其在教学和研究领域的卓越成就而享誉全球，被英国泰晤士报评为全世界最佳150所大学之一，同时被墨尔本应用经济和社会研究院评为澳大利亚最佳10的大学之一。拉筹伯大学还与全世界260多所大学建立了科研和交流的纽带并开展了广泛的合作研究。',NULL,NULL,0,NULL,0,'2013-08-09 15:27:22',0,17),(41,'申请澳大利亚名校的窍门','申请海外名牌大学是每个出国留学学生的梦想，由于对境外大学的不了解，学生往往只能选择耳熟能详的各别大学造成学生申请集中。所以大学才不断抬高门槛，来限制越来越多的入学申请，使很多学生失去进入名校学习的机会。如何抓住机遇申请澳大利亚名校有一些窍门，下边给大家介绍一些方法',NULL,NULL,0,NULL,0,'2013-08-09 15:28:36',0,17),(42,'2009年最新澳洲大学排名','与其它国家不同，澳大利亚国内没有专业的大学排名，所以我们在这里的澳洲大学排名是指澳洲的大学在世界上的排名。目前，世界上认可度最高的大学排名有三个，分别是英国的TIMES世界大学排名、上海交大版世界大学学术500强排名，以及美国新闻周刊的世界大学100强排名。',NULL,NULL,0,NULL,0,'2013-08-09 15:29:32',0,17),(43,'澳大利亚大学名单(按地区分类)','澳大利亚大学名单(按地区分类)',NULL,NULL,0,NULL,0,'2013-08-09 15:31:07',0,17),(44,'澳洲热门专业大学排名—护士专业','一提起护士，很多中国的学生和家长马上联想到繁重的工作量和嘈杂的工作环境，这种情况在中国的医院里的确是这样，但在西方，尤其是福利制度发达、人口稀少的澳大利亚去完全不是这样，而且澳大利亚的护理人员不仅从事帮助病人“打针吃药”的日常工作，而且能使用各种高新的设备，配合医生对病人做出全面的诊断和看护。',NULL,NULL,0,NULL,0,'2013-08-09 15:31:59',0,17),(45,'热门专业攻略:浅谈澳洲精算专业','一般来讲，在赴澳洲留学的中国学生中，80%的学生会选择商科就读，商科下面包括了会计，金融，应用金融，人力资源管理，市场，管理等专业，尤其会计专业由于目前属于澳洲技术移民职业中的紧缺职业而获得了更多留学生的青睐，然而，随着赴澳留学生的不断增加，这些选修商科的学生毕业之后势必会面临着激烈的竞争，此时另一个之前不被学生所了解的商科专业逐渐浮出水面，这就是目前被称为金领职业的精算专业。',NULL,NULL,0,NULL,0,'2013-08-09 15:33:49',0,17),(46,'拉筹伯大学土木工程系奖学金 – Bendigo 校区','该奖学金的设置是为了吸引想学工程学士（土木工程）的学生到La Trobe大学的Bendigo校区学习，并为学生们提供到维省郊区就业的机会，因为那里目前正面临着土木工程师的技能短缺。',NULL,NULL,0,NULL,0,'2013-08-09 15:35:41',0,17),(47,'澳洲5大热门专业就业前景分析','由于我国正在大力发展第三产业，并且澳大利亚本身也是强调“无烟工业”，注重第三产业的国家，因此服务业中的金融、咨询、大众传媒、创意产业等相关专业的就业前景也是十分广阔的。',NULL,NULL,0,NULL,0,'2013-08-09 15:36:37',0,17),(48,'2013澳洲留学 五大热门高薪职业盘点','如今越来越多的家长意识出国留学选择高薪职业才是真正的王道，所以在考虑专业的选择时，应该关注一下回国后的就业发展情况，那么哪些职业最有“钱途”呢？',NULL,NULL,0,NULL,0,'2013-08-09 15:38:00',0,17),(49,'留学澳洲 最难申请的专业及大学清单','中国学生和家长的名校情结由来已久，在对待出国留学选校选专业问题也是这样。比如赴澳洲留学，就一定要读澳洲八大名校。然而，名校有名校的定位和标准，学生和家长盲目选择，只会陷入一些误区，导致留学失败。',NULL,NULL,0,NULL,0,'2013-08-09 15:39:50',0,17),(50,'澳大利亚各类移民专业起薪','澳大利亚各类移民专业起薪',NULL,NULL,0,NULL,0,'2013-08-09 15:41:14',0,17),(51,'澳洲留学签证的类型有哪些','澳洲留学签证的类型有哪些',NULL,NULL,0,NULL,0,'2013-08-09 15:42:30',0,18),(52,'申请澳大利亚签证技巧','每年的7、8月份是澳大利亚的开学高峰期，如果想在这一时间段入学的学生，现在要开始着手签证申请工作了，因为澳大利亚的签证申请，尤其是常规申请的周期较长，如果不早做准备的话，很有可能耽误开学。现编者就签证申请需做的准备工作以及不同的签证方式流程等方面做重点的介绍。',NULL,NULL,0,NULL,0,'2013-08-09 15:43:20',0,18),(53,'澳大利亚留学的申请要求和条件','澳大利亚留学的申请要求和条件',NULL,NULL,0,NULL,0,'2013-08-09 15:44:27',0,18),(54,'简析澳洲留学签证材料之资金情况','签证材料由于经济状况导致拒签的情况，也特别提出了申请人必须有足够的经济能力支付你在澳洲学习生活的全部费用。顺利拿到签证的理由主要集中在以下三个方面：',NULL,NULL,0,NULL,0,'2013-08-09 15:45:21',0,18),(55,'出国留学怎么汇款最划算','出国留学的高峰又要到了，根据海关规定，出境最多只能带５０００美元现金或等值外币。那么对于出国留学的人来说，汇款就成为必不可少的程序。现在汇款方式多种多样，主要的包括电汇、汇票、西联汇款、速汇金、国际卡、旅行支票等，但是这些方式的到账时间、费用不等。如何选择适合、最省钱的汇款方式呢？江苏省中行汇款业务专家日前给市民支招。',NULL,NULL,0,NULL,0,'2013-08-09 15:46:17',0,18),(56,'专家详解赴澳留学签证被拒原因','申请留学热门国澳大利亚签证的中国学生常常遇到被拒签的情况，那么申请澳大利亚签证的难点和重点到底在哪里，为什么留学澳大利亚会被拒签呢？',NULL,NULL,0,NULL,0,'2013-08-09 15:47:15',0,18),(57,'签证周期是和很多因素密切相关的','签证周期是和很多因素密切相关的，主要分以下几个因素',NULL,NULL,0,NULL,0,'2013-08-09 15:48:09',0,18),(58,'澳大利亚留学签证申请注意事项','据统计，近几年澳大利亚留学签证申请获签率颇高，但这并不意味着澳大利亚签证是可以轻而易举的获得，整个申请过程中有诸多事项需要注意。',NULL,NULL,0,NULL,0,'2013-08-09 15:49:07',0,18),(59,'学生签证所需文件清单','适用于申请赴澳大利亚留学的常住在中国或新西兰的中国公民',NULL,NULL,0,NULL,0,'2013-08-09 15:50:25',0,18),(60,'雅思成绩豁免可以接受AEAS考试','超过70所的学校已获澳大利亚政府批准，在头两年的英文IELTS成绩豁免规定期间可以接受AEAS考试的成绩。随着更多的学校向澳大利亚政府提出申请，获澳大利亚政府批准的可以接受AEAS考试成绩的学校数量还会增加。',NULL,NULL,0,NULL,0,'2013-08-09 15:52:02',0,19),(61,'澳洲部分院校今年提高雅思成绩','2009年，雅思成绩提高得比较明显的是澳洲院校。比如澳洲蒙纳士大学，从以前的6.5分提升到7分；墨尔本大学商学院将提高其研究生课程入学的雅思要求，在原要求的基础上，要求学生加考GMAT，且需达550分以上。',NULL,NULL,0,NULL,0,'2013-08-09 15:53:16',0,19),(62,'想赴澳洲读中学先参加AEAS考试','留学顾问建议，去澳大利亚读中学，不妨先参加澳大利亚教育评估服务机构组织的英语水平考试AEAS考试，该考试被称为“中学生的雅思”，已经有相当数量的中学获得澳大利亚政府的批准，允许招收完成AEAS考试评估的学生，而且该考试分数越高，越有可能申请到好的中学。',NULL,NULL,0,NULL,0,'2013-08-09 15:54:03',0,19),(63,'雅思改革 中国考生签证机会多','随着新托福难度增加但认可范围的缩小，雅思考试成为越来越多准备出国人员的不二选择。据相关统计2007年雅思考试参加人数比2006年增长了50%，以往天津每月1场的考试现在已增加到平均每月2场，考生仍需要提前3-4个月报名才能获得考位。据英国文化处官方消息，2008年雅思考试将在阅读方面加入商务英语文章，以提高考试的学术色彩。',NULL,NULL,0,NULL,0,'2013-08-09 15:54:57',0,19),(64,'最新雅思考试政策专家解读','2008~2009年雅思考试政策有不少变化本报特邀专家进行解读',NULL,NULL,0,NULL,0,'2013-08-09 15:56:01',0,19),(65,'雅思考试 你究竟了解多少？','今年，恰逢雅思(IELTS)考试在中国迎来自己二十周岁生日，对雅思考试来说，其在中国的发展已日臻成熟、并迅速成长为值得依赖的国际性英语考试。正如英国文化协会考试部中国业务总监史哲明所言，“去年，全球有超过一百二十万考生参加了雅思考试，其中两成多为中国考生，总数超过二十六万人。中国学生保证了雅思作为全球英语(论坛)考试领头羊的地位。”',NULL,NULL,0,NULL,0,'2013-08-09 15:57:05',0,19),(66,'IELTS考试及未来发展趋势','在北京召开的IELTS记者招待会上，IELTS考试专家透露了IELTS考试2008年的中国发展计划以及全球发展趋势，并回顾了IELTS考试在中国所取得的成就。',NULL,NULL,0,NULL,0,'2013-08-09 15:58:05',0,19),(67,'专科生何去何从？','这句话听起来好像很耳熟，但又不完全正确，没错！上帝为你关上一扇门，一定会为你打开一扇窗是原版，但经过这次小转折后，觉得上面的这句话更能体现出我此时此刻的心情。',NULL,NULL,0,NULL,0,'2013-08-09 15:59:21',0,20),(68,'澳大利亚的兼职工作','获取学生签证的十五岁以上的外国学生经父母许可可在澳洲兼职工作。学生在读书期间每周最多可以工作20小时；假期可以全日工作(每周约35小时)。但是外国海外学生必须向移民和多元文化事务部提出工作申请，并在抵澳开始学业后才能工作。学生申请工作的费用是55澳元。学生家属工作的权利有所不同（研究生家属打工不受每周20小时限制），因课程长短而异，但要到当地移民部申请兼职学生签证。',NULL,NULL,0,NULL,0,'2013-08-09 16:00:22',0,20),(69,'澳大利亚中学学期制度','澳大利亚中学体制来说，虽然也是一个学年分为两个Semester(学期)，但这个学期的概念在当地人的心中非常模糊或者说几乎没有，他们主要是说Term(学期)。然而此学期(Term)非彼学期(Semester)，一个大学期(Semester)由两个小学期(Term)组成。换句话说，澳大利亚中学学期设置里面一个大学期包括有两个小学期，一个学年总共就有了四个小学期。',NULL,NULL,0,NULL,0,'2013-08-09 16:01:39',0,20),(70,'留学澳洲：选择住宿家庭还是学校公寓','对于初次来到澳洲的中国学生来说，住宿一直是家长和学生相对比较关注的问题。对于海外学生来说，澳洲的住宿大致可以分为，住宿家庭，学校公寓和校外合租3种，但是对于刚刚踏上澳洲国土，对身边的环境还非常陌生的中国学生来说，一般住宿家庭和学校公寓会他们首先会考虑的。然而，既然有住宿家庭和学校公寓两种选择，那学生到底应该选择哪一种才适合自己呢?',NULL,NULL,0,NULL,0,'2013-08-09 16:02:24',0,20),(71,'澳洲寄宿家庭','澳洲寄宿家庭（Homestay）的定义是澳大利亚的家庭向国际学生开放，接受海外学生成为他们的家庭成员。海外学生可和这个家庭成员一起吃、住、购物、郊游，参加该家庭的各种活动。寄宿家庭服务是适应于澳洲教育输出，接受外国留学生来澳所应运而生的。',NULL,NULL,0,NULL,0,'2013-08-09 16:03:33',0,20),(72,'澳大利亚留学之衣食住行','澳大利亚的生活基本用品不是很贵，因此根据个人情况，有选择的携带即可。对于学生来说，可多带休闲装。同时，最好携带一些和中国不同的东西，比如三眼电源转换插座、个人护理护肤用品和电脑用的网线电话线等。此外建议学生可以带些当地的邮票和明信片，作为礼物既不会太贵重、又比较有特色。',NULL,NULL,0,NULL,0,'2013-08-09 16:04:33',0,20),(73,'堪培拉, 布理斯班与黄金海岸','',NULL,NULL,0,NULL,0,'2013-08-09 16:07:39',0,20),(74,'留学这些事：两代留学生谈澳洲生活体验','中国留学生在澳大利亚注册入学人数已近20万，是澳大利亚最大的留学生群体。如今澳大利亚已遍布中国留学生的脚印。本期《留学这些事》从两代中国留学生的讲述里，我们可以了解更多澳洲留学环境的变化和时代的变迁。','/articlePic/74.png',NULL,0,NULL,10,'2013-08-10 14:19:34',0,21),(75,'澳大利亚商业投资移民 188签证申请评分标准','新的188签证，即临时商业创新和投资签证（Provisional Business Innovation and Investment visa）的申请人必须在“创新打分测试”（Innovation points test）中得到至少65分。',NULL,NULL,0,NULL,0,'2013-09-12 04:50:14',0,28),(76,'澳洲商业投资移民签证简介','2012年5月25日，澳洲移民局宣布了商业移民新政的整体框架，政府彻底改革了现有的商业技术签证项目，将其重新命名为“商业创新与投资”项目，并对其指导纲要进行修改。原先13类商业移民项目合并为3类，而之前颇受国内同胞青睐的163转892商业移民正式退出历史舞台，为新的188转888签证类别所替代，新的商业移民政策已从2012年7月1日起正式施行。',NULL,NULL,0,NULL,0,'2013-09-12 04:56:52',0,28),(77,'2013年澳洲商业移民签证要求对照表','2013年四类澳洲商业移民签证要求详细对照，包括适用人群，签证类别，永居条件等等。',NULL,NULL,0,NULL,0,'2013-09-12 05:01:32',0,28),(78,'投资500万澳币就可获得澳洲绿卡','澳大利亚移民部长2012年8月29日公布了《巨额投资者类签证》详情，只要投资500万澳元，无论其年龄、英文如何，均可以申请澳洲188商业移民签证，4年以后满足居住条件，就可得到888永居签证。新签证从2012年11月24日起实施。',NULL,NULL,0,NULL,0,'2013-09-12 05:17:22',0,28),(79,'持163签证登陆以后','对申请人来说，获得商业临时签证（如163签证）还只是获得永久居留成功的第一步。他们在获得临时签证抵达澳洲后，还会有大量事务性的事情需要操办，如购买房产，孩子入学，注册公司，寻找生意等。',NULL,NULL,0,NULL,0,'2013-09-12 05:18:43',0,28),(80,'澳大利亚500万重大投资者移民签证','“机不可失，时不再来。”首次700个发放移民指标，数量有限，很有可能一抢而空，因为很多潜在的申请人除来自中国大陆外，东南亚、印度、南美、俄罗斯和中国台湾的富商也十分感兴趣。“先到先得，不能保证未来不会提高各种门槛，或许将不复存在也未可知。”',NULL,NULL,0,NULL,0,'2013-09-12 05:19:51',0,28),(81,'澳洲移民的心路历程','踏上澳洲移民之路纯属一个偶然, 在中国工作创业的10多年,我从事的一直是比较前端的广告营销,市场推广新兴行业,随着业务的不断发展,感觉自己的事业慢慢达到了一个瓶颈状态,非常希望到海外获取一些新的发展平台以及新的创业思路.尤其是英语能力的提高. 在对澳洲进行了一系列的考察后,觉得澳洲是个非常适合工作和生活的国家。',NULL,NULL,0,NULL,0,'2013-09-12 05:21:22',0,28),(82,'PR在澳居住两年的解释','',NULL,NULL,0,NULL,0,'2013-09-12 05:24:47',0,30),(83,'政府将延长父母探亲签证的逗留期限','澳大利亚移民和公民部部长，国会议员克里斯·鲍恩宣布：吉拉德政府将延长澳大利亚公民和永久居民的父母探亲签证的逗留期限，以使他们来澳洲探亲时能够呆得更久',NULL,NULL,0,NULL,0,'2013-09-12 05:25:57',0,33),(84,'父母移民常见问题','家庭移民常见问题及解答，如申请人必须通过家庭平衡测试，申请人的子女至少有一半在澳洲定居; 或者申请人在澳洲定居的子女比在其他任何一个国家都多等等。',NULL,NULL,0,NULL,0,'2013-09-12 05:28:00',0,33),(85,'父母移民的基本要求','父母移民基本条件要求，包括孩子需要是澳洲公民或永久居民或是符合要求的在澳新西兰公民，并满足在澳洲居住2年的要求等等。',NULL,NULL,0,NULL,0,'2013-09-12 05:29:43',0,33),(86,'父母移民类别简介','父母移民可分为普通父母移民（parent category）和付费父母移民（contributory parent category）',NULL,NULL,0,NULL,0,'2013-09-12 05:31:00',0,33),(87,'配偶海外申请签证的两个选择','关于配偶签证可以有两种选择。',NULL,NULL,0,NULL,0,'2013-09-12 05:33:26',0,30),(88,'配偶签证申请注意事项','在申请临时居留签证时，申请人需具备以下条件：由澳洲公民、永久居民及合格的新西兰公民为其担保，担保人至少18岁以上。与担保人结婚，属合法且真实持久的关系，打算到澳洲后继续此关系。　',NULL,NULL,0,NULL,0,'2013-09-12 05:34:33',0,30),(89,'中国买家频繁出手引发担忧 外媒称中国正买世界','一些中国人正以自己的方式撩拨世人的神经。他们在海外市场上甩出的大把钞票，让外国人一次次瞪大双眼。',NULL,NULL,0,NULL,0,'2013-09-12 05:36:21',0,32),(90,'中国人炒澳洲房产 一不留神三年赚上百万','就在中国国内对房地产限购之际，不少先知先觉的炒房人将目光投向了澳洲。南京范女士3年前花200万元在墨尔本买了一套房，最近已升值了100多万，3年收益率近60%。据业内人士介绍，目前在南京的高端人群中已形成一股投资澳洲房产的热潮。',NULL,NULL,0,NULL,0,'2013-09-12 05:41:25',0,32),(91,'墨尔本居民人口十年内有可能超悉尼','在澳洲，除了墨尔本之外没有哪座城市的人口有如此快的增长速度。随之给基础设施和公共服务带来了很大压力，公共交通拥挤、出行缓慢、医院急诊等待时间太长等等。这或许是工党2010年维省大选溃败的关键原因。人们不免担心，墨尔本多次名列世界最宜居城市前三甲，在人口暴增的趋势面前，还能保持优势吗？',NULL,NULL,0,NULL,0,'2013-09-12 05:49:00',0,32),(92,'如果在澳洲购买房产','澳洲政府一向把房地产业作为主要的支柱产业大力扶持，采取多项措施支持其发展，企业界尤其是金融界也采取了相应的举措。其中一项重要的政策就是鼓励海外人士买入澳洲房产，作为其个人投资组合的一部分，共同打造了一个对全世界开放的个人房地产投资市场。那末作为海外人士，甚至从未来过澳洲的人士，都可以享受到那些支持呢？',NULL,NULL,0,NULL,0,'2013-09-12 05:49:43',0,32),(93,'不破的泡沫：走入迷途的中国房价','2002年以来中国的房地产市场逐步升温，经过2003年的大幅上涨，2004年1到9月份的全国商品房价格涨幅仍达到了13%，商品房平均价格达到2777元，相比2002年底，在两年不到的时间里，价格上涨超过四分之一。对于住房这种关系到国计民生的特殊商品来说，这样的涨幅堪称暴涨。',NULL,NULL,0,NULL,0,'2013-09-12 05:53:05',0,32),(94,'2012年澳技术移民职业封顶配额出台','随着EOI的出台，澳大利亚移民局开始按照市场需要设置给具体各专业的移民配额，这个配额直接关系各类打分的技术类移民的邀请机会，也是移民局希望大家不要一窝蜂选择同一个专业的手段。',NULL,NULL,0,NULL,0,'2013-09-12 05:54:26',0,27),(95,'EOI需要关注的申请事项','对于技术移民来说，是要SOL职业的才可以递交！此外必须完成了完整的职业评估和达到雅思最低要求，才可以提交，否则无效！材料无需上传，但是如果你提供虚假的材料，日后审理到了就会视为人品问题，不但拒签，可能以后也无法再移民！',NULL,NULL,0,NULL,0,'2013-09-12 05:55:57',0,27),(96,'新旧打分制度的对照','',NULL,NULL,0,NULL,0,'2013-09-12 05:57:49',0,27),(97,'最新中英文职业清单（SOL）July 2013','最新中英文职业清单（SOL）July 2013',NULL,NULL,0,NULL,0,'2013-09-12 06:01:32',0,27),(98,'186ENS签证和187RSMS 申请要求','从2012年7月1日，旧有的6种雇主担保永居签证种类将归类于2种类别，名为186ENS签证和187RSMS签证。 ',NULL,NULL,0,NULL,0,'2013-09-12 06:09:01',0,29),(99,'2012年7月澳洲雇主担保移民大变革解析','雇主担保移民和普通技术移民的区别主要在于，普通技术移民要开始EOI的邀请政策，打分高的申请人优先移民，不过雇主担保类的不受EOI影响，可以直接申请PR。',NULL,NULL,0,NULL,0,'2013-09-12 06:10:27',0,29),(100,'2012年澳洲独立技术和雇主担保类移民要求对照表','2012年澳洲独立技术和雇主担保类移民要求对照表',NULL,NULL,0,NULL,0,'2013-09-12 06:11:43',0,29),(101,'2013年7月1日457新政概要','457新政与之前出过的草案没有太大差别，本文详细分析了主要的变化。',NULL,NULL,0,NULL,0,'2013-09-12 06:14:27',0,29),(102,'澳大利亚商业签证','457商业签证主要有以下三种： 1． 到澳大利亚进行投资或合资的独立海外商业业主； 2． 到澳大利亚设立分公司的海外公司代表； 3． 到澳大利亚公司工作的海外申请人457商业签证主要有以下三种： 1． 到澳大利亚进行投资或合资的独立海外商业业主； 2． 到澳大利亚设立分公司的海外公司代表； 3． 到澳大利亚公司工作的海外申请人.',NULL,NULL,0,NULL,0,'2013-09-12 06:15:43',0,29),(103,'在澳留学生如何申请457工作签证','随着澳洲技术移民的收紧，雇主担保类别的成为一个很好的方案。申请856的雇主担保移民，移民局要求申请人要么有3年的工作经验，要么有2年的工作签证。所以工作签证457再度成为留学生关注的焦点。',NULL,NULL,0,NULL,0,'2013-09-12 06:16:57',0,29),(104,'2011年墨尔本折桂“世界最宜居城市”',' 英国《经济学家》信息部8月30日公布最新世界宜居城市榜，澳大利亚墨尔本获选第一名，过去十几年来常居榜首的加拿大温哥华落至第三位.',NULL,NULL,0,NULL,0,'2013-09-12 06:18:56',0,24),(105,'全方位比较澳大利亚和加拿大','本人拿了国内大学学士去了加拿大ubc读硕士，毕业后申请美国的学校未果，经过多方考虑移民去了悉尼，我想我还是有资格比较一下这两个国家的。',NULL,NULL,0,NULL,0,'2013-09-12 06:22:07',0,24),(106,'境内签证续签收费详解','对于指定类别临时签证(如学生签证，工作签证，旅游签证等)的持有者，在一些情况下需要付额外$700的境内续签费用，移民局把它叫做subsequent temporary application charge.',NULL,NULL,0,NULL,0,'2013-09-12 06:23:20',0,25),(107,'签证常见问题解答','澳大利亚现代化的电子签证系统无需在护照上贴签，即能确认您的签证状态和您在澳洲的权利。',NULL,NULL,0,NULL,0,'2013-09-12 06:24:48',0,25),(108,'海外人士在澳洲驾车须知','中国驾照是可以带过来使用的，你只要带过来找NAATI任何级别翻译，翻译一下就可以使用。',NULL,NULL,0,NULL,0,'2013-09-12 06:26:29',0,31),(109,'澳大利亚福利','澳洲移民享受的福利多数都是以津贴的形式来发放，本文列举几种大家最关心的津贴进行了简要解释。',NULL,NULL,0,NULL,0,'2013-09-12 06:31:50',0,31),(110,'未来五年澳洲留学会火的新兴专业','澳洲留学专家表示，在专业的选择上还是应该更多地考虑自身兴趣爱好，并且务必要明确澳洲留学之旅的目的，结合自身性格特点和未来五年留学规划，最终决定一个最适合自己的专业。而那么未来五年澳洲哪些专业需求量更大？哪些专业更有前途？跟随留学专家一起来盘点澳洲最火爆的新兴职业。',NULL,NULL,0,NULL,0,'2013-09-16 12:50:34',0,17),(111,'澳大利亚移民：父母移民签证新要求（2013年6月）','澳洲移民局已做出宣布将在7月1日后以申请人头来计申请费。这变更将申请费使大幅度增长。新的申请费是在旧有的申请费为基础，再加上副申请人的申请费。',NULL,NULL,0,NULL,0,'2013-09-16 12:54:50',0,33),(112,'澳洲大学优势专业和入学要求盘点','详细盘点25所澳洲大学优势专业和入学要求',NULL,NULL,0,NULL,0,'2013-09-16 12:57:28',0,17),(113,'澳洲大学奖学金发放情况','今年来澳大利亚留学不断传出利好政策，其中包括PSW工作签证，澳洲国立大学在内的多所名校接受中国高考成绩，且为留学生提供了丰厚的奖学金等等，下面留学小编为大家整理了最受大家关注的澳大利亚留学奖学金名校申请情况，希望对大家有所帮助。',NULL,NULL,0,NULL,0,'2013-09-16 12:59:12',0,17),(114,'澳洲新移民指南：澳大利亚养老体系详解','在讲到澳大利亚的养老政策体系时，人们通常称其有“三部分”“三个层次”或“三个支柱”，即“雇主必须缴纳的养老金”“个人自愿缴纳的养老金”和“政府的退休金”。而实际上不如说是有“两套体制”和一系列“辅助措施”组成，更显得全面而容易解读。',NULL,NULL,0,NULL,0,'2013-09-16 13:00:51',0,31),(115,'澳洲移民：配偶签证的最新更新(2013年4月)','配偶签证可以是夫妻婚姻关系或同居关系。对于境外申请配偶签证类别为309临时配偶签证和100永居配偶签证。对于境内申请配偶签证类别为820临时配偶签证和801永居配偶签证。还有一种境外申请的夫妻300的未婚夫妻签证。',NULL,NULL,0,NULL,0,'2013-09-16 13:03:53',0,30),(116,'澳洲移民163转892所需准备的资料','本文详细介绍了163转892需要的材料，拿了163的朋友们，赶快看一下，尽早着手准备吧，188A的朋友也可以借鉴一下的。',NULL,NULL,0,NULL,0,'2013-09-16 13:06:30',0,28),(117,'看好澳洲房地产的前景的10大理由','让我们来看看澳洲房地产市场前景良好的10大理由',NULL,NULL,0,NULL,0,'2013-09-16 13:08:40',0,32),(118,'颠覆你对澳洲移民的八大误解','澳洲拥有优越的生活环境和自然风光，因此近年来，澳大利亚已成为很多中国人移民、留学、房产投资的热土。但很多学生对移民澳大利亚的理解存在八大误区，在这解释一下这些误区。',NULL,NULL,0,NULL,0,'2013-09-16 13:12:53',0,31),(119,'住在北京二环边上有套房的人都够资格直接移民美国','中国只有建设一个健康而强大的资本市场，才能变“流血”为“输血”，真正发挥其社会资源再分配的作用，才能让这些资金血液真正地为实体经济服务。',NULL,NULL,0,NULL,0,'2013-11-15 06:43:16',0,32);
INSERT INTO `article_content` VALUES
    (16,16,'<p>国际货币基金组织宣布，澳洲，被来势汹汹的世界经济危机大潮彻底卷进了进去。澳洲，已经进入了经济衰退期。</p><p>虽然国会将于下周复会，而澳洲总理将会再次提出一个救市方案：就是往市场上投放现金，大举政府赤字，将以往自由党为澳洲政府挣来的那些收入完全吐出来。羊毛出在羊身上，最后，等经济危机的浪潮过去，在海边捡债务贝壳儿的还是纳税人。</p><p>澳洲储备银行也表示，下周将减息。评论家们认为，这次澳洲储备银行减息幅度应该是一厘（BAXTER旁白：现在澳洲人民已经对这种幅度的减息不感到吃惊了）。减息救市，政府投资刺激市场，这些好像是对于一个晚期癌症患者的打吗啡等消极治疗，病情能维持多久？最后如何？没有人可以说出来。</p><p>澳洲经济能够挽救过来吗？BAXTER在这里，给澳洲政府一个处方。别看那些MANLY海滩的一群SB在那里叫嚣着，别看那些澳洲的SB在反亚着，没有中国人，澳洲根本没戏。国际货币基金组织指出，澳洲之所以是最后一个卷进经济衰退，是因为中国经济放缓的惯性。奥运后，中国经济发展放缓，对澳洲的冲击到现在才刚刚开始显露出来。现在，中国这个大引擎开始放慢了速度，澳洲---一个依靠中国经济腾飞而出口能源的国家也开始跟着停摆了。</p><p>唯一的处方就是：澳洲政府把正在欧洲游历的中国总理***爷爷请来，让他掏出兜里的钢笔，多在澳洲签几个合同。因为，澳洲的BHP已经开始了全球裁员了。必拓，这个澳洲能源巨人也没有例外，也开始了衰退。如果***爷爷在澳洲多签几分合同，重建四川多用澳洲一些钢材和铁矿；如果中国继续建设核能发电站，澳洲的矿石和那些铀矿就会有了买主，能源经济就会被带动起来。让那些ANTI CHINESE的SB们看看，现在，没有中国，他们真的要回到新石器时代了。</p><p>有人说了，澳洲的经济和我们留学生没有什么关系。城门失火，殃及池鱼，怎么能没有关系？澳洲经济衰退对留学生有利有弊，任何事情都是有两面性。</p><p>首先，拿澳币来说。如果澳洲政府正式宣布经济进入衰退，澳币肯定一路下滑，一个澳币兑换4.5的时代肯定结束，一比六的时代更加遥遥无期。此时不留学，更待何时？</p><p>中国的货币是由政府操纵的，与世界货币市场不接轨的。中国政府一直要保持汇率稳定，从不敢轻言人民币贬值。因为，如果人民币贬值，将意味着让世界经济危机雪上加霜。我党不会这样做！（BAXTER旁白：就是这样的政党，这样的政府，还有一些人叫嚣着是我党不负责任，还有一些海外白菜帮子高喊着独立，根都没有了，那些菜帮子能蹦跶几天？滑天下之大稽！！！打倒那些菜帮子独独们！）</p><p>人民币的稳定，给世界一个信心，给那些留学生信心。任凭风吹雨打，我自闲庭漫步。澳币狂贬才好，正好可以趁机留学。</p><p>那位看官质疑了，那学费是不是要涨钱了？学费是和老师的工资，学校的投资相辅相成的。现在是百业萧条，谁敢言涨工资？涨工资可以，裁员，两个人的工作一个人做！我说的这是官方正式宣布经济衰退之后，我敢断定，那时候，澳洲人民一定会茫然不知所措。工作都快保不住了，谁还敢说涨工资？中国人不敢，澳洲人也不敢！这就是中国留学生捡来的便宜柴火。</p><p>切入正题，移民，澳洲经济衰退对留学市场以及移民配额的影响。</p><p>自从去年11月份，澳洲总理陆克文就说过，面对经济危机，澳洲将要砍掉一些移民配额。因为，这个移民配额是是2008年中期定的，换一句话说，就是在经济危机前定的。然而，这个砍向移民配额的大刀一直没有落下来。为什么？BAXTER在这里进行深层剖析。</p><p>首先，移民配额关联着教育出口行业。</p><p>如果移民的配额减少，或者是大幅度地砍掉，对澳洲教育出口行业肯定是一个大震动。而澳洲这个国家可以出口的资源并不是很多，他们没有SONY和IPHONE等高科技，靠的就是能源和教育。能源出口已经是昨日黄花了，教育出口再有问题。澳洲经济还禁得起折腾吗？套用***主席最近的讲话--不折腾，澳洲政府也是一样，不折腾！</p><p>不折腾不等于不变；回首澳洲人力资源市场，就明白为什么移民配额一直在增加。在2005年，前任的澳洲总理霍华德和新西兰的前任总理海伦克拉克女士，在新西兰的首都奥克兰会晤，他们对着媒体发出一声无奈的嘶喊：我们已经没有工人可用了。在2007年大选的时候，霍华德自豪地说：在十年前，人们抱怨找不到工作；现在倒好，抱怨找不到工人。这两位总理都已离任，他们的时代结束了。那按照当时经济形势指定的移民配额会一成不变吗？肯定会变。</p><p>如果澳洲政府正式宣布经济衰退，失业率一旦提高，首先受到冲击的就是那张牵动万千留学生的澳洲急需行业名单。这纸文书肯定会变，受到冲击最大将是那些TAFE课程，那些以往被视为移民小跳板的急需职业。</p><p>TAFE将是受到冲击最大的；那些以往澳洲没有人做的，找不到工人的行业，现在肯定可以找到人，那么多的人失业，有工作不做？这几乎不可能。而且，澳洲政府已经注意到，不可以忽略本国公民的再教育，面对本国公民，TAFE是免费的。在澳洲，如果人失业了，很多人去TAFE上学，然后操起一份新的工作，时间短，见效快。这就是TAFE！当初TAFE面向海外招生，我就感到非常差异。这些原本是服务本国公民的机构，怎么也开始盈利？现在，他们开始了回归本初了。</p><p>首先，我们来分析一下那些TAFE课程，大家觉得那些课程是不是需要高智商，较高文化水平才可以做的吗？根本不是！原本是为了救急的一些急需专业，在经济衰退中，也不会那么炙手可热了。准备上TAFE的同学们，需要三思了。</p><p>那TAFE真的不行了吗？TAFE的急需专业真的没有希望了吗？会不会改变呢？如果澳洲经济还没有正式被政府宣布进入衰退，如果澳洲的失业率还是很低，如果那些急需专业还是没有人做，急需的专业名单肯定不会变。大家觉得这种可能在，在危机的浪潮中存在吗？</p><p>一般上TAFE的人，不是家里不富裕，就是不爱学习；以往，我认为，来澳洲读硕士的，一般是比较穷的。后来有了TAFE，我发现，这些人更加不如那些苦命的硕士。至少那些读硕士的还有一些读书的精神，就算不爱读书，他们硬着头皮还是可以把书本啃下来，拿到硕士毕业证。反观这些TAFE的学生，家境一般比硕士们还要差，论学习精神吗，根本不如那些硕士。而那些TAFE的急需专业，也不是需要高水平的知识才可以完成的。所以，我说TAFE的辉煌早已成为了昨日之夕阳，想要靠TAFE移民，已经是黄粱一梦了。据线报：现在一些TAFE的学生已经开始不交学费了，开始准备撤退了。他们的理由是雅思的七分和工作经验的900小时无法拿到。以后，恐怕你拿到了这些东西，凭着这些专业也是很难拿到永居了。虽然有点悲观，而且，我也希望我预言的不会成为现实。</p><p>他们还有出路吗？天无绝人之路，在最后我将说说这些人的出路。</p><p>现在说说本科及硕士留学生以及相关的急需专业；</p><p>&nbsp;</p><p>&nbsp;</p><p>硕士，一直以来是热门；为什么？因为它的含金量高，且收费相对本科来说便宜。而本科，含金量更高；因为，凡是在澳洲本科毕业的，无论你的专业如何，你的英文够强。这些人一般家里有钱，很小过来。他们的优势就是年轻力壮，学说话快。一般来说，他们的英文很强。如果加强一下学习，雅思七分应该不是问题；如果真的有问题，那是他们自身的原因，怪不得别人。扯远了。。。赶紧杀回来。</p><p>硕士还是比较被大家普遍接受的选择，而什么专业将是今年乃至明年铁定急需的专业呢？让我们来分析一下。。。</p><p>抛去医生，牙医，等等这样的长期急需的，且要求极高而让人无法逾越的专业，最最广谱的专业里，IT，会计和翻译。</p><p>IT，我个人认为是铁定急需的；当我读世界是平的这本书的时候，我发觉，未来的世界发展以及科技走势，都无法离开互联网和电脑了。现在很难想象没有网络和电脑了，而且，澳洲的IT还有很大的拓展空间，澳洲在很多方面真的是有欠发达。</p><p>澳洲总理陆克文在竞选时提过，他要打造一条高速的互联网，而且，要让每一个学生配备一部电脑。虽然金融危机了，虽然澳洲衰退了，但是在教育上，澳洲政府是绝对不手软的。因为，陆克文总理曾经说，要让澳洲成为一个高科技的国家，让澳洲人成为科技人。</p><p>因此，IT是不可避免地成为澳洲飞翔的翅膀；没有翅膀，澳洲将无法与其他的强国比翼双飞；没有IT，澳洲将裹足不前；没有IT人士，澳洲的IT将无法发展。这种软设施是澳洲必须的，这些人才是澳洲需要的。澳洲需要你们，高智商的IT人士！</p>'),(15,15,'<p>留学专家告诉记者，澳洲留学奖学金政策正在逐步放宽，新开设奖学金的专业大多是工程专业，所以建议学生不要片面地集中去报读会计、国际贸易等热门的商科专业，选择一些工程、设计等技术含量相对较高、学术要求更严格的专业将会更有利于将来的发展。</p><p>澳大利亚的海外学生奖学金一般分为两大类：政府奖学金和大学及研究机构奖学金。政府奖学金又分澳洲发展奖学金(ADS)和澳洲国际研究生研究奖学金(IPRS)。ADS目前不接受个人申请，IPRS是专门为海外留学生设立的，主要针对研究型硕士生或博士研究生。IPRS和澳洲各大学设立的奖学金一般都由各院校直接选择发放，但发放名额相当有限。每一种奖学金都有各自的发放标准，申请者要确认条件是否符合，盲目申请很难成功。</p><p>因为获得奖学金不容易，极大地影响了那些渴望出国深造但经济基础又相对薄弱的学生赴澳求学的热情。为此，澳大利亚政府从去年起启动专项计划吸引留学生，分5年拨出18亿澳元奖学金给各国申请者，这是该国第一次大规模提供奖学金给海外学生。这个奖学金中适合中国学生申请的项目有6项，单笔奖学金最高可达9.5万澳元，将近50万人民币，对于广大留学生而言，确实是一个出国深造的好机会。</p><p>据其提供的资料显示，此次澳大利亚政府启动的奖学金计划中包括学习类奋进奖学金、研究生奋进奖学金和亚洲奋进奖学金等项目，在每年30个奖项名额中，中国学生可有4个人获得这一项奖学金。其中的研究生奋进奖学金是为赴澳攻读硕士学位的海外学生提供资助，而亚洲奋进奖学金则是专门为赴澳攻读研究生或博士学位或者从事短期研究的亚洲学生提供资助，很适合已经走出大学校门的职场人士。</p>'),(9,9,'<p><iframe src=\"https://www.youtube.com/embed/vsj6J0162mQ\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p><p>\"打工\"是留学生们体验社会、锻炼能力、养活自己的一个必要途径。在澳洲，多数学生会<wbr />&shy;选择一边学习，一边打工，在这种双重体验中收获海外生活的苦与乐。这些在国内被人们称<wbr />&shy;为\"小皇帝\"、\"千金女\"的孩子们，在经历疲惫、受伤、委屈后完全变了样。本期《留学<wbr />&shy;这些事》新老留学生对话分享各自的打工经历！</p><p>如果您不能观看来自YouTube视频，请点击这里观看：<a href=\"http://v.youku.com/v_show/id_XNTQ1Mzc3OTg0.html?f=19297080\" target=\"_blank\">《留学这些事》：打工那些事</a></p>'),(12,12,'<p><iframe src=\"https://www.youtube.com/embed/9x8RpS7EWr4\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p><p>&nbsp;</p><p>你是否正在纠结留学之后是回国还是留澳?面对移民的重重阻碍,你是否选对了移民途径?<wbr />&shy;本周日来自新澳东国际咨询服务中心的梁维东老师做客解答你所关注的\"移民\"问题。</p><p>如果您不能观看来自YouTube视频，请点击这里观看：<a href=\"http://v.youku.com/v_show/id_XNTQ4ODYwOTcy.html?f=19297080\" target=\"_blank\">留学这些事：如何顺利移民澳洲</a></p>'),(11,11,'<p><iframe src=\"https://www.youtube.com/embed/tspW_JrjjO0\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p><p>&nbsp;</p><p>中国赴澳留学人数增多。无论年龄大小，如何选择学校成了最大的问题？本期节目专访新澳&shy;东国际咨询服务中心移民首席顾问梁维东老师，给大家带来澳洲择校及专业选择的完全攻略&shy;。</p><p>如果您不能观看来自YouTube视频，请点击这里观看：<a href=\"http://v.youku.com/v_show/id_XNTQ1NzU4Njcy.html?f=19297080\" target=\"_blank\">《留学这些事》：澳洲留学择校攻略</a></p>'),(13,13,'<p><iframe src=\"https://www.youtube.com/embed/zIdZRraGOnE\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p><p>&nbsp;</p><p>留学生毕业后的就业形势却越来越不景气，而在澳大利亚找到适合自己并与专业相关的工作<wbr />&shy;更是难上加难。留学生在语言文化上很难比肩澳洲本土毕业生，再加上签证身份等因素束约<wbr />&shy;，留学生找工作似乎成了一个棘手的问题。<br />本期《留学这些事之资讯速递》邀请新澳东留学移民公司的资深顾问梁维东老师根据澳洲就<wbr />&shy;业环境给想在澳洲找专业工作的留学生们一些实用的建议。</p><p>&nbsp;</p><p>如果您不能观看来自YouTube视频，请点击这里观看：<a href=\"http://v.youku.com/v_show/id_XNTUxNjEzNjg4.html?f=19297080\" target=\"_blank\">留学这些事：如何找到专业工作</a></p>'),
    (17,17,'<p><strong>为何选择赴澳留学?</strong></p><p>与其它西方国家相比，澳大利亚是个安全的地方，环境舒适，安宁，学生可以安心学习，并可自由旅行。澳大利亚是个多元文化汇萃的国家，种族多元化也是很多院校的特色。澳大利亚的学校不但十分欢迎海外留学生，而且很关注学生不同的需要。</p><p>&nbsp;</p><p><strong>在澳大利亚进修英语</strong></p><p>澳大利亚国家英语语言教学评审计划署(National ELT Accreditation Scheme，英文简称NEAS)为全国学院确定评核制度，NEAS 评审学院的管理、员工、最低师资要求、设施、服务、校舍，以及课程等。</p><p>&nbsp;</p><p><strong>澳大利亚的职业培训教育</strong></p><p>澳大利亚的职业培训教育由职业技术（TAFE）学院以及私人机构，如企业公司、私立学院、社区团体、专业组织和学校等负责提供。</p><p>TAFE 由澳大利亚政府资助，各个州及地区均设有 TAFE 的管理机构。各机构通力合作，共同设立了一个全国性职业培训网络，不但可满足各行各业在人才方面的需求，也可使受训者学到是适时实用的技能，协助他们寻找工作。</p><p>TAFE 的培训机构、院校及中心网络，不但包括各大城市，而且还延申到各乡镇社区。全澳大利亚各教育机构和院校每年提供数以千计职业及非职业培训课程，有超过一千二百万名学生修读，这些课程包括：</p><p>文凭及证书进修课程</p><p>职业培训课程</p><p>个别选修职业培训课程的预备课程</p><p>辅助补充课程</p><p>专业技能培训</p><p>成人个人兴趣、消闲课程</p><p>TAFE 着重小组学习，教师均为经验丰富的专业人士，课程专业实用并重，是澳大利亚引以为荣的教育服务之一。</p><p>&nbsp;</p><p><strong>澳大利亚的高等教育</strong></p><p>澳大利亚的高等教育质量与学术水平在国际上享有盛誉。澳大利亚的大学以启发及传授知识为基础，在国际学术界有着举足轻重的地位。</p><p>澳大利亚大学的教授讲师均由世界各地招聘而来，而在澳大利亚大学任职的员工及毕业的学生，在世界各地也是炙手可热的招聘对象。全球各大知名大学都十分愿意录取澳大利亚大学的毕业生作为研究生，可见澳大利亚大学的学术水平已经获得了广泛的认可和良好的评价。而国际的认可同时也有助于澳大利亚的院校保持优秀的教育水准。</p><p>澳大利亚的大学提供的课程包括大学课程及研究生课程: 大学课程- 包括文凭（文凭课程也可在 TAFE 学院修读）及学士学位课程研究生课程 - 包括研究生文凭及证书、讲授硕士课程、研究硕士课程及博士学位课程</p><p>&nbsp;</p><p><strong>课余兼职</strong></p><p>十五岁以上的海外学生经父母许可，每周可兼职工作不超过二十小时。这些兼职工作经验也有助于海外学生结交朋友，加深对澳大利亚的认识。但学生必须确保自己的学业不会受兼职工作的影晌，也不应把兼职工作视作其在澳大利亚上学的主要经济来源。</p>'),
    (18,18,'<p><strong>教育质量</strong>：首先，澳大利亚高端的教育质量，为国际学生提供了全方位的教学保障。其中，教育水准高、国际通行的学歷、接受转换专业申请和一年开学多次等特色最为夺人眼球。《英国泰晤士报高等教育增刊》对全球88个国家的1300所大学进行了调查，其结果揭示了这样一个事实──澳大利亚38所公立大学在世界200强大学中有17所、100强中有12所，50强中有6所。&nbsp;</p><p><strong>经济体系</strong>：澳大利亚具有类似西方的商业文化，其开放型经济的发达且具备创新精神，使得超过840家国际公司已将其亚太区总部设在澳大利亚，大量人员招募使得全球金融危机下终于出现了一个振奋人心的消息，中国学生将能够获得大量就业工作的机会，实现留学、就业、移民一步走的完美规划。&nbsp;</p><p><strong>生活环境</strong>：澳大利亚的人民享受着在全世界来看都可名列前茅的优质生活。清洁的环境、健全的卫生医疗服务、低犯罪率、便捷的交通、高福利政策吸引着人们前来居住与学习。澳洲工薪族&ldquo;琳琅满目&rdquo;的休假待遇也堪居世界前列。社会安定，国民富足，使得学生们可安心学习，并能享受自由旅行的乐趣。&nbsp;</p><p><strong>留学费用</strong>：与美英等许多其他发达国家相比，澳大利亚的生活费用比较低。在澳洲一年的生活费大致在4-5万人民币，每週可打工20小时，每小时平均收入10-15澳元，一般来说可抵上大部分生活费。学费因学校和专业的不同差别很大，澳洲一年的生活费和学费总共约10-18万人民币。这一费用对大多数中等收入的家庭来讲还是可以承受的。&nbsp;</p><p><strong>移民政策</strong>：对获得澳洲大学的学士学位或硕士学位者，可免除工作经验要求，并可获得一定的加分奖励，相比较国内申请漫长的等待时间，学生毕业后在澳洲申请移民更为便捷。在获得移民身份后可立即获得除政治权利外的所有澳洲公民应享有的一切权利和福利，如果需要，以移民身份住满2年，即可申请加入澳大利亚国籍，获得世界上70多个国家(包括美国)免签的澳洲护照。</p>'),
    (19,19,'<p>相比于其他几个主要的留学国家，澳大利亚具有吸引国际学生的显著优势，主要表现在</p><p><strong>一、气候宜人、风景优美</strong></p><p>澳大利亚地处南半球，在太平洋和印度洋之间，属于热带和温带地区，全年平均气温13摄氏度到27摄氏度，属于地中海式气候和温带海洋性气候。澳大利亚被称为&ldquo;世界上天然风景最美的国家&rdquo;，大堡礁（世界奇观）、黄金海岸（GOLD-COAST）、BONDI海滩（世界五大海滩之一）、悉尼歌剧院（地标）均为世界知名的旅游胜地。</p><p><strong>二、教学质量一流</strong></p><p>澳大利亚的教育体制是国际上公认的，澳大利亚当局对国内院校的教学水平要求严格，确保培养成绩优异的学生。其大学以启发及传授知识为基础，在国际学术界有着举足轻重的地位。澳大利亚在介入国际教育和发展方面具有较长的历史演进过程，一向注重教学科研人员和学生奖学金项目的国际交流，尤其注重来自不同文化背景的学生之间的相互理解和尊重。能够提供国际认可的教育和培训，课程实用，与现代社会的需求同步。毕业生遍布全球，受到雇主的欢迎。</p><p><strong>三、学校众多、学费适中</strong></p><p>澳大利亚共有40所大学及几百所公立私立中学供海外留学生选择。公立中学（GOVERNMENT HIGH SCHOOL）为澳洲教育部认可，隶属于各个州政府，费用低廉，校风严谨，升学率高。学生可根据住址、自身情况自由选择学校。私立中学包括教会学校，男子，女子中学，管理严格，设备先进。公立大学包括悉尼大学，新南威尔士大学，墨尔本大学，堪培拉大学以及麦考里大学等诸多知名院校，具有世界公认教育水平。澳大利亚为发达国家，留学的费用低于美国、英国及加拿大等国家，每年的学费和生活费大约为30，000元澳币左右，折合人民币180，000元。</p><p><strong>四、入学手续简便，签证通过率高</strong></p><p>澳大利亚是一个迷人的、学习环境宜人的国家。高校规模大小不等，遍布在全国各地，为学生提供名目繁多的专业和研究课程，而且学生的入学手续相对简便。由于澳大利亚是教育出口国家，所以门槛较低，如果符合审核的条件，被拒签的几率相对较小。澳大利亚接受中国学生去读高中，签证也很方便。而这是其他许多国家所不具备的。</p><p><strong>五、福利完善、政策宽松</strong></p><p>对海外留学制定了一系列的福利，学生在澳洲可以享受全部医疗保险，享受优惠交通设施。澳大利亚欢迎海外留学生前往就读，学生可以每周合法打工20小时（周六、日和节假日不限时）。　</p><p><strong>六、移民迅速</strong></p><p>作为移民国家，学生在澳洲自费留学拿到学士学位或硕士学位后，可以直接办理移民，取得永久居留权。澳大利亚移民局规定，对赴澳自费留学后获得学位的留学生进行移民盛情时，优先考虑并可在当地申请移民，申请周期为6-8个月。目前，澳大利亚独立技术移民的分数为120分，主要对申请人的学历背景、专业知识、语言程度、年龄等进行综合评估。会计、护理、计算机、</p><p><strong>七、犯罪率低</strong></p><p>自建国以来，本土从未发生过战乱和其他大规模社会冲突。澳大利亚的犯罪率是世界最低的地区之一。在这里，生活和居住环境安全，整个社会对外国留学生前来读书非常欢迎。与其它西方国家相比，澳大利亚是个&ldquo;安全&rdquo;的地方，环境舒适，安宁，学生可以安心学习。</p>'),
    (20,20,'<p>澳洲的大学在教育和培训各方面，都拥有相当高的国际声誉。</p><p>澳洲的大学在许多领域上，都被公认具有拥卓越成就。学校提供实用、以就业为导向的培训方式，所以毕业生能确信他们绝对具有雇主所要求的技能。</p><p>澳洲的职业教育与培训方法，已经被认定为全世界最好和最创新的教育方式，大大提高工人的技能和生产力，对於澳洲的经济扮演了重要角色。</p><p>澳洲的学生在国际比赛中表现出色，例如OECD PISA阅读比赛、科学与数学性文学等级比赛，并且在科学与数学领域上胜过其它英语系国家。</p><p>澳洲的职业教育与培训学校，在科技性的学习发展上居世界领导地位，例如我们的英语语言学院都拥有影视及图书馆设备、电脑辅助学习设备和英语教室。</p><p>澳洲的创新和浓厚的研究风气，吸引了无数国际学生，您可以到『澳洲科技馆』(Australian Technology Showcase，简称ATS)网站，体会澳洲是具有创新科技和先进技术的国度。</p><p>澳大利亚教育机构的教授讲师均由世界各地招聘而来，他们一般都是所在领域的行业专家。澳大利亚教师对于指导来自世界各地的学生有着丰富的经验。</p><p>每年澳大利亚的大学通过与美国、英国、加拿大、欧洲和亚洲等国的著名学府已建立起来的联系，开展各种校际间的学生和教师学术交流活动。</p><p>澳大利亚因比其他许多国家以更快的速度采用新技术而著称。在人类迈入新千年之际，澳大利亚国内的因特网速度居世界前列。在教学、培训和研究的设备方面，其现代化的实验室、教学课堂、设施先进的图书馆以及现代技术都属于世界一流水平。</p><p>在工业、科学与资源部的网站上，你可以获得更加详细的有关科学技术领域等方面的资讯。</p>'),
    (21,21,'<p>情况一：美国次贷危机所引发的全球性经济危机，正以我们中国普通老百姓所想象不到的深度及广度影响着西方社会，从经济到政治到国家关系等各个层面。有专家预测，此次经济危机对各行各业的影响可能波及到未来的很多年。具体到教育界，学生在选择专业时原来的热门专业不再热门，比如像MBA、国际贸易、金融等等。而一些基础服务性行业则趋于走俏，比如厨师、教师、导游、国家公务员等等。</p><p>情况二：中国成功的举办奥运会对西方社会以及澳洲社会从上至下在有关中国的国家情况、百姓的经济状况等方面有了一个全新的了解和认识。张艺谋在奥运会开幕式上的中国实力&ldquo;成功演绎&rdquo;正逐步取代其早期电影&ldquo;黄土高坡&rdquo;及&ldquo;一穷二白&rdquo;留给人的印象。更多的澳大利亚人把中国学生定位在&ldquo;有钱人家的孩子&rdquo;这一概念上，而&ldquo;嫌贫爱富&rdquo;则似乎是人类共通的毛病，因此整个社会对中国学生的态度还是往积极方向发展。</p><p>情况三：去年9月份开始的570签证，把中国从原来的四类地区的签证要求提升到三类地区，也就是说：可以有条件的不需要雅思成绩获得赴澳留学签证。但从9月至09年初的570签证运作情况看，申请签证者鱼龙混杂，大批怀有不良留学目的&ldquo;伪学生&rdquo;混在其中，移民局不胜其扰，在很多570签证被拒的同时，对其他类别的签证亦有某种程度上的严格倾向，所以在09年，尤其是上半年，签证材料的精心准备，不失为策。</p><p>情况四：澳大利亚是一个高福利、高税收的国家，优良的福利来自于税收及丰富的矿产。在全球经济萧条之风劲吹的情况下，矿产出口锐减，各行各业大量裁员，据最近的新闻报告：澳近期税收减少1150亿澳元。经济不好影响到外汇市场的澳币的汇率，回想80年代出国潮中，澳元对人民币的比值高达1： 8至1：9，而现如今才1：4.5上下，据分析澳币还有可能持续走低。对澳大利亚人来说这是一个大大不好的消息，而对中国留学生来说，这确是一个利好的消息，同比去年留学费用减少30%到40%，比教育出口的劲敌加拿大在费用上低30%，这对经济上有些压力的工薪阶层来说，不失为天赐良机。</p><p>情况五：对澳大利亚来说教育出口占到了出口业的30%，换而言之，外汇收入的30%来自于留学生。而07年底推出的移民新政策，在经营了多年&ldquo;教育出口产业化&rdquo;的生财之道之后，又在&ldquo;移民出口产业化&rdquo;做文章，降低高中、本科的移民&ldquo;门槛&rdquo;，但提高了研究生移民的要求，即所谓的移民道路&ldquo;三选一&rdquo;──在雅思4个7分;专业对口的就业;选择偏远地区留学中选择一个途径方可解决移民问题。这一政策打击了不少原来想赴澳读研的学生的信心，改而求其他学习之路。眼见巨额外汇的流失，澳政府又推出了一个新的移民政策：&ldquo;职业年&rdquo;(Professional Year)。用简单的话来解释这一政策就是花钱买工作经验(当然是真的工作经验)，他既解决了学生的移民问题，也增加了政府的收入，一举两得。在09年中希望学生要密切关注有关&ldquo;职业年&rdquo;的政策细节，做到有备无患。</p><p>情况六：随着移民政策向低龄留学生的倾斜，越来越多的小留学生出国，已成为一种趋势和潮流。小年龄学生出国尽管存在着费用高、孩子自控力差的弊端，但必竟一旦学成，学生在语言、课程结构、升学率、就业率、移民率、融入社会的能力等方面都有其他本科生、研究生不可比拟的优势，所以无论你处在哪一个留学层面，都要清楚的意识到：留学生的年龄在09年将继续走低。</p><p>情况七：相对英、美、加国家来说，澳大利亚人民友好，留学移民政策稳定，但不可否认，由于经济、政治的影响，09年签证及移民政策的微调可能会多于以往。若选择中介办理出国留学，应更进一步加强与中介的合作，而中介对澳形势政策的实时跟进，对学生做及时、准确、全面的指导则应是09年的工作重点。</p>'),
    (22,22,'<p>澳大利亚教育简史及现有规模</p><p>自从澳大利亚联邦建立以来，澳大利亚的教育经历了巨大的变化。殖民地时期的1900年,全澳州有380万人口，6,900所官办学校，在校学生623,700人。此外，还有大约153,400名学生在私立学校学习。同年，中等学校教育只是极少数青年人享有的特权。1910年澳大利亚联邦政府统计报告称，&ldquo;男女学生离开州立政府学校、终止学习的年龄大概在14岁左右，而且各州自此以后也不关心他们的去向&rdquo;。澳大利亚联邦成立之初，职业技术教育很长一段时间也没有建立起来。在维多利亚州，&ldquo;直到皇家职业教育委员会（成立于1899年）报告发布之后，教育上存在的许多缺点才得以矫正。&rdquo;就高等教育而言，当时也只有悉尼大学、墨尔本大学、阿德雷得大学和塔斯马尼亚大学等4所大学，4所大学在校生总数仅为20,000人。</p><p>2000年，全澳共有中小学生320万人，其中政府学校有220万人，私立学校有100万人。此外，接受职业教育和培训的人约160万人，42所高等教育机构的在校生总数为695,500人。</p><p>1911年的统计数据表明，整个教育系统的雇员只有31,700人，占劳动力人口总数的1.6％。到2000年，教育系统的工作人员达615,400人，占整个劳动力人口的6.8％。</p><p>澳大利亚教育管理体制</p><p>根据澳大利亚联邦宪法，教育事务由各州、领地政府负责管理，联邦政府没有法律上的义务。总体来讲，各州、领地政府对教育的责任包括对初级和中等教育的行政管理和拨款，对职业教育和培训的行政管理和拨款。</p><p>随着时间的推移，联邦政府通过联邦拨款、设立专门教育项目等手段，通过已经设立的&ldquo;联邦教育培训和就业部长会议&rdquo;等多个全国性教育机构等机制，越来越多地介入对教育事务的管理，如负责高等教育的拨款，对学校、职业教育和培训提供补充经费，加强对土著居民、岛屿居民、移民的教育和培训，开展国与国间的合作与交流等等。州和领地政府也能从联邦政府申请到特别用途的专项经费。除了重要的拨款功能以外，联邦政府也在促进全澳教育和培训的公平性、一致性和连续性方面发挥极为重要的作用。</p><p>（一）学前教育</p><p>澳大利亚各州、领地规定，学前教育不是义务教育的一部分，但属于正规教育。各州规定的学前教育一般为一年，而且大多数州和领地要求儿童在5岁时开始其学前教育。</p><p>尽管所有州和领地在政策上保证所有儿童在上学前都有机会接受学前教育，但是在提供学前教育方面目前还没有一个全国统一的政策。因此各州和领地在立法、行政管理和学前学校的组织等方面都有相当的区别。儿童接受学前教育的年龄从3到5岁不等，使得各州和领地儿童的小学入学年龄产生细微的差别。近年，由于许多白天长时托育中心也把提供学前教育作为其服务的一个组成部分，一些学前教育学校则不断延长学生的在校时间，使得学前教育和白天长时托育中心之间的差别越来越不明显。这使得澳洲很难准确确定接受学前教育的儿童数量。1999年全澳对儿童托育情况进行了一次调查，调查将学前教育定义为&ldquo;一种正规的、广泛适用于3岁到小学开始年龄儿童的（有时，也接受年龄更小的儿童）、并对儿童在校期间进行的一种照顾。&rdquo;儿童通常有固定的上学时间。根据这种界定，1999年，全澳只有231，600儿童接受学前教育，只占3－5岁儿童的30％。</p><p>（二）中小学教育及学制</p><p>澳大利亚义务教育年龄为六至十五岁（塔斯马尼亚州至十六岁），一般学生在10年级即完成义务教育。11和12年级为非义务教育。各州、领地中小学通常在每年二月初开学，十二月初结束。</p><p>塔斯马尼亚州实行一学年3学期制，昆士兰州和北领地区实行一学年2学期制，其他各地实行一学年4学期制。</p><p>新南威尔士州、维多利亚州、塔斯马尼亚州和首都地区实行13年学制，即幼儿班1年，小学6年，中学6年。南澳州和北领地区也实行13年学制，但年度分配与上述几州不一样，这两个州、领地的分配是学前班1年，小学7年，中学5年。</p><p>昆士兰州和西澳州实行12年学制，即小学7年，中学5年。</p><p>塔斯马尼亚州、首都地区和其他州的个别公立中学只设7到10年级。学生读完10年级后，如果计划继续接受高等教育，可进入单独设立的学校（高中）完成他们的11和12年级的学习。</p><p>澳大利亚公民和永久居民的子女在公立中小学享受免费教育，但须缴纳教材、学校设备的使用费等费用。此外，学校要求每位学生每学期缴纳一定数额的&ldquo;捐款&rdquo;。学校尽管没有明确具体数额，但一般每年都要交纳数百澳元的&ldquo;捐款&rdquo;。</p><p>所有公立中小学和大部分私立小学为男女生混合学校。在教学方面，学校强调学生的参与精神，以培养学生的自学能力和实际工作能力为主。因此，在课堂上，教师要求学生动手的内容比较多。</p><p>学校一般按学生的年龄进行分班，年龄相同的学生通常被分在同一班级学习。经过一段时间学习，学校可根据学生的能力和兴趣，重新编班。学生无升学考试。期末，教师根据学生的年龄和平时学习成绩，参考期末考试成绩，与学生家长协商决定学生的升留级事宜。小学毕业没有统一的毕业考试。所有毕业生都可就近进入中学学习。</p><p>澳大利亚的学校享有相当的自主权。各校都有校董事会，校董事会由校长、社区代表、学生代表、家长代表组成，决定学校的内部事务。各州和领地都设立了教育行政管理机构，负责各州和领地自己的教育事务。学校一般都根据各州和领地的政策指导原则自行决定教学方法，也可在州规定的课程之外提供其它不同的课程供学生选择。</p><p>对学生的评价，各州和领地制度不同。一些州有完整的以学校为基础的评估制度，学校自主对学生进行考试、评价。另一些州则将这一制度和外部评估制度相结合，有的州、领地教育主管部门对10、12年级的学生进行统考。</p><p>（三）高中教育与高等教育的衔接</p><p>在高级中等教育（高中）阶段，绝大部分学校提供广泛的选修课程供学生选择。政府鼓励学校自己开发一些能够满足学生学习兴趣和要求的课程，但这些课程的开设须得到学校所在州、领地教育主管部门的审批。近来，学校越来越重视将职业技术教育纳入高中教育课程体系。高中学生毕业时也因此能够获得职业技术教育证书。</p><p>达到了最低离校年龄的中等学校的学生可以离开学校寻找工作机会，也可以进入职业教育和培训机构（VET），如TAFE机构或者私立商业学校，继续学习。</p><p>对于许多VET课程来说，完成中等学校10年级的课程是最低入学标准。对那些继续完成全部中等教育（至12年级）的学生来说，可以进入高等院校、职业技术学校和其它类型的高等院校学习。</p><p>对有资格进入高等院校学习的学生的评价，一般在其学习的最后两年或在毕业时进行。以首都地区学校为例，11和12年级的学生必须参加5次考试，第一次在11年级第一学期第一学段结束时进行，第二次在第一学期第二学段末进行，第三次在第二学期末进行，第四次在12年级第一学期末进行，第五次在第二学期末即毕业时进行。在第12年级末，希望进入大学学习的学生还必须参加&ldquo;澳大利亚等级考试&rdquo;。</p><p>各科五次考试的平均成绩与AST成绩相加，即为高等教育机构决定是否录取学生的依据。五次考试的科目一般有英语、数学、科学、商科、艺术、信息技术。AST的考试科目为Quantitative, Verbal和 Writing。</p><p>高等学校的录取工作是学校、州教育厅、学校和学生共同参与的过程。</p><p>澳大利亚中小学校教育规模</p><p>截止1999年8月，全澳共有9，600所中小学校，其中约7，000所学校为政府学校（占总数的73％）， 2，600所学校为非政府（私立）学校（占总数的27％）。全澳共有215，700名教职员工, 其中约有150，500全职教职员工在政府学校工作（占70％），65，200名在非政府学校工作（占30％）。</p><p>1999年，全澳有320万全日制中小学生，其中公立学校学生数为220万，占总数的70％，非政府学校学生数为100万，占总数的30％。表四显示，从1984年到1999年，学生总数增加了209，000，增幅7％。而从1984年到1989年，政府学校的学生数减少了66，200名，减少幅度为3％。但是从此以后的十年中（至1999年），学生数又增加了53，300名，增幅达到2％。</p><p>就非政府学校而言，1984－1989年，学生数增加了80，000名，增幅达11％，1989－1999年的十年中，学生数更进一步增加141，900名，增幅达17％。1984年，非政府学校学生数占学生总数的比例为25％，到1999年，这一比例则达到了30％。</p><p>其它形式的教学安排</p><p>边远地区的学生和残疾学生可以不受义务教育要求的限制。在北部领地的一些边远地区，一些居住在非中心地带的土著儿童只好接受来自固定学校&ldquo;访问教师&rdquo;的教学帮助。长期以来，尽管各种不同的特别安排延长了边远地区的学校教育年限，但却不同程度地满足了少数民族的教育需求。从1867年开始，新南威尔士州在学龄儿童不足25人的居住地实行了临时和&ldquo;半日制&rdquo;学校。巡回教师在人烟稀少的居民点实施挨家挨户的教学。收音机的出现，使得地处偏僻的牧民家庭也能够享受&ldquo;空中学校&rdquo;[11]的教育。今天，这些孩子能够通过各种不同的方式，如远程教育、&ldquo;空中学校&rdquo;、计算机和传真等而获得教育。</p><p>各州和领地都为智力和身体有残障的孩子实行了&ldquo;特殊教育&rdquo;。政府和非政府机构实施特殊教育的方式有特殊课堂、特殊学校和普通学校。普通学校实施特殊教育的方式是，专门的教师将为在普通班级里上课的残障孩子在课外实施额外的强化帮助以使他们能够适应普通班级的教学。几乎所有的州和领地，特别是在新南威尔士州、昆士兰州和维多利亚州，许多家长自发组织起来建立额外的学校以满足残障孩子们的特别需要。联邦政府也给各州（领地）政府、非政府机构和社区团体提供资金，以帮助他们实施特殊教育，改善特殊教育设备。在一些非政府学校，特别是在一些较大的城镇的非政府学校提供住宿设备。有少量政府学校，特别是为土著居民服务的政府学校的附近还设有宾馆。</p><p>保留率</p><p>保留率指一定数量的学生继续学习到一定年级的百分比，它是衡量一个教育制度和相关的政府教育政策成功与否的重要指标。</p><p>澳大利亚12年级学生的保留率从1992年的77％下降到1999年的72％。在前些年，女学生的保留率为79％，高于同期男学生66％的保留率。1962年至1992年，保留率一直持续上升，直到1992年的77％为止。1967年，并非所有的政府中学都设有12年级。在这一年，只有15％的女生上12年级。1975年以后，政府学校里女生的保留率已经超过男生的保留率。但是，直到1982年以后，非政府学校里女生的保留率才超过男生。</p><p>保留率受不同因素的影响。就国家一级来讲，这些因素包括复读学生数、移民和学生性质的变化（如海外缴费学生数的不断增加）等。此外还要注意的是，学生从政府学校向非政府学校的流动也使得非政府学校的保留率得以上升，而政府学校的保留率下降。</p><p>学校教育拨款</p><p>1999-2000，澳大利亚各级政府教育事业费达到340.36亿澳元（包括固定资产贬值，但不包括支付非财政性资产的开支），占GDP的5.3%。同年，政府在非财政性规定资产上的现金开支达到19.76亿澳元，私人教育现金支出95.75亿澳元，占当年GDP的1.5%。</p><p>在340.36亿澳元的政府教育事业费拨款中，学前教育经费11.11亿澳元，约占3.26%；中小学教育经费184.55亿澳元，约占54%。</p><p>职业技术教育政府拨款占政府全部教育事业费的10%。职业技术教育财政拨款中，54%来自州和领地财政拨款，只有21%左右来自联邦政府拨款。就整个职业技术教育经费而言，约有21%的收入来自教育服务收费、从事贸易以及向学生收取的学费等（其中向学生收取行政管理费占4%，全额缴费学生的学费、向海外学生收取的学费、雇主或其它个人或组织向学校交纳的服务费等约占11%）。</p><p>高等教育政府拨款占全部政府教育事业费的28%。1999-2000年，&ldquo;1988年高等教育拨款法&rdquo;所规定的高等教育机构的全部事业费收入达到87.3亿澳元，联邦政府拨款只占其中的45%。此外，联邦政府也通过&ldquo;澳大利亚研究委员会&rdquo;向高等教育机构拨付了一部分科研经费。</p><p>就非政府学校而言，各州、领地政府的拨款相对较少。1998年非政府学校的经费43％来自私人资源，40％来自联邦政府拨款，17％来自各州和领地的拨款。非政府学校根据设立于各州和领地的政府机构（通常是注册委员会）规定的条件进行运转。这些条件包括要求学校达到最低教育标准，并有令人满意的房产等。</p><p>绝大部分非政府学校由天主教会开办，每个州、领地都设有&ldquo;天主教教育委员会&rdquo;，全国也有这样一个委员会。其它非政府学校则由其它宗教团体开办，或监管。</p><p>职业教育和培训</p><p>（一）职业教育和培训机构</p><p>职业教育和培训课程大部分都由政府管理的教育机构提供。在一些州和领地，这些机构一般称为&ldquo;学院&rdquo;，或&ldquo;技术和继续教育&rdquo;学院。少数技术学院、部分高等教育机构、中学、农业学院、成人和社区教育机构、私营教育提供者以及雇主，也提供职业教育和培训。2000年，全澳共有92个TAFE学院和其它类型的政府机构，在1,322个教学点提供职业教育和培训。另外有139个社区教育提供者和3,389个其它类型的教育提供者享受部分政府拨款。</p><p>职业教育和培训机构遍布澳大利亚农村城镇，类型多样。例如，维多利亚州20个TAFE机构中，有4个既是高等教育机构，又是VET机构，6个在监狱里提供教学课程，4个有海外校园。昆士兰州、西澳州和北领的一些大学也设置VET课程。</p><p>（二）学生和课程</p><p>培训课程分为12个学习领域。这种分类与高等教育机构所覆盖的学习领域大体一致。表八是政府拨款的职业教育和培训的入学情况。</p><p>深受客户欢迎的课程包括：商科，管理和经济学科，工程和测量学科，服务、酒店管理和交通运输学科等。在土地、矿产、畜牧、建筑、工程、测量等领域，超过50%的注册学生是男性。绝大部分女性选择学习商业、管理、经济、艺术、人文社会科学、健康和社区服务、兽医和动物养护等学科。</p><p>高等教育</p><p>（一）高等教育机构</p><p>澳大利亚高等教育机构分为四个部分。</p><p>1、大学</p><p>澳大利亚对&ldquo;大学&rdquo;名称的使用非常严格，有一定的使用标准。现在，以大学名称命名的高等教育机构共有39所，其中两所（即Bond University和University of Notre Dame Australia）为私立大学。除了澳大利亚国立大学和澳大利亚海洋学院由联邦政府立法成立之外，其它大学都由所在的州、领地立法成立。各大学有自主开设课程和授予学位的权利，都接受或部分接受联邦政府拨款，一般都有多个校园。</p><p>2、其它有自我评定权的高等教育机构</p><p>这类院校共有三所，即Australian Maritime College, Batchelor Institute of Indigeous Tertiary Education和Melbourne College of Divinity。这三所院校尽管不以大学命名，但都依法成立，有自主开设课程和授予学位的权力，前两所院校都由联邦政府拨款。上述两类院校相加，就是人们常说的42所高等院校。</p><p>根据联邦教育部的统计，上述两类高等教育机构2000年的学生数量约69万，其中公立大学的学生数约为64万，私立高等教育机构的学生数约为5万人。</p><p>3、非大学类高等教育机构</p><p>澳大利亚非大学类高等教育机构共有60所，它们一般有学士学位、硕士学位、研究生证书、研究生文凭中的一个或多个学位或学历授予权。他们属于非自主类院校，无权自主开设课程或提供学历教育。如果要开设课程或提供学历教育，须得到相关州或领地高等教育审批机关的批准。</p><p>4、宗教院校</p><p>这类院校共有32所，与第三类院校一样，这类院校也是非自主院校，其课程和学历都要由其所在州或领地高等教育审批机关的批准。</p><p>2000年，42所大学以及澳大利亚电影电视和广播学校、国家戏剧艺术学院、澳大利亚国防学院接受联邦教育、科技和培训部的拨款。</p><p>（二）教职员工</p><p>高等教育教职员工分为学术性和非学术性员工。2000年的统计数据显示，非学术员工的数量大于学术员工的数量。绝大部分学术员工都是讲师或高级讲师。</p><p>（三）学生和课程</p><p>高等教育机构不仅提供全日制课程，也提供业余课程和远程教育课程。部分机构提供全日制学习和部分时段工作的课程。1990年至2000年，高等教育学生数量从485.1万增加到695.5万，增长69%。值得注意的是，在1990年，全日制高等教育学生数量占学生总数的62%，而2000年，由于远程教育的逐步发展，这一比例下降到59%。</p><p>高等教育机构一般提供3年或4年的学士学位课程，部分高等教育机构也提供文凭和高级文凭课程。绝大部分高等教育机构提供研究生课程，硕士学位课程一般需要1年到2年，博士学位课程一般需要3到4年。部分专业提供研究生文凭和证书课程。2000年，77%的高等教育学生学习学士学位课程，约19%的学生学习更高一级的学位或其它研究生课程。高等教育机构提供内容广泛的学习课程，包括农业、建筑、人文艺术、商业、牙医、经济、教育、工程、科学、健康、法律、医学、兽医等。2000年，学生学习较多的课程是商业、管理和经济类课程（24%），人文、艺术和社会科学类课程（22%），科学类课程（15%）。</p><p>（四）高等教育经费构成和拨款机制</p><p>澳大利亚现有42所高等教育机构（其中公立大学37所，私立大学2所，其他类型的公立高等教育机构3所），其事业费及相关费用（Operating Grants and Related Grants）均由澳联邦政府直接拨付。2001年度，澳大利亚42所高等教育机构从联邦政府和社会各界所获高等教育经费总额达90亿澳元，约占GDP（5952.08亿澳元）的1.51% ;其中联邦政府对高等教育拨款总额达58.6亿元，约占GDP（5952.08亿澳元）的0.98%。</p><p>(五) 教育国际化</p><p>近些年来，澳大利亚各大学十分注重教育国际化，从事教育输出。教育输出已成为澳的第四大产业，为澳大利亚创收了40多亿澳元。为了创收，澳大利亚各大学十分重视从海外，特别是从亚太地区国家，招收海外学生。一些学校已把目标瞄准了这些国家，并在有些国家开设了自己的分校。澳大利亚很多大学也看好了中国这个大市场，纷纷到中国寻找合作办学的机会和伙伴。据有关统计显示，在上述40多亿教育产业收入中，有一半来自中国。</p>'),
    (23,23,'<p>中国人留学为了啥，90%以上都是为了毕业后移民找工作享受生活，有几个有资格移民却最后回到中国的（官二代富二代除外啊）。现在全世界经济，最好的肯定是澳大利亚，没有之一两个字，远远超过其他那些留学大国。</p><p>澳大利亚平均工资6万4千澳元每年，1澳元=6.70人民币。</p><p>加拿大约为4万2千加元，1加元=6.52人民币</p><p>英国约为2万3千英镑，1英镑=10.47人民币</p><p>美国数字4万3千美元，1美元=6.69人民币</p><p>澳大利亚失业率为5.1%，美国为9.8%，加拿大为8%，英国7.9%</p><p>澳大利亚最低工资，15澳元一小时</p><p>http://www.livingin-australia.com/salaries-australia/</p><p>加拿大最低工资，只有8加元，约等于澳大利亚一半</p><p>http://canadaonline.about.com/library/bl/blminwage.htm</p><p>美国最低工资普遍8美元以下，GEORGIA居然是5.15美元1小时</p><p>http://www.dol.gov/whd/minwage/america.htm</p><p>英国最低工资，2010年10月上涨到5.93英镑，现在是5.80英镑，约为9.6澳元一小时</p><p>http://www.direct.gov.uk/en/Nl1/Newsroom/DG_178175</p><p>英国美国加拿大失业率基本是澳大利亚的一倍，人均工资大概只有澳大利亚的三分之二，而且未来澳大利亚经济走向肯定远远好于美国英国加拿大。大家常去澳洲论坛和美国加拿大论坛的，比如文学城等，会发现华人的生活状态完全不一样的，北美那边谈论的基本都是怎么找工作之类的，澳洲基本每人讨论找工作，都是怎么旅游，怎么多买几套房子。这就是生活差距。</p><p>虽然澳大利亚学费生活费都比美国英国加拿大贵很多，不过我觉得如果能够移民澳洲之后找到工作，那些钱一年两年基本就赚回来了。比去那些根本找不到工作的国家强多了。</p>'),
    (24,24,'<p>据澳大利亚媒体报道，一项针对高等教育系统进行排名的研究显示，尽管澳洲在教育资源方面投入较低，但是毕业生人数以及研究成果却不凡，因此在全球排名第8位。</p><p>不过墨尔本大学的威廉姆斯教授(Ross Williams)警告，如果澳洲政府不对高校加大研究投入的话，用不了几年澳洲的高校表现可能就没有那么好了。</p><p>这次分析针对48个国家的高校机构，结果显示全球高等教育表现最佳的国家是美国，其余排名前十的国家依次是瑞典、加拿大、芬兰、丹麦、瑞士、挪威、澳洲、荷兰以及英国。</p><p>威廉姆斯教授认为，澳洲的高校表现应该和北欧国家及加拿大一样好，如果政府不加大投资、尤其是研究方面的投资，那么澳洲也许很快就会落后。</p><p>这项研究显示了各国高校在4个广泛领域中的表现，以及一个整体排名。澳洲在国际联系方面排名第4，这主要是归功于澳洲庞大的留学生人群。</p><p>在&ldquo;产量&rdquo;方面，澳洲排名第7，这一项包括了研究报告、入学人数以及24岁以上的高等教育学生比例。</p><p>在教育环境方面，澳洲排第7，其中包括了当局的相关政策、监管环境、以及高等教育数据以及女学生的比例等。</p><p>不过澳洲在资源方面的排名，竟然就只有第19位。</p><p>威廉姆斯教授称，值得欣慰的是，澳洲的高等教育业虽然投入很少，但是其他领域的排名却还不错，总排名还进入了前八强，这说明了澳洲的高等教育称得上&ldquo;低投入高产出&rdquo;。</p>'),
    (25,25,'<p>相对美英等国昂贵的留学成本，以及令人堪忧的就业前景，身处南半球的澳大利亚反倒成为一个利于安心留学的平静港湾，成为诸多中国学生海外留学的上选。</p><p>首先，澳大利亚教育层次丰富，教学质量国际领先。其次，澳大利亚作为一个移民国家，移民政策平易近人，就业机会广阔。最后，澳币对人民币的缩水也给中国留学生带来实惠，由于汇率的变化，留学费用降幅达30%。</p><p>三重利好</p><p>留学成本跳水现阶段澳币兑人民币汇率是1：5左右，以现在比较热的澳洲学校麦考瑞大学举例，本科资金担保需人民币约50万元，研究生2.5年的会计硕士，仅需资金担保39万元。而以往资金担保分别需要本科约68万元，研究生约52万元。</p><p>澳洲还有一些研究生课程仅需要读一年，资金担保现仅需要人民币18万元左右，以往需要20多万元(仍然是用麦考瑞大学作为参照)。由此可见十几万元能读出一个澳洲名牌大学的硕士，已成为可能。</p><p>教学质量有保证国外高校有很大一部分资金来源要靠企业捐助，随着金融风暴持续，企业为学校提供的资金相对会减少，学校为了盈利，常超额招生导致教学质量下降。澳大利亚的大学几乎都是公立大学，资金来自澳大利亚政府，所以学校必定会在保证自身教学品质的前提下进行全球招生。</p><p>毕业时或迎就业高峰金融危机往往存在周期性，在目前低谷的时候求学，在经济逐步恢复的时候找工作，会是更合理的个人规划。现在潜心求学，待到危机过后凭借着良好的教育基础和国际视野，为人生的大发展做充分的准备。每次的危机之后都是企业用人之际和求职的黄金季节，这对众多学生来说是一个不容错过的好机会。</p><p>两大平价方案</p><p>根据留学专家设计，澳大利亚留学可以有两种比较平价的留学方案。这两种方案尽管形式略有不同，但是本质上却都是通过压缩留学时间，节省在澳留学的费用。根据测算，花费至少可以便宜人民币10万元以上。</p><p>方案一：直读大学一年级文凭课程</p><p>除了澳洲的五所大学一定要通过预科外，绝大多数大学可以通过快捷课程直接就读大学一年级文凭，或者通过高考成绩直接申请就读大一。</p><p>这一方案适用于澳大利亚多数学校。留学专家推荐院校有：可以通过快捷课程入读的大学阿德雷德大学、莫纳什大学、麦考瑞大学、佛林德斯大学等。</p><p>该方案优势体现在：</p><p>省时免去预科一年的时间，大一文凭毕业的学生直升大二。这样一来，文科、商科的学生本科学业只需要三年即可完成。</p><p>省费比读预科的方案节省一年的支出，学费生活费总共可以节省人民币12万元。</p><p>课程深入浅出、容易结业为国际留学生特别开设的25人左右的小班授课方式，使得中国留学生逐步适应国外授课方式，分阶段消化教学内容。</p><p>方案二：直读大学一年级</p><p>英语成绩优异并且适应能力强的学生，还可以参考直接升读澳洲大学一年级的方案。</p><p>这类方案适用于优秀学生，留学专家推荐院校有：麦考瑞大学、拉筹伯大学、塔斯马尼亚大学以及卧龙岗大学。以上大学都排在世界500强的大学之列。</p><p>该方案优势体现在：</p><p>英语环境好从一开始就是与当地学生一起进入大一年级，英文环境比快捷课程或者预科课程都要好。</p><p>省时省费减少了1年的预科，节省了1年的海外花费，所以适合家庭情况不太宽裕的学生。</p><p>学费</p><p>赴澳大利亚留学的海外学生除少数奖学金获得者外均须缴纳学费。澳大利亚的学费通常比英国美国低，不同院校的收费会有所不同。下列收费可作参考：</p><p>中学：每年5000-10000澳元；</p><p>英语课程：每年7000-8000澳元；</p><p>职业技术培训课程：每年3000-12000澳元；</p><p>学士课程(如经济学及法律学)：每年12000澳元；</p><p>需要实验的学士课程(如科学及工程学)：每年14000-16000澳元；</p><p>硕士、博士课程：每年12000-18000澳元；</p><p>医科课程：每年不低于25000澳元。</p><p>伙食</p><p>澳洲是一个多元化的国家，各国风味饮食在每个大城市甚至各区域的购物中心都很容易找到。除了餐馆之外，也很容易买到各式食谱材料在家烹调，例如中餐，几乎各大城市都有中国城，在那可以买到所有我们需要的菜。除了中国城外，很多郊区的购物中心也都有一或二家的亚洲食品杂货店以方便移民及留学生解决食的问题。所有学校里都设有餐厅、福利社，提供简便餐饮给学生。平均伙食费一周约澳币50-90元。</p><p>住宿</p><p>与澳大利亚人家庭同住(费用150-200澳元/周)；</p><p>寄宿学校(费用8000-9500澳元/年)；</p><p>租住或分租(费用70-150澳元/周)；</p><p>学生招待所(费用80-120澳元/周)。</p><p>交通</p><p>澳大利亚大众运输工具有公车、火车、航空，而有些城市有电车及渡船，其他还有计程车、私人汽车、自行车及非常少数的摩托车。一般而言澳洲的大众运输很方便，不论火车或公车及航空的各路线都有时刻表，可以到各交通单位索取。</p><p>澳洲的各城镇都有很好的道路与航空网路连接，所以长途旅行也很方便，有关这方面的资讯可直接向铁路、航空公司、巴士公司、观光局或旅行社索取与定位。对于学生的长程旅游有时还有打折的优待。</p>'),
    (26,26,'<p>举几个我曾经咨询过的赴澳洲留学案例，来进一步说明不同类型的学生应该如何定位留学方向。<br />案例1<br />张XX，是上海市某重点高中2003年毕业生，其父在2002年孩子刚上高三时来我这里咨询留学事宜，一开始也是抱着考不上复旦就出国的想法。经过几番讨论，并听了留学讲座后改变了原先的观点，决心送孩子去澳大利亚国立大学念精算专业。2003年该生参加了高考，并顺利拿到了复旦的录取通知。最终于2003年9月拿到澳洲签证出国。<br />点评：从国际教育资源的角度来说，学生即便考上了复旦大学，如果能进澳洲国立大学念本科，何乐而不为？学生之所以没有放弃高考，原因有二：一是签证未下来之前，不要轻易放弃国内的学业，以免万一签证不过造成被动局面；二是正常的学业可以保持孩子学习的连贯性。现在，这个学生已经在国立大学念精算专业大学二年级了。<br />案例2<br />李X，是上海市某区重点学生，成绩在班内属于中等，班主任对其的评估是正常发挥可以考上二本。家长也是抱着万一考不上大学就送其留学的念头前来咨询。在仔细了解孩子的情况后，我建议家长考虑申请阿得雷德大学的学位转移课程，这样可以在孩子的学习能力范围内以相对较短的时间完成本科学习。阿得雷德大学是澳洲八大名校之一，以李X的情况看，需要他很努力才能较好地应对将要面临的学业压力。所幸该学生英文水平较好，而且也表达了比较强烈的用功读书的愿望，我觉得这样的学生出国读书会取得成功。目前他已经通过DTP课程，顺利进入大二的计算机专业。<br />点评：李X参加了当年高考，也正如其班主任所料，成绩刚好略低于一本分数线。他如果考上了国内的一本会不会放弃出国？他不会的，因为阿得雷德大学也排名世界前200位，理工科又是该校的强项，再加上学生家里的经济条件不错，他自己又有强烈的出国读书愿望，这样的机会没有理由放弃。　</p>'),
    (27,27,'<p>白领人群也会成为赴澳留学的一支生力军.</p><p>因为对学历的渴望、知识的渴望会比刚毕业就要留学的学生会更迫切一些，资金也已经到位了,&nbsp; 所以这部分学生在选择留学的时候会更积极.&nbsp; 通常来说，留学手续包括申请、资金、雅思三部分.&nbsp; 当资金已经到位了，还欠缺两方面，一个就是申请。申请我的建议是这样，因为每个学校的开学时间不一样，虽然澳大利亚两次开学，2月、7月，但是有个别的学校可能1次开学，所以申请时间一定要做好规划。</p><p>还有一个不一样的地方，对白领来讲就是雅思了，因为白领去留学，可能只是学语言，提升英语方面的表达或者沟通能力。另外一方面，他们是做573，是去多硕士，这种硕士课程来讲，我觉得雅思分数是重要的，这个课程雅思分数需要通常硕士一般6.5分，只有个别学校是6分，很少。白领来讲在日常工作当中，虽然英语接触很多，但是这个接触多并不见得在雅思考试的四个单项中都表达出来，可能只是说口语能力很好或者阅读能力很好，因为白领日常的写作能力，可能是日常化的、办公化的，不见得是符合雅思考官的需要，所以雅思方面还是需要再提高的。而且这个雅思考试本身分为四个方面也是有两个要求，一个是平均分的要求，另外是四个单项的学校，可能学生平均分够了学校的标准，但是只是写作没有过，实际上也是不符合标准，如果读硕士在英语方面也是着重的考虑。</p>'),
    (28,28,'<p>澳大利亚中小学教育概况</p><p>澳大利亚的中小学是十二年制，一年级到六年级为小学，七年级到十二年级是中学。其中七年级到九年级为初中部（相当于中国的初一到初三），九年级到十二年级为高中部（相当于中国的高一到高三）。十二年级是特殊的一年，因为在这一年中，中学生们要做中学毕业的准备，并参加中学毕业考试。这个中学毕业考试的成绩是做为进入大学的唯一参考成绩。</p><p>澳大利亚的中小学可分为公立和私立两种教育体系。公立学校是国家政府资助的，私立学校则是私营的。还有一些教会学校都是私营的。总的来说，在教学内容上，公立和私立学校几乎没有什么不同。只不过因私立学校的资金来源广泛，财力雄厚而导致师资力量强、教学环境好、教学设施先进等等。在学费方面，私立学校较之公立学校贵些。例如，公立学校高中十至十二年级的学费一般为九千澳元，而相应的私立学校一般为一万至一万二千澳元不等。</p><p>澳大利亚中小学教育体制及内容与中国大有不同。在澳大利亚学习不是以死记硬背为主的填鸭式教学方法，而是侧重于实践知识的掌握和动手能力的培养。学生在澳大利亚读书的压力并不大，完全要靠自觉。澳大利亚中小学的教学设施较好，一般都有运动场、游泳池、图书馆和计算机房。许多学校要求学生穿统一的校服，有的还要求学生购买手提电脑。</p><p>在澳大利亚，中小学一学年分为四个学期。每学期不到三个月，而且每学期之间都有几个星期的假期。年底的假期最长，长达一个多月。</p><p>许多中国家长所担心的是孩子在澳的食宿及监护问题。这一点是很可以理解的，因为中学生毕竟年龄小，生活能力不强。但其实家长大可不必太担心，澳大利亚是一个很安全、社会治安很好的国家，同时它也很重视对学生的爱护。如果家中有亲戚在澳当然最好，如没有，我中心会帮助海外留学生安排寄宿家庭，可以是华人也可以是澳洲人，他们提供一日三餐及住宿，并做好与学校和家长的联系工作。如住在澳洲人家里，对学生的英文水平的提高将有很大的帮助。</p><p>申请进入澳大利亚中学学习</p><p>澳大利亚政府一直把教育做为一种工业为国家赚取大量的收入，尤其是亚洲市场，更是澳大利亚教育输出的主要对象。但自从亚洲经济危机以来，来自东南亚的生源急剧减少，大大降低了国家在教育方面的收入。为弥补这个损失，澳大利亚政府决定进一步开放中国市场，希望吸引更多的中国海外留学生来澳就读中学和大学。</p><p>现在中国已有许多中学生在澳洲就读，同时还有更多的学生希望来澳，只是苦于信息不灵通或没有相应的渠道。澳大利亚移民法律中心是一家资深的澳大利亚顶尖持牌移民服务代理之一，在办理学生签证领域经验丰富。以下是我公司总结的就赴澳读中学的几点经验：</p><ol><li>年龄要适当</li></ol><p>年龄最好在14至18岁，未读完高中的中国中学生可申请在澳大利亚中学继续读相应的年级。例如学生14岁，在中国就读初二或初三，可申请在澳就读8年级或9年级。如学生17岁，在中国就读高二，可在澳大利亚中学读11年级。如学生已满18岁，但还未完成高中的学业，仍在高三就读，我公司也可联系在澳的相应高中课程，办理签证，但要根据学生的具体情况而定。</p><ol start=\"2\"><li>对英语水平的要求</li></ol><p>许多中学生担心自己的英文水平不够，不能适应在澳读中学。其实这种担心大可不必。因为澳大利亚的中学都要求海外留学生在上正式的中学课程之前补习一段时间的英文课程。一般来讲，英文课程是在所接收中学上，但也有在其他中学上的。英文课程的长短要因人而异，大约有半年左右。</p><ol start=\"3\"><li>经济担保及家庭经济背景</li></ol><p>此项要求是办理中学生赴澳最关键的一点，也是办理签证最重要的一点。相比之下澳大利亚中学的学费是比较贵的，私立中学则更贵一点。学校要求学生的家长有足够的经济实力以担保其子女在澳就读。如果学生在澳就读的时间越长，所需的担保金额则越大。此外，在办理赴澳签证方面，澳大利亚移民局在资金方面也有严格的规定，即不仅要提供所上整个中学课程的经济担保，同时也要评审学生家庭是否有足够的经济实力以提供其子女上大学的经济担保。</p><p>有的人认为只要家里有一大笔存款就可以送孩子赴澳读书，其实不然。有存款以确保缴纳学费和生活费当然是一个重要的前提，但并不是只要有钱就可以获得签证的。澳大利亚移民局要综合评审家庭背景及经济情况，例如存款数额、存款来源、父母的职位、父母年收入、家庭的社会背景及家庭的不动产等等。就我中心的办案经验而谈，学生的父母最好有自己的企业，或在公司中任要职，或在公司中占有股份，有较高的年收入以及一定的家庭存款（半年以上）。如果家庭还拥有自己的房子和汽车则更有说服力。</p><p>澳大利亚移民局之所以有经济方面的评审是出于对学生真实性的考虑，即他们不希望因经济原因而导致学生在澳不能顺利就读，或违反签证规定在澳非法打工。同时他们也不希望经济担保给学生家庭带来沉重的经济负担。因此移民局审核比较严格、细腻，许多条件很好的学生遭到拒签，只是因为不懂签证手续及如何提供材料。</p>'),
    (29,29,'<p>昨日，记者走访市内各大留学中介发现，今年提前在高一、高二选择出国的学生明显增多，部分中介机构的数据显示高一、高二学生出国比例同比去年同期增加约30%左右，而由于汇率变化导致出国费用较去年降低，是家长选择提前送子女出国的重要原因。记者获悉，由于不少家庭今年银根紧缩，相对于美、英等，澳大利亚、加拿大等国家由于费用相对便宜，而备受家长青睐。专家建议，这些&ldquo;低龄高中生&rdquo;在准备留学前，最好能提前半年就做专业咨询。</p><p>变化：高中生提前出国</p><p>记者了解到今年留学市场上的&ldquo;主力军&rdquo;仍以高中生为主，但据介绍，今年至3月中旬，前来咨询并已确定出国的高一、高二学生，同比去年同期增加约30%左右。</p><p>对此，业内人士表示，由于汇率变化而导致的学费和生活费较往年大幅降低，是家长选择提前送子女出国的主要原因。&ldquo;按照现在的汇率，去澳大利亚留学的同样学校学习，相对于1年前，现在每年生活费和学费可减少10万元左右。&rdquo;</p><p>此外，专家介绍，&ldquo;现在很多家长和学生的心态不一样了，他们把出国定为确切目标，此外，如果早点留学，语言的基础会较继续在国内读完高中好很多。&rdquo;</p><p>选择：低费用国家受青睐</p><p>记者了解到，除低龄化外，由于经济大环境影响，今年家长在选择出国留学的国家时，会倾向于选择一些费用方面性价比较高的国家。相对于美国和英国，家长们会更精明地选择澳大利亚、加拿大这些费用方面降幅较大的国家。按照1年前人民币兑换澳元的比率是6.4：1来算，留学澳大利亚一年的费用大概是人民币20万元~25万元，而最新的兑换比率约为4.3：1，也就是说今年留学澳大利亚可能一年费用仅需人民币15万元左右。而考虑到美国受金融危机的冲击较大，今年咨询留学美国的佛山家长也有所减少。</p><p>提醒：最好提前半年做咨询</p><p>记者从留学中介了解到，高中生选择出国时，需备齐的资料包括初中3年以及高中已读年级的成绩单，初中的毕业证、私人文件（包括出生证明的材料、户口本、护照、身份证）以及父母的收入证明，提供的资金存折证明等。</p><p>&ldquo;家长和学生最好能在开学时间前的半年就着手做准备，尽早咨询。&rdquo;留学顾问表示，目前存在的通病是家长往往到临近申请开始前才来咨询，导致部分心仪国外高中的学位一早就已经招满。此外由于国外高中的语言班是每两个月开设一期，提前咨询更容易在时间上做调配。专家提醒，家长可以根据自己子女的成绩提前咨询到相匹配的学校，然后通过中介推荐意见和上网登录相关网站，或该校的官方网站，查询这所高中的简介和教育水平，还可以根据这所高中在其国内的综合排名以及升上重点大学的升学率，来对这所学校的教学质量作出判断。</p><p>雅思：复习考试最好能提前半年</p><p>出国留学的高中生低龄化也间接催热了本土的培训机构。记者从开设了雅思和托福等培训课程的机构了解到，与打下一定英语基础的大学毕业生不同，目前高中生在备战雅思和托福的时候无论是在口语、听力、阅读等方面的水平都相对较弱。高中生备考雅思和托福如何能取得高分？</p><p>今年24岁的阿君本科毕业于广外，现就读英国Bristol大学，雅思曾取得7分。阿君表示，高中生复习雅思考试最好能提前半年左右时间，如果方便的话，周末就可以先去上培训班，同时先增加词汇的记忆，扩大词汇量。</p><p>&ldquo;高中生的话词汇量做雅思阅读一般都比较吃力。如果目标是6分以上的话，平常最好就看点英文类报纸。&rdquo;阿君说，像《21st Century》等英文类报纸都是不错的选择，而背单词则可选择《剑桥雅思词汇精选》。在离考试四五个月左右的时候，可去上一下培训班。而最后三个月重点推荐的教材是《剑桥12345》。阿君建议，最好第一次考雅思的时间比预定的稍提前一点，这样第一次分数不够，可准备1个月再考一次。</p><p>托福：听力每天至少练1小时</p><p>据介绍，高中生准备托福，主要存在三方面的&ldquo;短板&rdquo;。首先是词汇量，其次是读写能力方面，此外，是托福考试的听力部分语速很快。对于高中生来说，想要取得80~110分的成绩，需要3到4个月左右的时间，其中单词方面应该靠长期的积累。</p><p>而针对托福的语速较快的特点，每天都做听写练习是少不了的，听写练习较好的材料是老托福听力的Part C，高中生每天花在听力上的时间不应少于1小时。阅读方面的挑战主要来自于词汇，假如考生已经攻克词汇难关，还需要做一项工作，就是阅读题型的分类。阅读量大约在四万词左右对学生阅读速度的提高和题型的熟悉十分有效，因此家长也应督促孩子保证每天的阅读量</p>'),
    (30,30,'<p>随着中国经济的飞速发展，随着中国家长的意识观念的国际化并轨，许多学生和家长都在考虑是不是要送孩子出国去读书？随着高考难度加大、想考入优秀大学越来越难，随着高校的不断扩招和糜烂颓废的大学生活的暴光，越来越多家长和学生都在质疑，是否需要选择参加高考或者入读国内的各种名目繁多的高校？那么对于有送孩子出国留学的家长，对于有目标和勇气出国读书的中学生来讲，什么时间是办理出国留学手续最合适的时机呢？选择什么样的国家送孩子出国读中学最好呢？该怎么安排国外的语言和中学课程的学习计划，最经济最省时间呢？</p><p>作为近十年来留学政策最稳定，签证批准率较高的国家之一，澳大利亚一直以其优美恬静、自由宽松的自然环境及人文环境吸引着中国学子。作为一个集中有八所世界前100名著名大学的国家，澳大利亚的高校为留学生提供了教育严谨、人才培养注重实际应用、教学设备及理念先进的本科学士课程。无论从文学、理学、工学、商学这些基础学科，还是法学、农林学、医学、制造学、航海航天学等专业性超强的科目，澳大利亚为您呈现的是超过1000多个专业的完善系统培训的不同等级学历课程。多元化的社会和校园更为留学生自由愉快的学习和生活提供了温暖的环境。无疑对于年纪偏小，专业和爱好可塑性强的中学生来讲，赴澳大利亚留学将是学生和家长最关注和最佳的选择！</p><p>一、如果你还在高中二年级或以下级别中学就读，那么恭喜你！你现在选择澳大利亚留学将是最经济划算，最不费力融入西方主流教育的时机：</p><p>澳大利亚使馆在2000年7月份的新签证政策说明，所有申请中学12年级以上课程学生需要提供至少总分5分的A类雅思成绩，同时，办理澳大利亚签证的中学生主课课程时间不得少于16个月，也就是说至少申请11年级（部分）和12年级课程才符合使馆规定，而很多高中学生办理时间稍晚，甚至高二课程即将结束才决定办理留学手续，如果此时申请签证，也就是意味着需要重读一年高二课程，也就是澳大利亚的11年级，学生既要重读课程，同时签证审理时也会因为年龄、倒读课程情况受到限制，所以办理中学课程赶早不赶晚，一般情况初三、高一办理澳大利亚中学生签证时机最好。一般情况，初三学生可以申请澳大利亚10年级，高一学生可以申请11年级，如果高二学生，为了满足澳洲签证政策，中学生课程不得少于16个月的规定，也只能申请11年级，相比之下，中国初三、高一、或者刚上高二学生选择澳大利亚的中学课程比较适合。</p><p>学生可以选择公立中学、私立中学、大学附属中学学习，有的学校对学生成绩、年龄、插读课程有规定，学生选择课程时需要同咨询顾问详细了解询问。</p><p>　　</p><p>二、如果你已经高中二年级毕业或高三年级在读了，那么也没有什么损失！现在你选择进入大学预科课程将是最省时间、最省金钱的时机了：</p><p>如果中国高中二年级学历以上的学生，能够出示高中四学期成绩那么就可以申请澳大利亚大学的预科课程了！由于大学预科是大学的基础课程，澳大利亚多数本科学士课程为三年学制，因此学生在入读本科学士前的预科课程就是非常必要的衔接国内中学和澳大利亚大学的环节了！学生在申请预科课程时需要确定选择课程专业方向，一般分成文科、商科、工科、科学等专业，由于学生在国内申请澳大利亚的大学预科时可以获得&lsquo;大学预科和本科&rsquo;两份录取通知书，很多大学预科为了保障学生生源质量，对学生中国境内的学习成绩有严格的要求，现在申请竞争比较激烈的是排名靠前的大学预科，例如澳洲国立大学、墨尔本大学、新南威尔士大学等预科课程。</p>'),
    (31,31,'<p>最适宜的城市，最合适的学校</p><p>对国际留学生而言，选择一个合适的学校就读无疑是他们留学生涯中最重要的一个决定。我们相信，维多利亚州的政府公立中学有以下值得你选择她的原因：</p><p>墨尔本是全世界最适宜人类居住的城市，社会稳定、治安良好，并且是一个多元文化的城市；</p><p>在此获得的高质量教育获得全世界的广泛认可；</p><p>有近200所政府公立中学可以供你选择；</p><p>有专门针对国际留学生的英语课程；</p><p>你可以选择住宿澳大利亚人家庭，这样将有助于加深对澳洲文化的了解和认同；</p><p>学校提供全方位的呵护，确保学生能够安心地学习；</p><p>学习费用低廉；</p><p>所有学校全部受维多利亚州教育部监管，确保教育质量。</p><p>国际留学生可以选择他们想要就读的维多利亚州公立学校就读，学校可以提供大量的学习科目供学生选择学习。所有的公立学校都可以为国际学生提供以下的服务：</p><p>免费机场接送；</p><p>协助安排住宿；</p><p>良好的教育设施；</p><p>英语课程辅导；</p><p>新生入学欢迎会；</p><p>高质量的教师队伍；</p><p>大量课程供选择；</p><p>就业建议。</p><p>维多利亚政府学校根据学生的需要提供一系列的可供选择的科目，这些课程安排都是为了让学生可以接受更广泛的教育和职业机会而设计的。学生可以从以下八个主要的学习领域中：英语、数学、科学、科技、社会和环境学习(地理、历史和商业)、语言(41种)、艺术、卫生和体育，学习到知识、技能和人生价值。</p><p>这些普通的课程都是提供给从7-10年级的学生，学生每学期一般说来要学习总共10个以上的课程。学校学年分四个学习段，每两个学习段为一个学期。</p><p>11-12年级的学生构成了维多利亚教育证书的课程，这个时候，学生就必须开始接受有关他们将来职业计划的有选择性的专业课程科目。学生通常在11年级时间选6门课程/每学期，但在12年级学生必须每学期选择最多5门课程来学习。</p>'),
    (32,32,'<p>TAFE (Technical and Further Education) 即技术与继续教育学院的简称，从2003年的&ldquo;无人问津&rdquo;到如今的&ldquo;供不应求&rdquo;，早已悄然成为澳大利亚留学的主流产品。然而究竟什么样的人群适合选择到澳大利亚读TAFE 课程？是否所有的学生都适合TAFE 课程？不同的人群如何选择正确的TAFE专业？已经成为越来越多准留学生的困惑。</p><p><strong>一．TAFE课程介绍及特点</strong></p><p>首先，我们先明确一下TAFE 的定义，以及她所提供的课程特点。</p><p>TAFE (Technical and Further Education) 即技术与继续教育学院的简称。已有100多年的历史，也是澳大利亚一种独特的职业教育培训体系，隶属于澳洲政府的各州教育部，他所提供的课程均以实践和技能为主。</p><p>TAFE 课程的特点：</p><p>1． TAFE 学院所提供的课程主要是根据当地的就业需求开设的，因此大部分课程都为紧缺职业，大部分专业在申请移民职业评估的时候可以评估到60分。</p><p>2． TAFE 课程将理论和实践相结合，特别强调实践性和操作性，以及学生操作能力动手能力的培养。</p><p>3． TAFE 课程的学费普遍比较低，平均每年为1万澳币左右，仅为本科或者研究生课程学费的一半。</p><p>4． TAFE 课程对于语言的要求相对较低，一般要求5.5分，个别专业听说读写单科不能低于5分。</p><p>5．入学条件为高中以上或等同于高中学历即可。</p><p><strong>二．哪些学生适合选择澳大利亚的TAFE课程？</strong></p><p>根据TAFE课程的特点，我相应的归纳出如下几类客户适合选择TAFE 课程：</p><p>1．以&ldquo;移民&rdquo;为主要目的的学生，这个是选择TAFE课程的首要前提。由于大部分TAFE课程均针对当地紧缺职业开设，定向培养，因此移民职业评估分数较高，就业需求相对比较大。</p><p>2．动手能力强或在该领域已经有一定的专业技能或实践经验的学生。这类学生动手能力较强，或者在国内专科或职业学校已经学习了一些相关技能或工作了一定时间，比如厨师，美发师，点焊技工等。</p><p>3．经济条件一般的工薪阶层。由于TAFE 课程的学费仅为大学课程学费的一半左右，每年连同生活费的全部花销约为2万多澳币。学生可以先选择TAFE课程，移民后继续后续课程的学习，享受当地学生的学费。</p><p>4．英文基础一般的学生。 TAFE 课程对于英文要求普遍为5.5 分，学生只要考到最低5分便可以配读语言课程，进入主课学习了。</p><p>5．国内成绩或学历一般的学生。一般国内高中成绩一般或等同于高中毕业的学生，如果直接进入本科阶段的学习，往往压力会比较大，经过两年TAFE课程的过渡，学生的语言以及环境的适应都已突破。</p><p><strong>三．是否所有学生都适合读TAFE课程？</strong></p><p>TAFE 课程固然有其优势和特点，但是并非所有学生都适合：</p><p>1．没有&ldquo;移民&rdquo;计划的学生。TAFE课程的紧缺专业往往是针对澳大利亚本土的职业需求情况开设的，如果学生回国，在国内往往并不适合。</p><p>2．家庭经济条件以及学生学习基础都比较好的高中毕业生。这类学生有很强的学习能力，在经济允许的条件下还是建议选择本科课程的学习。如果想要移民，可以选择本科专业中，职业评估分数较高的专业，比如工程类，教师类，计算机类等。</p><p>3．在国内有很好的本科专业背景的学生。如果学生在国内本科本身就学习的澳大利亚移民紧缺职业的相关专业，可以继续就读本专业的研究生课程，比如会计专业，计算机专业，工程专业的学生。</p><p><strong>四．如何选择正确的TAFE 专业？</strong></p><p>TAFE 的专业大体分为如下几类，针对不同的人群，选择最适合自己的专业，才能更大程度的赢得就业的机会，以顺利完成&ldquo;移民&rdquo;计划。</p><p><strong>1．旅游酒店管理</strong></p><p>该专业包括西厨，西点师，面包师等专业，要求学生对烹饪或者西点等有一定的兴趣和天赋。或者本身对旅游酒店管理专业有兴趣，将来想要继续旅游酒店本科专业学习的学生。该类专业由于开设时间久，选择的学生多，因此毕业后的就业竞争依然很激烈，这就要求选择该类专业的学生，注重自己英文能力的提高，以及专业技能的锻炼。</p><p><strong>2．工程类/汽修类专业</strong></p><p>该类课程由于职业特点，更适合男生学习，因此也规避了一半女同学的竞争压力。如果本身也对工程类的专业有兴趣的学生，不失为一种很好的选择。</p><p><strong>3．建筑技能类</strong></p><p>该类专业包括砌砖，吊顶，橱柜制作，铺设地砖等专业，主要是对于学习者的体能以及动手能力有一定的要求，毕业后薪水相对更高些。因此对于身体条件很好，语言能力相对较弱，且毕业后希望尽快有个比较好收入的成年人比较适合。</p><p><strong>4．园艺类</strong></p><p>对园林设计，花圃培养，植物栽培等有兴趣的学生，或者将来想继续景观设计，城市园林规划等方向学习的学生，可以考虑本专业。</p><p><strong>5．牙模技师</strong></p><p>该专业一般开设位置较少，有兴趣的学生往往需要提早一年申请。需要学生认真仔细，性格能够安静下来，心灵手巧。</p><p><strong>6．社区福利</strong></p><p>该专业要求学生有一定的成熟度和社会阅历，以及很好的表达能力和逻辑思维能力。有爱心，性格开朗，喜欢与他人沟通。当然对于英文的要求也相对较高。</p><p><strong>7．平面印刷前技术</strong></p><p>该课程要求学生有一定的绘画基础或者一定的创造性。对于将来想要从事平面设计或者动漫设计的学生是很好的选择。可以继续接读多媒体设计，动漫设计等专业。</p><p>纵观03年至今的移民政策变化，不难看出澳大利亚政府也是希望能够将真正可以支持澳大利亚本土建设，弥补紧缺职业就业需求的人才留下。因此，注重所学TAFE专业技能的学习，以及英文能力的训练，是唯一应对变化的最有效方法。</p>'),
    (33,33,'<p>为什么出国留学？</p><p>你准备选择哪种类型的学校？</p><p>解答上述问题答案如出一辙，为开阔眼界，为寻找更宽广的机会，上名校以求将来更大的发展空间。</p><p>你知道几种出国学习方式？</p><p>英语过关就能独闯天下吗？</p><p>解答上述问题答案非常多，我从事留学生办理工作7年，经手的案例很多，成功的、失败的，都与境内办理之前的选择有很大关系，希望与大家探讨、学习，寻找最适合的课程，&lsquo;最适合的课程才是最好的课程&rsquo;</p><p>[境外大学预备课程]</p><p>澳大利亚目前有38所公立大学，设置大学预备课程的大学由原先的各别五星级大学，到现在的普遍的大学预备课程，很多学生在国内都想通过进入一所名校的大学预备课程的学习，从而进入这所大学本科阶段，但是如何从大学预备课程进入本科，中间经历哪些考试？录取机会有多大，如何选择专业？</p><p>一般情况，境外大学预备课程分成四种方向课程：文科、商科、工科、科学等，不同方向将来选择的大学本科课程不同，在大学预备课程的学习科目上也就存在不同点，举例，如果将来想学习会计本科，首先需要学习大学预备课程的商科方向，必修课有数学/商务/计算机基础等，如果想学习计算机、通讯等工科方面的课程，大学预备课程就要选择工科方向，物理/数学/是最基本的核心课程，学生能否顺利进入大学，关键看大学预备课程的专业课成绩，每年各大学本科各专业录取分数线都在调整，由于各个大学的各个专业录取标准不同，学生进入的机会不同，即使上本校的大学预备课程，也会有成绩达不到被动降低要求进入低层次大学学习，或者选择本校分数不高的次级专业，再或者类似我国的复读生重新学习各别成绩不理想科目，以求下个学期进入名校学习。</p><p>[境外大学Diploma+本科课程]</p><p>这种方式有些类似国内的《专生本》课程，学生可以选择一所不错的大学就读这样的课程，由于门槛非常低，学制时间短，担保金少等优势，很受国内学生的欢迎，被翻译成多种名称&lsquo;快捷课程&rsquo;&lsquo;学院本科&rsquo;等，由于澳大利亚的教育体制和我国不同，商科、文科课程的学制时间通常是三年制，各专业的基础课程都被放在大学预备课程中或高中12年级课程中学习，所以澳大利亚的大学一年级的课程是直接上专业课，有别于我国的大学一年级上基础课程，所以，直接上Diploma相当于让国内高中学生直接上我国的大学二年级，对于有些高中生来说，难度比较大。</p><p>由于不是正规本科阶段学生，需要经过毕业考试才能进入大学本科阶段学习，学习成绩决定于专业选择，通常选择的专业面比较窄，能否一次过关进入大学也是关键，很多大学的科目在假期没有补考机会，海外学生要想节省时间，必须咬紧牙关不能有失误，宽松的入学门槛，学生生源条件低造成升学率不高。</p><p>[境外的大学本科课程]</p><p>由于中国与澳大利亚教育体制不同，学生进入大学之前通常需要学习大学专业课的基础课程，大学预备课程是最好的衔接环节，部分澳大利亚大学本科接受我国高中毕业生直接入读，但是由于星级排名低/知名度不高，目前不被学生和家长认可，各别可以破格录取的名牌大学对学生的要求又非常高，一般达到国内高考一本分数线的学生才有机会，目前到境外直接上本科课程学生数量非常少。</p><p>[境内合作办学项目]</p><p>国内有很多1+2，1+3等项目课程，有民间项目(国内企业或大学直接与境外合作)，也有政府行为的课程(澳大利亚昆省大学预备课程)，项目战、大学认可战、价格战此起彼伏，真正能站住脚的还应该是教育品质，签证有保障等因素。</p><p>澳大利亚昆省大学预备课程目前正在招收第十四届学生，由于是澳洲教育部办学，针对大学范围广，师资力量强，办学严谨，再加上北京澳际出国留学签证成功率高等因素，是国内招生最有实力，办学历史最长，人数最多的项目，培养学生的主要方向不单纯英语学习，还涉及学生的学习方式改变，象西方孩子那样的独立个性，良好的沟通能力，管理能力，团队能力等，由于在国内上学一段时间再出国，起到桥梁/拐杖作用。</p><p>留学方式点评</p><p>以上针对高中学生的四种选择，前3种需要提前准备IELTS考试，至少5分才有资格办理澳大利亚签证，我国高中生的英文程度基本上是4分左右，要想达到使馆的要求，需要全脱产学习专门的IELTS课程半年左右时间，但是要达到境外入学IELTS6分或6.5分成绩，需要长达一年时间，再加上办理签证、申请院校时间，需要更长的持久战时间，学生即使英语达到标准，由于中西方教育背景差距，沟通式差距，学习习惯差距，造成很多拥有很高的英语成绩学生到达境外无从下手，需要更长时间适应境外课程，宽进严出的入学方式，以及学生自身不切实际的追名牌、追名校的做法，使很多家庭白白交纳学习费用。</p><p>进入名校大学预科课程学习还需要考虑学生在中国学习期间的程度、能力、自觉性，不是花大价钱就能顺利上名校，名校的竞争更激烈，淘汰率更残酷，这种方式比较适合国内学习能力很强，善于沟通，有见解的金字塔尖的学生。</p><p>而直接节省时间的快捷Diploma课程，使很多基础不扎实的高中学生没有享受到快捷优势，而是花费更长时间想办法进入本科，这种方式适合在国内已经上大专的学生，除英语程度比较弱，其他专业课有一定基础学生学习。</p><p>大部分中国高中学生优势在智商方面，而情商方面的薄弱是最大的问题，长久以来的中国教师为中心的应试教育模式，与境外以学生为中心的素质教育有很大差别，单从学生完成作业的形式上就不难看出，中国学生的作业形式以书面为主，有标准答案，海外学生作业以电子版形式为主，个人想法+小组讨论+网络电子图书官大量数据多方面内容组成，这只是中西方教育的多项区别中最小单元，很多学生在刚进入国外课程学习时普遍感觉无从入手。</p>'),
    (34,34,'<p>澳大利亚高等教育概况</p><p><strong>职业技术与继续教育学院（</strong><strong>TAFE</strong><strong>）</strong>&nbsp; 技术专科学校(TAFE)　TAFE的全称是Technical&nbsp;and&nbsp;Further&nbsp;Education，由各州和地区政府负责和管理，是澳大利亚引以为荣的独特教育系统，目前，TAFE每年培养出一百多万有技能的学生走上社会或进入大学。在澳大利亚拥有232所主要TAFE学院，TAFE课程得到各行业、雇主及大学的广泛认可。TAFE也正与其他国家的理工学院、教育部门、大学、雇佣机构及专业团体广泛接触，使修读澳大利亚TAFE课程的海外学生所取得的学历资格可以获得学生本国的承认。</p><p>&nbsp;</p><p><strong>大学</strong>&nbsp; 澳大利亚共有大学42所，其中36所是纳入国家统一教育体系的公办大学。四所是联邦政府办的特种高等专业学校。两所为私立大学。澳大利亚的大学提供的课程包括大学课程及研究生课程：大学课程包括文凭（文凭课程也可在TAFE学院修读）及学士学位课程，研究生课程包括研究生文凭及证书、讲授硕士课程、研究硕士课程及博士学位课程。</p><p>*专科课程(1-2年)&mdash;包括文凭及证书课程（Diploma,Certificate）</p><p>*大学课程(3年)&mdash;包括文凭(文凭课程也可在TAFE学院修读)及学士学位课程；</p><p>*研究生课程(1-2年)&mdash;包括研究生文凭及证书、讲授硕士课程、研究硕士课程及博士学位课程。</p><p>大学的学年：第一学期由二月中旬至六月下旬，第二学期由七月中旬至十一月底。十二月及一月为暑假。学期中还有假期。</p><p>&nbsp;</p><p>学生签证英语要求</p><p>直接读技术专科学校(TAFE)，雅思必须5.5分</p><p>如果雅思考5.0分，可以通过读语言学校（不超过20周）进入技术专科学校。</p><p>直接读本科或以上学位，雅思必须6.0分</p><p>直接读大学预科雅思必须5.5分</p><p>如果雅思考5.0分，可以通过读语言学校（不超过30周）进入大学预科。</p><p>&nbsp;</p><p>雅思考A类或G类可由学校决定。</p><p>&nbsp;</p><p>签证经济担保要求</p><p>&nbsp;</p><p>澳洲所需资金证明指以下几种：现金存款证明(也就是留学担保金)；留学贷款证明；收入来源证明。　　在准备现金存款证明时要注意：一定要在准备签证前将所需现金额在银行内存满6个月。如果中国留学生准备赴澳读研究类的硕士和博士，那么只要3个月存期覆盖第一年学习费用的存款证明就可以了。</p><p>澳洲移民部处所需要的现金存款证明数额，是根据你去澳洲读书的年份来计算的。如果你申请的赴澳留学时间是3年或3年以上的，只需要提供3年的学费和生活费作为留学担保金。最多算3年的学费和生活费的现金存款。如果不到3年时间的，那么均按照你学习的实际年份来提供学费和生活费的现金存款证明。一般来说，单身学生在澳洲的每年生活费是1.2万澳元，而学费则根据每个学校的具体情况来定夺。现金存款证明中还包括来回机票的费用，大约2000澳元。　　提供证明者，可以是本人，也可以是其配偶、父母、祖父母/外祖父母、兄弟姐妹、伯/叔、舅、姑/姨。但伯/叔、舅、姑/姨必需是常住澳大利亚的澳民、永久居民或新西兰公民。　　如果你申请留学贷款证明，那么要明确一点，移民部认可的中国可提供留学贷款的金融机构为：中国银行、工商银行、中国建设银行、农业银行、中信实业银行和上海浦东发展银行。对于留学贷款证明拿到的时间，没有明确限定。但贷款期有时间限定。如果你申请的赴澳留学3年或3年以上的，贷款期要满3年。不满3年的，按实际年份来计算。</p><p>收入来源证明方面，提供证明者，年收入要和所提供现金存款数额相符。</p><p>&nbsp;</p><p>&nbsp;</p><p>留学费用计算　</p><p>按一年（学费+杂费+生活费+来回机票）人民币兑澳币按5.0</p><p>&nbsp;</p><p>学校，专业不同，学费不一样</p><p>&nbsp;</p><p>学费&nbsp;17000：(17000+500+12000+2000) = 31500澳币 X 5.0 = 157500 （人民币）</p><p>学费&nbsp;20000：(20000+500+12000+2000) = 34500澳币 X 5.0 = 172500 （人民币）</p><p>学费&nbsp;25000：(25000+500+12000+2000) = 39500澳币 X 5.0 = 197500 （人民币）</p><p>&nbsp;</p><p>&nbsp;</p><p>留学方案　</p><ol><li><strong>一年预科升本科大一</strong></li></ol><p>　　中国学生想进入澳大利亚的名牌大学，一般要先读预科。预科的长度一般为一年，整个预科课程是围绕本科学习设计的，除了英语和信息技术之外，预科的专业课程品种也很丰富，提供了会计、经济学、生物技术、工程等课程，为学生进入本科学习打下基础。</p><p>高中毕业生要进入澳大利亚的名牌大学，以莫纳什大学为例，高中主课成绩需达到80分以上，IELTS5.5分，可以选择预科MUFY课程，课业完成达到要求后，学生就进入本科一年级学习。</p><ol start=\"2\"><li><strong>直接就读本科</strong></li></ol><p>　　最近，直接认可中国高考的澳洲高校开始增加，比如斯威本大学、墨尔本皇家理工大学、塔斯马尼亚大学、昆士兰科技大学和邦德大学等院校，都开出了本科直通车，国内高考达到本科线的考生，英语基础良好，就可以直接向这些学校的本科提出申请，被学校录取后就可以进入本科一年级学习，无需就读预科。</p><p>报考这些学校的本科，除了非常优良的高考成绩外，还需要良好的英语基础。IELTS要求6.0-6.5分，如果考生的IELTS成绩不能一步到位，也可以选择下半年读10周到20周的语言，然后次年春天进入本科一年级学习。</p><ol start=\"3\"><li><strong>快捷课程升本二</strong></li></ol><p>　　对于定位于选择商科和IT以及部分设计、文科专业的学生，快捷课程是一条省时省力的途径。快捷课程对IELTS的要求相对较低，5.5分就可以入读，学生完成8个月的课程以后，可以进入相应本科的二年级学习，整个本科课程是2年8个月。</p><p>比如莫那什大学是澳大利亚八大名校中唯一一所提供快捷课程的。它的快捷课程分两个部分，每个部分都是8个月。成绩一般的高中毕业生，要从第一部分读起，完成16个月的学习才能升入大二。而成绩优秀，高中的主课成绩达到80分以上，IELTS达6分的学生，则可以从第二部分读起，2年8个月完成本科课程。另外MIBT＋Deakin, &nbsp;RMIT College+RMIT University，LA trobe College+La Trobe University等都是这样的原理来设置课程。当然申请人必须在快捷课程达到60分才可以升本二。</p><ol start=\"4\"><li><strong>&nbsp;</strong><strong>副学位课程</strong></li></ol><p>&nbsp; &nbsp;&nbsp;Associate Degree是介于TAFE的DIPLOMA和本科类的课程，签证属于573本科课程签证，雅思需求6.0，但是入学成绩可以比本科低，tafe的入学成绩就可以了。比如RMIT大学的土木工程、计算机等副学位，学完2年可以直接豁免本科两年学分。　这样担保人只要提高2年担保金，而不是本科的3年，所以比较适合高考成绩不理想，资金有限，但是还是想上名校本科的申请人。</p><ol start=\"5\"><li><strong>TAFE</strong><strong>移民就业升本二</strong></li></ol><p>&nbsp;&nbsp; TAFE是澳大利亚的高等职业技术教育，培养了很多技术人才和高级蓝领。由于澳大利亚劳动力紧缺，英语良好，掌握一技之长的移民最受雇主欢迎。中国的高中毕业生或等同于高中毕业的三校生，IELTS达到5.5分，就可以向TAFE学校申请，如果选择的是移民专业，完成2年学业和900小时相关工作经验后，就可以申请绿卡。而且完成了2年TAFE可以免1-1.5年的本科，直升大二。部分TAFE专业甚至有实习工资，申请人只要有10多万人民币就可能出国！</p><p>&nbsp;</p><p>&nbsp;</p><p>墨尔本的大学</p><table border=\"1\"><tbody><tr><td><p>院校</p></td><td><p>排名</p></td><td><p>优势专业</p></td><td><p>入学要求</p></td></tr><tr><td><p>墨尔本大学</p><p>University&nbsp;of Melbourne</p><p>&nbsp;</p></td><td><p>五星</p></td><td><p>法律、商科、工科、工商管理、金融、艺术、理科、康复治疗、生物、药学、物理疗法</p></td><td><p>进本科的要求：高中毕业，拉筹伯，皇家理工，莫纳什大学预科的成绩达到85分以上，雅思6.5分，单科不低于6分</p></td></tr><tr><td><p>莫纳什大学</p><p>Monash&nbsp;University</p><p>&nbsp;</p></td><td><p>五星</p></td><td><p>商科、MBA、翻译、工程、信息技术、法律、医学、生物</p></td><td><p>进大学预科的要求：高中主课成绩需达到80分以上，雅思5.5分，单科不低于5分</p></td></tr><tr><td><p>皇家墨尔本理工大学(RMIT)</p></td><td><p>四星</p></td><td><p>设计、艺术、传媒、工程和计算机</p></td><td><p>进大学预科的要求：高二80分以上或高三70分以上,雅思5.5分，单科不低于5分</p></td></tr><tr><td><p>拉筹伯大学</p><p>La Trobe University</p><p>&nbsp;</p></td><td><p>四星</p></td><td><p>教育，护理，卫生</p></td><td><p>进大学预科的要求：高三70分以上</p><p>雅思5.5分，单科不低于5分</p><p>&nbsp;</p></td></tr><tr><td><p>迪肯大学</p><p>Deakin&nbsp;University</p><p>&nbsp;</p></td><td><p>四星</p></td><td><p>商科是这个学校的优势专业，特别是会计</p></td><td><p>进大学预科的要求：高三70分以上</p><p>雅思5.5分，单科不低于5分</p><p>&nbsp;</p></td></tr><tr><td><p>维多利亚大学</p><p>Victoria Unversity</p><p>&nbsp;</p></td><td><p>三星</p></td><td><p>会计和旅游酒店管理</p></td><td><p>进大学预科的要求：高中毕业，雅思5.5分，单科不低于5分</p></td></tr><tr><td><p>斯维本科技大学Swinburne University of Technoloy</p></td><td><p>三星</p></td><td><p>信息技术、电子金融、电子商务、工程学，化学</p></td><td><p>进大学预科的要求：高中毕业，雅思5.5分，单科不低于5分</p></td></tr></tbody></table>'),
    (35,35,'<p><strong>澳大利亚中小学教育概况</strong></p><p>澳大利亚的中小学是十二年制，一年级到六年级为小学，七年级到十二年级是中学。其中七年级到九年级为初中部（相当于中国的初一到初三），十年级到十二年级为高中部（相当于中国的高一到高三）。十二年级是特殊的一年，因为在这一年中，中学生们要做中学毕业的准备，并参加中学毕业考试。这个中学毕业考试的成绩是做为进入大学的唯一参考成绩。</p><p>澳大利亚的中小学可分为公立和私立两种教育体系。公立学校是国家政府资助的，私立学校则是私营的。还有一些教会学校都是私营的。总的来说，在教学内容上，公立和私立学校几乎没有什么不同。只不过因私立学校的资金来源广泛，财力雄厚而导致师资力量强、教学环境好、教学设施先进等等。在学费方面，私立学校较之公立学校贵些。例如，公立学校高中十至十二年级的学费一般为一万二千澳元，而相应的私立学校一般为二万至三万澳元不等。</p><p>澳大利亚中小学教育体制及内容与中国大有不同。在澳大利亚学习不是以死记硬背为主的填鸭式教学方法，而是侧重于实践知识的掌握和动手能力的培养。学生在澳大利亚读书的压力并不大，完全要靠自觉。澳大利亚中小学的教学设施较好，一般都有运动场、游泳池、图书馆和计算机房。许多学校要求学生穿统一的校服，有的还要求学生购买手提电脑。</p><p>在澳大利亚，中小学一学年分为四个学期。每学期不到三个月，而且每学期之间都有几个星期的假期。年底的假期最长，长达一个多月。</p><p>许多中国家长所担心的是孩子在澳的食宿及监护问题。这一点是很可以理解的，因为中学生毕竟年龄小，生活能力不强。但其实家长大可不必太担心，澳大利亚是一个很安全、社会治安很好的国家，同时它也很重视对学生的爱护。如果家中有亲戚在澳当然最好，如没有，我中心会帮助海外留学生安排寄宿家庭，可以是华人也可以是澳洲人，他们提供一日三餐及住宿，并做好与学校和家长的联系工作。如住在澳洲人家里，对学生的英文水平的提高将有很大的帮助。</p><p>&nbsp;</p><p><strong>到澳洲就读高中的签证要求（</strong><strong>571</strong><strong>签证）。</strong></p><ol><li>拥有初中毕业证</li></ol><p>&nbsp;</p><ol start=\"2\"><li>年龄符合要求：</li></ol><p>入读9年级年龄不超过17周岁。</p><p>入读10年级年龄不超过18周岁。</p><p>入读11年级年龄不超过19周岁。</p><p>&nbsp;</p><ol start=\"3\"><li>在澳洲就读高中的时间不得少于16个月，因此最晚要申请11年级第3学期。</li><li>澳洲高中不允许跳读。例如学生赴澳时初中毕业，是不能就读澳洲11年级的。</li><li>澳洲高中允许倒读，例如学生赴澳时正在国内刚读完高二，是可以到澳洲重新读高二的。但倒读的时间规定不得超过1年半（以入读主课的时间计算）</li><li>如果申请人年龄小于16周岁，不要求IELTS雅思成绩。学校根据你的英语成绩，要求你到就近的语言中心就读不超过30周的语言（一般为20周）。</li><li>如果申请人年龄满16周岁，需要有雅思成绩（或学校指定的考试，如AEAS）。高中要求5分，如果不足5分（至少4分），需要到申请的学校或就近的语言中心就读不超过30周的语言（一般为20周）。</li><li>学生未满18周岁，需要安排在澳期间18岁之前的监护人。学校可以安排监护人。如果在澳洲有监护人，要提交移民局审核自行安排的监护人是否满足监护条件。合格的监护人可以是在当地有永久居住权，有无犯罪证明的学生的兄弟姐妹，姥姥姥爷、叔舅姑姨，或继父继母。</li></ol><p>&nbsp;</p><p><strong>签证经济担保要求</strong></p><p><strong>&nbsp;</strong></p><p>澳洲所需资金证明指以下几种：现金存款证明(也就是留学担保金)；留学贷款证明；收入来源证明。　　在准备现金存款证明时要注意：一定要在准备签证前将所需现金额在银行内存满6个月。如果中国留学生准备赴澳读研究类的硕士和博士，那么只要3个月存期覆盖第一年学习费用的存款证明就可以了。</p><p>澳洲移民部处所需要的现金存款证明数额，是根据你去澳洲读书的年份来计算的。如果你申请的赴澳留学时间是3年或3年以上的，只需要提供3年的学费和生活费作为留学担保金。最多算3年的学费和生活费的现金存款。如果不到3年时间的，那么均按照你学习的实际年份来提供学费和生活费的现金存款证明。一般来说，单身学生在澳洲的每年生活费是1.2万澳元，而学费则根据每个学校的具体情况来定夺。现金存款证明中还包括来回机票的费用，大约2000澳元。　　提供证明者，可以是本人，也可以是其配偶、父母、祖父母/外祖父母、兄弟姐妹、伯/叔、舅、姑/姨。但伯/叔、舅、姑/姨必需是常住澳大利亚的澳民、永久居民或新西兰公民。　　如果你申请留学贷款证明，那么要明确一点，移民部认可的中国可提供留学贷款的金融机构为：中国银行、工商银行、中国建设银行、农业银行、中信实业银行和上海浦东发展银行。对于留学贷款证明拿到的时间，没有明确限定。但贷款期有时间限定。如果你申请的赴澳留学3年或3年以上的，贷款期要满3年。不满3年的，按实际年份来计算。</p><p>收入来源证明方面，提供证明者，年收入要和所提供现金存款数额相符。</p><p>&nbsp;</p><p><strong>留学费用计算　</strong></p><p>按一年（学费+杂费+生活费+来回机票）人民币兑澳币按5.0</p><p>公校&nbsp;(12500+500+12000+2000) = 27000澳币 X 5.0 = 135000 （人民币）</p><p>私校&nbsp;(25000+1000+12000+2000) = 400000澳币 X 5.0 = 200000 （人民币）</p><p>&nbsp;</p><p><strong>留学方案　　</strong></p><p>学生通常就读20周左右英语课程，再按照1、4、7、11月入学口进入高中</p><p>高一学生和初三学生是办理赴澳留学最佳阶段，也是可以挑选公立和私立各个阶段插读的最好机会。</p><p>初中三年级选择读10年级</p><p>高中一年级选择读10或11年级</p><p>高中二年级选择读11年级</p><p>如果你已经高中二年级毕业或高三年级在读了，那么也没有什么损失！现在你选择进入大学预科课程将是最省时间、最省金钱的时机了：</p><p>如果中国高中二年级学历以上的学生，能够出示高中四学期成绩那么就可以申请澳大利亚大学的预科课程了！由于大学预科是大学的基础课程，澳大利亚多数本科学士课程为三年学制，因此学生在入读本科学士前的预科课程就是非常必要的衔接国内中学和澳大利亚大学的环节了！学生在申请预科课程时需要确定选择课程专业方向，一般分成文科、商科、工科、科学等专业，由于学生在国内申请澳大利亚的大学预科时可以获得&lsquo;大学预科和本科&rsquo;两份录取通知书，很多大学预科为了保障学生生源质量，对学生中国境内的学习成绩有严格的要求，现在申请竞争比较激烈的是排名靠前的大学预科，例如澳洲国立大学、墨尔本大学、新南威尔士大学等预科课程。</p><p>&nbsp;</p><p><strong>推荐学校</strong></p><table><tbody><tr><td><p>Scotch&nbsp;College</p><p>苏格兰学院</p></td><td><p>私立男子住宿学校</p></td><td><p>是G20 Schools，全球顶尖的20所中学</p><p>&nbsp;&nbsp;</p></td></tr><tr><td colspan=\"3\"><p>9-12年级学费+住宿费一年50,127澳币</p><p>9-12年级学费一年30,396澳币(不住宿)</p><p>海外医疗保险一年（OSHC）354澳币</p><p>学生可参加VCE（维省高考）或IB（国际高考）&nbsp;&nbsp;</p></td></tr><tr><td><p>Methodist Ladies&rsquo; College（MLC）</p><p>&nbsp;</p></td><td><p>私立女校住宿学校</p></td><td><p>顶尖私立中学</p></td></tr><tr><td colspan=\"3\"><p>11-12年级学费+住宿费一年47,500澳币</p><p>11-12年级学费一年30,000澳币</p><p>管理费一年1225澳币</p><p>海外医疗保险一年（OSHC）354澳币</p><p>学生可参加VCE（维省高考）或IB（国际高考）&nbsp;</p><p>&nbsp;</p></td></tr><tr><td><p>Carey&nbsp;Baptist Grammer School</p><p>&nbsp;</p></td><td><p>私立男女混校</p></td><td><p>顶尖私立中学&nbsp;</p></td></tr><tr><td colspan=\"3\"><p>11-12年级学费一年24,000澳币</p><p>管理费一年500澳币</p><p>海外医疗保险一年（OSHC）354澳币</p><p>学生可参加VCE（维省高考）或IB（国际高考）&nbsp;</p><p>&nbsp;</p></td></tr></tbody></table><p>&nbsp;</p><table><tbody><tr><td><p>Government&nbsp;Schools</p><p>&nbsp;</p></td><td><p>政府公立中学</p></td></tr><tr><td colspan=\"2\"><p>　　维多利亚省：有200多所公立中学，主要集中在墨尔本市。入学申请统一由省教育部审理并批准，通常监护人、接机住宿都由省教育部直接安排。申请费为200澳元，中学主课前的英语课程视就读中学是否具备语言中心来决定安排在校内或校外。维多利亚省公立中学的教育很成功，能让您的子女踏入世界各地和高等学府的大门。从维省公立中学毕业的学生将被授予国际承认的维省教育证书(VCE)。</p><p>11-12年级学费一年12,500澳币</p><p>海外医疗保险一年（OSHC）354澳币</p><p>申请费206澳币</p><p>住宿安排费226.6澳币</p><p>学生可参加VCE（维省高考）</p></td></tr></tbody></table><p>&nbsp;</p>'),
    (36,36,'<p>看到很多人在这里谈论澳洲大学的排名，哪个学校的会计好，本人觉得没有什么实际价值。故发表一些浅显的看法。</p><p>澳洲只有41所大学，大学与大学之间的差距并不像国内重点大学和民办本科之间的差距那么大。澳洲本地人，从大学里的教授到企业老板、职员，他们对澳洲的大学排名毫无概念。例如在堪培拉，大家并不觉得国立大学就一定比堪培拉大学要好很多。另外，澳洲的相关机构也从来都没有对这些大学做过一个完整的排名，只有每年的Good Universities Guide对每所大学的各个方面进行分析，结果是每所大学都有其利弊。当然，各个大学在学科与学科之间当然还是存在一些差距的，比如会计就是Macquire（麦考瑞）大学的专长。但是，这些差距并不一定会对我们这些非研究人士造成很大的影响。有些人还提及到移民与就业的影响更是无稽之谈。对于第一次出国的人来讲，大多数英文是很差的，在这边的环境里学习基础的东西成绩都很一般，更不要说去体会大学与大学之间的教学、课程水准差距了，我们根本没有给这些大学排名的资格。我浏览了一下澳洲各个大学的网站，发现每个大学的Business school教accounting课程的都至少有2名Professor，其他的任职人员也大多数都是PhD或是已经在业界工作很多年，积累了丰富的实际操作经验，回到学校搞专业研究的。例如SwinburneUni（斯文本大学）的会计不是强项，没有MelbourneUni（墨尔本大学）那么有名气，但是SwinburneUni里的lecturer的专业知识与经验是我们这些人用3-5年的时间都不见得能达到的。你在SwinburneUni毕业的水平和在MelbourneUni毕业的水平是没有什么差距的。唯一的差别可能就是在SwinburneUni你要花每年16000-18000的学费，而在MelbourneUni则要花每年22000的学费。</p><p>另外，如果你真的是很强的话，成绩优秀的SwinburneUni毕业成绩但同样可以申请到其他著名大学的PhD奖学金。SwinburneUni出来的PhD也同样有机会在其他大学任教。</p><p>除此之外，上海交大和泰晤士教育增刊对世界大学作的排名也只能是一个参考，这些排名所参照的指标绝大多数是依照科研成果为主的，对于学生而言实际的导向性并不高。这些排名都是建立在学术成就上的，只对于少数的想做学术研究的留学生有指导意义。</p><p>还有一种说法就是在课程设置上有略微的不同。例如Macquire的accounting是与CPA相联系的，只有完成CPA课程才能有资格拿到accounting的master，否则即便完成了Macquire的master课程也不能毕业。本人认为这一点对于没有PR的国际学生没有什么实际优势。在Macquire经过两年学习的毕业生，既拿到了master学位有完成了CPA课程，看起来好像是较其他大学具有优势，但实际上完成CPA课程并没有什么实际优势，因为完成了CPA课程并不意味着就是CPA会员，要想成为会员，必须要有3年的相关工作经验（详情见CPA网站 http://www.cpaaustralia.com.au/cps/rde/xchg/SID-3F57FEDE-137FE9F3/cpa/hs.xsl/802_ENA_HTML.htm ）。从这一点来看，在就业市场上，Macquire的毕业生相对于其他大学的毕业生而言是没有优势的。很多在澳洲读完本科的学生拿到PR后就开始工作，他们都尽量在accounting firm或者是大企业，这样可以达到CPA对于工作经验的要求。他们在工作的同时开始考CPA课程，一般在3-5年之内完成，这样，他们就能在3-5年之内成为CPA会员，这才是真正的优势。而且CPA课程的设置并不是简单的为了让学员学习并通过考试，而是要求学员在结合自己实际工作经验的同时对于会计有更深层次的理解，更好的应用，能够更专业的工作。从理论上讲，本科毕业生在工作的同时考取CPA课程所得到的实际价值要比没有任何工作经验一边学Master一边考CPA的得到的价值要高。</p><p>另外，很多本科毕业生在考取CPA课程的时候是不由自己花钱的，往往都是所在的公司承担这部分费用。</p><p>实际上，各个大学的accounting课程都没有太大的区别，说白了都是CPA和CA所要求的成为associate member所必须完成的12门课。其他的课程有的是选修课，有的是各个大学自己加进去的一些科目。这些在就业的时候并没不能体现出显著的区别。</p><p>说多了，再回到大学排名的话题上。大学与大学之间是有差距的，但问题是我们应该重视哪些方面，忽略哪些方面。如果想移民的话，是不一定要在名气大的学校就读的，因为澳洲的雇主主要看的是成绩单，悉尼大学的pass和Flinders大学的pass是没有区别的，而无论哪个大学的High Distinction都是让人故目相看的。所以在澳洲就业主要的是成绩，而不是学校的名气，因为学校的名气是学校的，不是你个人的。当然了，对于不想在澳洲发展的人来讲，最好是去一个有名气的大学，回国好混一些。</p><p>另外，出国学习主要是为了体验异国风情，融入当地环境，即便是打算回国的也想有一口流利的英文。但是，在悉尼、墨尔本各个著名大学充斥着亚洲学生的今天，很难看出挤着去那些大城市的著名大学是最佳的选择。就以悉尼大学和新南威尔士大学为例，学accounting和IT的超过70%（保守估计）都是亚洲人，在这样的环境中如何能与本地人进行良好的交流呢。而且在一些著名大学随着入学人数的逐年增加，lecture的学生数目不断膨胀，很难令人相信这些大学能够保证他们的教学质量。</p><p>最后再说一下我的所见所闻。第一，堪培拉大学的毕业生的就业率要比同在堪培拉的澳洲国立大学的就业率高。第二，我身边的很多人毕业后留在了堪培拉，都找到了与会计相关的工作；相反，在悉尼的很多毕业生为了拿工作经验，不得不倒贴给accounting firm 2000澳币去做volunteer。第三，一位在SwinburneUni读完MBA之后又拿到PhD的中国人，现在在ANU做lecture。第四，一位中国女孩读完Bachelor of Commerce in accounting (honours)的本科生现在正在ANU读PhD。第五，一位堪培拉大学的说学士学位毕业生在悉尼的BlueScope Steel的Finance department找到工作，现已被公司派回中国。第六，在Dr Birrell等人提交给移民局的report上建议要更改移民政策，使得没有相关工作经验、英文又不能达到要求的留学生不能马上拿到PR，其原因并不是因为澳洲不缺少accountant了，而是很多新移民的专业和英文水平不能达到雇主的要求</p>'),
    (37,37,'<p>&ldquo;传媒&rdquo;这个词应该来自于英文的medium，汉语词典里的解释很简单，意思就是传播媒介（指广播、电视、报刊，网络等）。近几年，随着留学业的不断发展，越来越多的人开始有机会接触到传媒这门学科，那么关于传媒学我们到底可以从中学习到什么，将来又可以从事什么样的工作呢？</p><p>学习传媒的学生大致可以从大众传媒、新闻、营销广告、媒体发布和创作表演五个方向选择你的课程。当然，你可以选一个方向主攻，也可以选两三个甚至五个方向同时学习，所谓术业有专攻，个人建议不要同时选修太多方向，但是如果你打算在大学阶段把传媒的每个方向都做个初步了解，然后还要进入研究生课程继续学习传媒的某一个方向，那也是可以全方向选课的。</p><p>澳洲多数大学都有传媒课程，但是个人认为相对较好并且有突出特点的大学只有五所，他们分别是墨尔本大学，悉尼大学，莫纳什大学，麦考瑞大学和皇家墨尔本理工大学。</p><p>墨尔本大学：</p><p>侧重于新闻、出版和一些相关的纸质传媒，学习内容学术性很强，包括传统新闻、网络新闻、新闻摄影、新闻写作等，学生将来可以进入报社或杂志社，也可从事广播、电视媒体的新闻，还可进入出版等领域。</p><p>悉尼大学：</p><p>传媒课程相对没有太明显的侧重点，新闻、网络、电视、广播、电子、数字、广告等都不错，其中传媒硕士要学的数字传媒，课程实践性很强，很有利于将来就业。无传媒相关背景也可申请。</p><p>莫纳什：</p><p>传媒专业是该所大学的强项专业之一，课程设置以专业为取向，用国际性的使用技巧来培养大众传媒，公共关系和企业通讯方面的专业人才。学生毕业后可做专业的公关人员，可以在企业、政府、社区、酒店、福利机构，或者文化交流等行业任职。</p><p>麦考瑞大学：</p><p>最近几年的优秀传媒工作者都是麦考瑞的学生，课程设置稍偏写作和编辑方向，有国际沟通学和新闻写作的双学位。学生将来可从事的工作包括编辑、公关等。</p><p>皇家墨尔本理工大学：</p><p>专业领域很广泛，实践性强，学生将来可从事的职业包括新闻、摄影、编辑、音效处理、互动游戏设计、网络设计、广告设计、品牌经理等。</p><p>澳洲的传媒课程，有极强的亚洲和西方文化交流的特性，因此澳洲知名大学毕业的高级专业人才被世界各国所青睐。近十几年，随着中国与外界交流的日益频繁，国内的新闻、影视、媒体与广告传播等行业也在迅猛发展，仅新闻媒体对新闻专业人才的需求已经远大于新闻专业人才的输出。因此，我深信传媒行业的各种高级人才在中国都将变的越来越抢手。</p>'),
    (38,38,'<p>近日了解到很多学生和家长垂询赴澳留学事宜时，经常问到澳洲某大学在国内的名次，旨在了解学校水平的高下。但澳大利亚教育当局从未给自己的大学排过名，因为这是一桩十分困难的事，不仅涉及到相当复杂的数据统计和准确的评估，而且评估往往会搀杂种种说不清道不明的主观因素，容易失之偏颇。</p><p>目前澳大利亚共有大学（University）40所，公立的38所，私立的2所。这些大学的社会地位在全国可以说是&ldquo;平起平坐&rdquo;。不像我国把大学分为全国重点（或中央级）、省重点（或省级）和地区级三个档次。事实上，所谓名牌大学也并非所有专业都是强项，非名牌大学也都有可以炫耀于世的品牌专业。澳大利亚人象其他西方人一样讲究实惠，上大学首先考虑专业，哪个大学的专业易于就业和收入水平高，就学哪个专业。一般来说，人们并不以出身&ldquo;门楣&rdquo;（学校）取人。事实上，40所大学不论建校时间长短和规模大小，都是&ldquo;尺有所短，寸有所长&rdquo;。所以他们对于学校的排名不是十分注重。</p><p>另外，澳洲高等教育不同于其他西方国家，联邦教育部对于高等院校（包括海外联合办学）的教学与科研质量的管理有十分明确和严格的标准。不管公立和私立的大学，一律按&ldquo;澳大利亚质量框架&rdquo;进行衡量和管理，且每三年对大学进行一次质量督察和评估，不符合质量标准的院校要受到制裁。因此，不管哪类学校的哪种专业，其教学科研质量都是有保障的。为了方便广大学生和家长了解澳洲院校情况，以下为澳际教育集团长春分公司翟立岩老师提供的部分澳洲名校的英文缩写及网址，相信在这里定会找到您喜欢的大学和专业。</p><p>　　澳大利亚国立大学 Australian National University(ANU)</p><p>　　网址：http://www.anu.edu.au</p><p>　　悉尼大学 University of Sydney(USYD)</p><p>　　网址：http://www.usyd.edu.au</p><p>　　新南威尔士大学 University of New South Wales(UNSW)</p><p>　　网址：http://www.unsw.edu.au</p><p>　　麦考瑞大学 Macquarie University(MQ)</p><p>　　网址：http://www.mq.edu.au</p><p>　　悉尼科技大学 University of Technology, Sydney(UTS)</p><p>　　网址：http://www.uts.edu.au</p><p>　　西悉尼大学 University of Western Sydney(UWS)</p><p>　　网址：http://www.uws.edu.au</p><p>　　卧龙岗大学 University of Wollongong(UOW)</p><p>　　网址：http://www.uow.edu.au</p><p>　　昆士兰大学 University of Queensland(UQ)</p><p>　　网址：http://www.uq.edu.au</p><p>　　昆士兰理工大学 Queensland University of Technology(QUT)</p><p>　　网址：http://www.qut.edu.au</p><p>　　阿德雷德大学 University of Adelaide(ADELAIDE)</p><p>　　网址：http://www.adelaide.edu.au</p><p>　　墨尔本大学 University of Melbourne(UM)</p><p>　　网址：http://www.unimelb.edu.au</p><p>　　迪肯大学 Deakin University(DEAKIN)</p><p>　　网址：http://www.deakin.edu.au</p><p>　　拉筹伯大学 La Trobe University(LATROBE)</p><p>　　网址：http://www.latrobe.edu.au</p><p>　　莫纳士大学 Monash University(MONASH)</p><p>　　网址：http://www.monash.edu.au</p><p>　　皇家墨尔本理工学院 RMIT University(RMIT)</p><p>　　网址：http://www.rmit.edu.au</p><p>　　西澳大学 University of Western Australia(UWA)</p><p>　　网址：http://www.uwa.edu.au</p>'),
    (39,39,'<p>一提起澳大利亚的高等院校，通常人们都会想到&ldquo;八大&rdquo;。&ldquo;八大&rdquo;是澳大利亚最顶尖的八所大学组成的大学集团的简称，在澳大利亚的大学中享有崇高的地位。&ldquo;八大&rdquo;的成员包括：阿德雷德大学、澳大利亚国立大学、墨尔本大学、蒙纳士大学、新南威尔士大学、昆士兰大学、悉尼大学、西澳大利亚大学。</p><p>&nbsp;</p><p>其实，澳大利亚的大学除了&ldquo;八大&rdquo;以外，还有其他一些大学联盟也各有特色。</p><p>澳大利亚的大学除了&ldquo;八大&rdquo;，还有很多选择。</p><p>■澳大利亚技术网络协会：以实用著称的大学</p><p>澳大利亚技术网络协会（Australia Technology Network，简称ATN）由五所大学组成，分别是科廷科技大学（Curtin）、南澳大学（UniSA）、皇家墨尔本理工大学（RMIT）、悉尼科技大学（UTS）和昆士兰科技大学（QUT）。这五所大学都以实用著称。</p><p>■澳大利亚创新研究型大学组织：都有特长学科</p><p>澳大利亚创新研究型大学组织（Innovative Research Universities Australia，简称IRU）由六所大学组成，分别是：弗林德斯大学（FLINDERS）、格里菲斯大学（GRIFFITH）、拉筹伯大学（LA TROBE）、麦考瑞大学（MQ）、莫道克大学（MURDOCH）、纽卡索大学（NEW CASTLE）。每所大学都有其特别出色的领域。</p><p>■新生代大学组织：教学方式新颖灵活</p><p>新生代大学组织（New Generations Universities，简称NGU）的成员大学都是1970年后建立的大学，包括艾迪斯科文大学（Edith Cowan）、南十字星大学（Southern Cross）、西悉尼大学（West Sydney）、巴拉瑞特大学（Ballarat）等十所大学。这些大学因为新颖灵活的教学方式和项目，得到澳大利亚政府、商界和社区的大力支持。</p>'),
    (40,40,'<p>拉筹伯大学 La Trobe University　<br />注册号：CRICOS provider number: 00115M<br />大学网址：http://www.latrobe.edu.au/<br />概 况<br />拉筹伯大学建校于1964年，是澳大利亚最大的、发展最快的、由政府出资兴办的一流大学之一。目前，拉筹伯大学拥有超过26,000在校学生，其中包括来自60多个国家的3,000名国际学生。拉筹伯大学因其在教学和研究领域的卓越成就而享誉全球，被英国泰晤士报评为全世界最佳150所大学之一，同时被墨尔本应用经济和社会研究院评为澳大利亚最佳10的大学之一。拉筹伯大学还与全世界260多所大学建立了科研和交流的纽带并开展了广泛的合作研究。<br />拉筹伯大学在研究方面被公认为澳大利亚最活跃，最有成效的大学之一。现在它已跻身获得政府研究经费拨款的前十所研究院：通过与亚洲、欧洲及美洲近100所大学的交流与合作协议，各院系广泛，多样的研究项目得以强化。许多项目涉及到了员工的交流与合作研究活动。<br />拉筹伯大学提供一系列广泛的本科生及研究生课程，涵盖如下领域：会计、农业、艺术与社会科学、银行与金融、商业与贸易、计算机科学、经济学、教育、电子学、工程、信息系统、语言、法律、工商管理、护理与保健科学、职业疗法、物理治疗、心理学、科学与技术、旅游和酒店管理。<br />　　在二十四所专业中心与研究院的支持下，研究项目得以强化。位于班杜拉校园的一所研究发展园与拉筹伯科技区，确保了学校与企业，工业间的合作，学校也为很多机构提供咨询服务。<br />大学在维多利亚有七个校园：<br />墨尔本Bundooras校区距墨尔本市30-40分钟车程<br />Bedigo校区位于距墨尔本90分钟车程的Bendigo市，人口92000。<br />Albury-Wodonga校区位于距墨尔本120分钟车程的Albury-Wodonga市，人口105，000。<br />Midura校区位于维多利亚省西北部的Midura市<br />Shepparton校区位于距墨尔本60分钟车程的Goulburn Valley。<br />中央墨尔本市校区主要教授研究生课程<br />Beechworth校区位于历史上著名的Beechworth市<br />地理位置及交通<br />学校位于维多利亚州，那里有着壮观的海岸线，迷人的海滩，配有一流设施的雪原。自然景观从肥沃的农田到多石、干旱的半沙漠地区，多种多样。墨尔本是维多利亚的首府也是澳大利亚第二大城市，是世界公认的最适于居住的城市之一，人口3500，000，来自于153个国家及地区，形成了它独有的多元文化特色。墨尔本市交通便利，学生可非常方便的乘坐有轨电车、公共汽车、城市铁路。从城中心校区到墨尔本其它校区只到30-40的车程。<br />中国学生最热门专业选择：<br />Bachelor of business<br />Master of educational leadership and management<br />Master of IT<br />Master of law<br />Master of linguistics<br />Master of telecommunication and network engineering<br />Master of science and technology<br />Master of accounting and finance<br />Master of accounting<br />入学要求：<br />本科：IELTS 6.0，单项不低于6.0<br />硕士：IELTS 6.5，单项不低于6.0<br />学 费：每年13,000 &ndash; 22,000澳元不等<br />　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　<br />奖学金<br />欢迎到La Trobe 大学奖学金信息站点。大学为开始申请的和继续就读的学生提供横跨所有研究的领域大范围奖学金, 包括联邦学习的奖学金(CLS) 并且La Trobe 产权和学术优秀奖学金。 一些奖学金从是提供给就读所有课程领域的那此在经济和教育上有困难的本地优秀学生。一些获学金还特别为在某特别的校园或学院就读的本科及研究生准备，学校还发放奖学金在学生的校园住宿费用上。<br />开学日期<br />每年２月、七月，部分课程每年１月、４月、１０月开学</p>'),
    (41,41,'<p>申请海外名牌大学是每个出国留学学生的梦想，由于对境外大学的不了解，学生往往只能选择耳熟能详的各别大学造成学生申请集中。所以大学才不断抬高门槛，来限制越来越多的入学申请，使很多学生失去进入名校学习的机会。如何抓住机遇申请澳大利亚名校有一些窍门，下边给大家介绍一些方法</p><p>寻找综合类名校的非热门专业</p><p>国内的申请人在申请学校时集中申请某一大学的一两个专业，甚至澳洲本土大学都莫名其妙，但是中国学生还是很坚持。例如申请商科会集中某几个大学，申请工科会集中另外几个大学。大家忽略了一点，这些名牌大学建校时间上百年世界排名靠前，评分规则不是某个单一专业强，而是综合能力强。各专业百花齐放，而不是某个领域一枝独秀，各个专业完善程度、世界认可程度、师资力量等都非常强。即使不是热门专业，也完全能够满足学生学习需求，用人单位看中的是求职者的综合能力，而不会区分是大学的某个专业。例如悉尼大学的工程专业目前世界领先，而不是仅仅商科、文科优秀。</p><p>寻找进入热门大学热门专业另一种途径</p><p>每年澳大利亚移民局都会公布紧缺职业，职业打分高的专业申请人数集中，入学标准很高，学费也一路飙升。例如麦考瑞大学的会计，可是与会计专业在课程选择很多相近的课程如经济学专业却一直无人问津。两个专业的入学分数要求相差很大，会计专业需要GPA2.7以上（相当于75分以上），而经济学只有GPA2.5（相当于70分以上）。学生如果选择经济学专业，学习四门与会计相同的基础课程，在第二个学期可以转入会计专业。像这样相近专业互转学分的情况还有很多，另外学生也可以选择一般院校的会计专业，学习一年后带着学分转入名校。由于澳大利亚的整体教育水平高，各大学的差距并不像国内学生想象的差距那样大。</p><p>寻找非热门城市中热门大学、专业</p><p>从1999年开始大批量中国留学生赴澳大利亚留学。至今历史并不长，中国学生愿意选择热闹城市，例如悉尼市、墨尔本市，占整个留学生比例的70%。这些城市的名牌大学的入学分数随着申请者数量的增加而不断增高，甚至有针对中国学生的入学标准。各别大学不仅要求中国的申请人在国内所在大学是排名靠前的大学分数更是从75分、80分到90分不等。同样是名牌大学但由于地理位置不佳，很少有人问津。其实这些学校所在的城市无论在气候，就业率、移民打分都大大优于悉尼，例如布里斯本市的昆士兰大学、阿德雷德市的阿德雷德大学、佩思市的西澳大利亚大学等。澳大利亚政府为调整各州人种比例，还会调整城市移民额外加分，就是鼓励海外学生、技术人员均衡发展。</p>'),
    (42,42,'<p>与其它国家不同，澳大利亚国内没有专业的大学排名，所以我们在这里的澳洲大学排名是指澳洲的大学在世界上的排名。目前，世界上认可度最高的大学排名有三个，分别是英国的TIMES世界大学排名、上海交大版世界大学学术500强排名，以及美国新闻周刊的世界大学100强排名。在此把这三大排名中的澳洲大学单列出来希望对大家留学澳洲的选校有所帮助。</p><p>&nbsp;</p><p>2009年 Times 世界大学500强排名中的澳洲大学</p><p>&nbsp;</p><p>此排名主要从学术同行评价、顾主评价、论文被引用次数、国际学生比例等几个方面对世界大学进行打分和评估。Times的排名基本体现了大学的综合实力，它不仅看重大学的研究水平，更重看大学的教学质量和顾主对毕业生的评价。建议申请本科和授课式硕士(by course)的学生重点参考。</p><p>16　澳洲国立大学</p><p>37　悉尼大学</p><p>38　墨尔本大学</p><p>43　昆士兰大学</p><p>45　新南威尔士大学</p><p>47　莫纳什大学</p><p>83　西澳大学</p><p>106　阿德雷德大学</p><p>182　麦考瑞大学</p><p>206　皇家墨尔本理工大学</p><p>207　卧龙岗大学</p><p>212　昆士兰科技大学</p><p>232　科廷科技大学</p><p>242　拉筹伯大学</p><p>273　弗林德斯大学</p><p>291　塔斯马尼亚大学</p><p>303　南澳大学</p><p>325　格里菲斯大学</p><p>396　迪肯大学</p><p>&nbsp;</p><p>2009 上海交通大学世界大学学术500强排名中的澳洲大学</p><p>&nbsp;</p><p>此排名的依据主要是大学毕业校友的成就、获得诺贝尔的次数、论文在核心期刊发表的次数、被引用的次数以及高被引论文数等。总之，上海交大的排名最看重大学的研究实力，建议想申请research(研究型硕士)的学生可以重点参考。</p><p>59　澳洲国立大学</p><p>73　墨尔本大学</p><p>97　悉尼大学</p><p>101-151　昆士兰大学、西澳大学</p><p>152-200　新南威尔士大学</p><p>201-302　麦考瑞大学、阿德雷德大学、莫那什大学</p><p>303-401　弗林德斯大学、詹姆斯库克大学、卧龙岗大学、塔斯马尼亚大学、纽卡斯尔大学</p><p>402-503　拉筹伯大学</p><p>&nbsp;</p><p>美国新闻周刊世界大学100强排名中的澳洲大学</p><p>此排名综合了40%上海交大的排名引用数据和60%TIMES的排名引用数据。</p><p>38　澳洲国立大学</p><p>50　悉尼大学</p><p>53　墨尔本大学</p><p>64　新南威尔士大学</p><p>73　莫纳什大学</p><p>78　西澳大学</p><p>91　昆士兰大学</p>'),
    (43,43,'<p>新南威尔士州&nbsp;&nbsp;&nbsp; (首府：悉尼)</p><p>全州人口670万，&nbsp;&nbsp;&nbsp; 悉尼420万</p><p>悉尼大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; The University of Sydney</p><p>新南威尔士大学&nbsp;&nbsp;&nbsp;&nbsp; The University of New South Wales</p><p>悉尼科技大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; University of Technology, Sydney</p><p>麦考瑞大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Macquarie University</p><p>纽卡素大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; The University of Newcastle</p><p>澳洲天主教大学&nbsp;&nbsp;&nbsp;&nbsp; Australian Catholic University</p><p>新英格兰大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; The University of New England</p><p>卧龙岗大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; The University of Wollongong</p><p>西悉尼大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; University of Western Sydney</p><p>南十字大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Southern Cross University</p><p>--------------------------------------------------------------------------------</p><p>维多利亚州&nbsp;&nbsp;&nbsp; (首府：墨尔本)</p><p>全州人口490万，墨尔本350万</p><p>墨尔本大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; The University of Melbourne</p><p>莫纳什大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Monash University</p><p>皇家墨尔本理工大学&nbsp;&nbsp;&nbsp; RMIT University</p><p>迪肯大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Deakin University</p><p>拉筹伯大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; La Trobe University</p><p>斯文本大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Swinburne University of Technology</p><p>维多利亚大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Victoria University of Technology</p><p>巴腊特大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; University of Ballarat</p><p>--------------------------------------------------------------------------------</p><p>昆士兰州&nbsp;&nbsp; (首府：布里斯本)</p><p>全州人口370万，布里斯本170万</p><p>昆士兰大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; The University of Queensland</p><p>昆士兰理工大学&nbsp;&nbsp;&nbsp;&nbsp; Queensland University of Technology</p><p>格里菲斯大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Griffith University</p><p>詹姆斯库克大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; James Cook University of North Queensland</p><p>南昆士兰大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; The University of Southern Queensland</p><p>邦德大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Bond University</p><p>阳光海岸大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Sunshine Coast University College</p><p>中央昆士兰大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Central Queensland University</p><p>--------------------------------------------------------------------------------</p><p>南澳州&nbsp;&nbsp;&nbsp; (首府：阿德来德)</p><p>全州人口150万，阿德来德110万</p><p>阿德雷德大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; The University of Adelaide</p><p>南澳大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; The University of South Australia</p><p>弗林德斯大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; The Flinders University of South Australia</p><p>--------------------------------------------------------------------------------</p><p>西澳州&nbsp;&nbsp;&nbsp; (首府：佩斯)</p><p>全州人口190万，佩斯140万</p><p>西澳大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; The University of Western Australia</p><p>科廷科技大学&nbsp;&nbsp; Curtin University of Technology</p><p>默多克大学&nbsp;&nbsp;&nbsp;&nbsp; Murdoch University</p><p>圣母大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; The University of Notre Dame Australia</p><p>爱迪考文大学&nbsp;&nbsp; Edith Cowan University</p><p>--------------------------------------------------------------------------------</p><p>堪培拉：&nbsp; 人口32万</p><p>澳洲国立大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Austalian National University</p><p>堪培拉大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; University of Canberra</p><p>--------------------------------------------------------------------------------</p><p>塔斯马尼亚州（首府：霍巴特）</p><p>全州人口46万，霍巴特20万</p><p>塔斯马尼亚大学&nbsp;&nbsp;&nbsp;&nbsp; The University of Tasmania</p><p>--------------------------------------------------------------------------------</p><p>全领地人口21万，&nbsp; 达尔文11万</p><p>北领地大学&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Northern Territory University</p>'),
    (44,44,'<p>一提起护士，很多中国的学生和家长马上联想到繁重的工作量和嘈杂的工作环境，这种情况在中国的医院里的确是这样，但在西方，尤其是福利制度发达、人口稀少的澳大利亚去完全不是这样，而且澳大利亚的护理人员不仅从事帮助病人&ldquo;打针吃药&rdquo;的日常工作，而且能使用各种高新的设备，配合医生对病人做出全面的诊断和看护。</p><p>护理人员不仅仅在医院工作。在或在办公室、在学校或在工厂、在飞机上、在油轮上以及一切需要他们出现的地方，护理人员都能找到合适的工作机会。而且无论是在中国还是西方，私人护理需求也比较大，薪水也比较高。</p><p>据统计，澳大利亚每年有近3万名护士的缺口，为了吸引更多的人从事护理工作，一方面增加护士的薪酬，另一方面鼓励更多的海外学生进入这个行业，这就是为什么在每年的澳大利亚紧缺名单上都有护士这个职业，这就意味着从移民角度来讲，海外学生在完成澳大利亚大学护理专业的学习后，不仅可以获得最高职业评估分60分，也可以获得15分以上的加分。</p><p>澳大利亚共有六个州和两个地区。每个行政规划都有各自的护士管理机构，并有其独立的护士注册标准。护理人员要在某地区从事护理行业，就必须注册或登记成为该地区的护士。另外，各行政规划的护士管理机构间也相互认可对方的注册标准，因此一名护士在一个地区成为注册或登记护士后，进入其他地区只需提出简单申请即可获得同等注册或登记资格，并开始工作。从移民角度来讲，如果从澳大利亚的大学护理专业毕业，需要先在该大学所在的州注册，然后在向澳大利亚护士协会（ANMC）递交职业评估申请，同时递交雅思A类（要求总分不低于7，单科不低于6.5）或者护士职业测试（要求每门在B或以上）（如果是在澳洲当地完成的护理专业，可以不递交语言成绩），一般在2个工作就可以得到结果。</p><p>澳大利亚的护理主专业有几种读法，对于中国的高三毕业生，一般需要先读一年的大学预科课程，然后进入大学或者读3-4年的单一护理本科专业，或者是和其他专业一起读的5年以上的双学位。对于中国的非护理本科毕业生，可以去读为期2-3年的护理本科（这种在西方很普遍，叫做GRADUATE ENTRY）。对于中国的护理本科毕业生，可以选择去读澳大利亚读护理硕士，也有可能读为期半年到一年的护理本科。对于具有护理大专，并且具有中国护士证和一定的工作经验，可以去澳洲读为期一年左右的本科。以上读的方式都可以使毕业生成为澳大利亚注册的护士。</p><p>护理专业名校榜</p><p>悉尼大学 (The University of Sydney)</p><p>澳洲顶尖八所大学（GROUP EIGHT）集团成员，是澳大利亚最古老的大学，成立于1850年，享有崇高的国际声誉，是世界一流大学，曾经培养出四位澳大利亚总理、三位诺贝尔奖金获得者。</p><p>墨尔本大学 (The University of Melbourne)</p><p>澳洲顶尖八所大学（GROUP EIGHT）集团成员。创建于1853年，是澳洲最古老、规模最大、声望最高的大学之一。墨尔本大学师资及研究力量雄厚，一批国际知名的学者应邀在校工作，其中包括诺贝尔奖得主Peter Doherty教授和Bert Sakmann教授。学科广泛，并以教学、研究规模大、质量高而举世闻名。</p><p>蒙纳士大学 (Monash University)</p><p>澳洲顶尖的八所大学（GROUP EIGHT）集团成员。位于墨尔本的巨型大学，充满活力的&ldquo;世界大学&rdquo;。建立于1961，在墨尔本及周围分布有六个校园，此外另有校园位于马来西亚吉隆坡及南非约翰内斯堡。在澳大利亚蒙纳士大学是校园最大，在校学生最多的综合性重点大学。</p><p>阿德雷得大学（The University of Adelaide）</p><p>澳洲顶尖八所大学（GROUP EIGHT）集团成员,成立于1874年，是是澳大利亚最古老和最有声望的大学之一，澳大利亚政府对各大学综合测评后推举的最优秀的四所大学之一。阿德雷得大学曾培养出三位诺贝尔奖得主，多位罗德奖（ Rhodes）学者，尤其是学术研究的成果更是个中翘楚。阿德雷得大学毕业生的水平在全世界享有盛誉。许多人在亚洲、欧洲、北美洲和太平洋地区的政府、商界、工业界和大学里担任重要职务。</p><p>&nbsp;</p>'),
    (45,45,'<p>一般来讲，在赴澳洲留学的中国学生中，80%的学生会选择商科就读，商科下面包括了会计，金融，应用金融，人力资源管理，市场，管理等专业，尤其会计专业由于目前属于澳洲技术移民职业中的紧缺职业而获得了更多留学生的青睐，然而，随着赴澳留学生的不断增加，这些选修商科的学生毕业之后势必会面临着激烈的竞争，此时另一个之前不被学生所了解的商科专业逐渐浮出水面，这就是目前被称为金领职业的精算专业。</p><p>精算也是隶属于商科的一个专业，广泛地运用于保险业、基金业、证券投资业、银行及政府相关部门。精算师属于高级专业人才，据澳大利亚精算师协会(Institute of Actuaries of Australia)的统计，一个刚刚获得精算师头衔(FIAA)的专业人士在澳洲的起薪约为9万澳元，每年薪金至少增长1万1千澳元。资深有丰富经验的精算师每年可挣20万元澳币。拥有澳大利亚精算师头衔的专业人才仅有1千多人，这一方面表明精算业的发展空间非常大，另一方面也暗示要成为一名精算师是非常困难的。精算师的就业前景灿烂，除前述领域外，还可以在环保、基因、信息技术、电子商务、电信等行业施展身手。</p><p>想成为一个合格的精算师，通常需要5到7年的时间，其中包括3-4年的大学学习。候选人需要有出色的数学能力及学士以上学位。沟通能力与商务技巧也是相当重要的。候选人要完成三个部分的课程与考试，具备一年以上的精算工作经验，以及参加精算师职业培训课程。三个部分的课程包括：第一部分精算基础(Foundation)，第二部分精算控制循环(Actuarial Control Cycle)，第三部分专业方向(Specialisation)。</p><p>第一部分的学习可以在大学内完成。澳大利亚精算师协会目前只认可5所大学的相关课程，分别是：</p><p>澳大利亚国立大学的Bachelor of Actuarial Studies</p><p>墨尔本大学的Bachelor of Commerce</p><p>麦考瑞大学的Bachelor of Commerce Actuarial Studies</p><p>新南威尔士大学的Bachelor of commerce</p><p>科庭理工大学的Bachelor of Science Actuarial Science</p><p>精算专业的入学要求高出其他商科专业许多，尤其看重申请人的数学能力及成绩。</p><p>第二部分的学习也在认可的大学内完成。以国立大学为例，精算学士学位需要3年完成，完成后即豁免第一部分的学习；再多读一年的荣誉学士学位(Honours)，完成后即豁免第二部分的学习。</p><p>完成前两部分的学习(且只能在大学里完成)后，即成为澳洲精算师协会的会员(AIAA)。接下来的第三部分学习由精算师协会组织。会员将在下列5门课程中完成任意2门的学习并通过考试：金融，生命保险，一般保险，养老金，投资管理。</p><p>一年以上的精算工作经验是按照通过第二部分考试，成为协会会员后所从事的工作计算。</p><p>精算师职业培训课程由精算师协会组织教授，会员通过参加2天的密集课程即可，无需考试。</p><p>上面这些步骤完成后，你才能申请精算师的头衔，成为炙手可热的专业精英中的一员。</p><p>小结一下成为精算师的步骤：</p><p>Part I精算学士学位精算师协会学生会员* (4所大学之一)</p><p>Part II精算荣誉学士学位精算师协会会员AIAA</p><p>Part III 5门专修课中任意2门</p><p>工作经验1年以上被认可工作经验Practical Experience</p><p>职业课程2天的密集讲座式课程精算师FIAA Professional Course</p><p>学位课程开始的时候，就可以成为学生会员。</p><p>因此，如果你具备良好的数学天赋并且将来希望从事商业领域的工作的话，精算专业无疑是一个很好的选择。</p>'),
    (46,46,'<p>该奖学金的设置是为了吸引想学工程学士（土木工程）的学生到La Trobe大学的Bendigo校区学习，并为学生们提供到维省郊区就业的机会，因为那里目前正面临着土木工程师的技能短缺。</p><p>奖学金总值澳币20，000，分四年发放. (每年澳币5，000)。它将提供给满足入学要求，愿意从2010年第一学期（2010年3月）起赴Bendigo校区攻读土木工程本科学位的学生。</p><p>申请这一奖学金的学生要求在高中最后一年的成绩达到70%，IELTS 要求总分不少于6.0，单项各科亦不少于6.0。</p><p>奖学金申请截止日期为2010年1月10日。</p>'),
    (47,47,'<p>由于我国正在大力发展第三产业，并且澳大利亚本身也是强调&ldquo;无烟工业&rdquo;，注重第三产业的国家，因此服务业中的金融、咨询、大众传媒、创意产业等相关专业的就业前景也是十分广阔的。</p><p>每年，澳大利亚都会根据本国的教育、就业和移民等因素综合考虑，列出不同门类的热门专业，内容基本大同小异，如何选择却成为了一个为难的问题。我们从专业角度结合了我国和澳大利亚的经济形势及市场需求对这些专业进行了分析，为准备去澳大利亚留学的学子提供中肯的建议。笔者认为这些建议不但适用于打算去澳大利亚留学的同学，有些同样也适用于打算去其它国家留学但是在专业选择方面存在困惑的同学。</p><p>会计专业，人才通道拥挤</p><p>据了解，很多中国学生留学澳大利亚都会选择商科专业，包括会计类专业、银行、金融等。由于会计专业一直以来都是澳大利亚移民紧缺专业，并且澳大利亚很多高校专门为没有会计教育背景的本科毕业生设置了相应的研究生课程，没有严格的专业背景要求，使得近年来赴澳大利亚攻读会计专业的人数激增，导致澳大利亚会计专业的人才实际上已经出现了供大于求的局面，会计专业毕业的学生很难再找到跟专业对口的工作。因此建议大家，在选择专业时一定不要扎堆，而是要将未来国内和澳洲，乃至亚太地域经济发展对人力资源的供需关系作为参考依据进行衡量选择。</p><p>当然，在商科领域中，也有很多专业可供选择，例如保险精算学、酒店管理、电子商务、创新管理、公司法务、税务、金融分析或者项目管理等。这些专业的就业前景还是相当不错的。</p><p>专才专业，就业有优势</p><p>所谓的通才专业和专才专业都是相对而言的，以会计专业为例，会计专业往往被认为是通才专业，因为所学的内容涉及会计领域的方方面面；而税务会计、金融分析、保险精算学等则被认为是专才专业，因为是会计专业的细化和深化。这些专业往往要求有相关的教育背景。</p><p>很多家长和学生担心选择专才专业就业面比较窄，只局限于某个行业的某个领域；并且专才专业的所学内容往往比较复杂，很难学会。任何事物都是一分为二的，专才专业选择的人少也就意味着竞争较通才专业要小很多，就业机会却多很多。专才教育的优势在于它可以使你具备从事某职业的专业资格，因此在就业的时候，你的目的性十分明确。</p><p>5大热门专业就业前景分析</p><p>■工程类专业</p><p>中国的工业刚刚发展了一半，未来的发展空间还很大，相应的对这方面的人才需求就很多，比如土木工程类人才、电子工程、化工工程、食品工程、矿业工程类人才等。</p><p>■旅游、酒店管理专业</p><p>澳大利亚拥有一流的旅游管理学院，教育品质国际公认，去澳大利亚学旅游课程性价比非常高。</p><p>一些优质大学的旅游学院在课程中都安排了较长时间的带薪实习机会。近年来，随着澳大利亚旅游市场的不断扩大，以及上海世博会的即将举办，国内对旅游人才的需求增加，该专业人才在中国和澳大利亚都将被看好。</p><p>■IT专业</p><p>目前IT行业的职位空缺相应增长。宏观经济条件以及网络的迅猛发展都使得人们对IT业进行大额投资充满信心。这一行业的多个部门再次出现人力短缺。受市场供求关系调节的影响，会有越来越多的学生对该专业逐步恢复几年前的热情。</p><p>■护理专业</p><p>随着世界人口老龄化趋势的显现，护士短缺呈现全球性危机。很多国家都在积极从国外引进护士，以解决本国的护士急缺，澳大利亚也是如此。在世界范围内经济不景气的环境下，护理从过去的底层职业一跃成为令人羡慕的职业，这给中国很多护校学生提供了很好的留学机会。但是需要注意的是赴澳攻读护理专业基本限于在国内已经有护理背景，受过专业学习或训练的学生。</p><p>2008年年底，澳大利亚移民部引入了CSL关键职业技术清单（Critical Skills List）。 CSL清单职业将得到移民局优先处理申请，甚至优于之前的MODL清单。 CSL清单主要关注于房屋建筑、信息技术、工程以及医药领域，这个结果也是在咨询了澳洲各州领地政府得出的结论，从一个侧面反应出各州政府对人才的需求方向，显示出以上专业人才在当前的形势下依然是供不应求的。除此以外，由于我国正在大力发展第三产业，并且澳大利亚本身也是强调&ldquo;无烟工业&rdquo;，注重第三产业的国家，因此服务业中的金融、咨询、大众传媒、创意产业等相关专业的就业前景也是十分广阔的。</p><p>■技工类TAFE课程</p><p>澳大利亚有着较为完善的职业教育制度，政府非常鼓励学生接受职业教育，如厨师、美容、美发、机械维修等。职业院校的课程由相关就业机构进行开发设计，直接为就业作准备。由于学生在学习期间熟练掌握了工作所需技能，就业率很高，甚至高于当地一些名牌大学的就业率。这类课程学费低廉，易于移民，得到更多学生和家长的认可。</p>'),
    (48,48,'<p>如今越来越多的家长意识出国留学选择高薪职业才是真正的王道，所以在考虑专业的选择时，应该关注一下回国后的就业发展情况，那么哪些职业最有&ldquo;钱途&rdquo;呢？</p><p><strong>飞行员</strong></p><p>民航的持续快速发展，机队规模迅速扩张，导致飞行、机务、空管、运行管理等专业人才十分缺乏。在航空运输自由化、全球航空联盟化大背景下，具有专业背景、外语好、能够参与国际交流的国际化人才短缺，懂技术、会管理的高素质复合型人才十分紧缺。</p><p>飞行员堪称高技术，高回报的专业，目前国内机长的年薪约在30万左右。一般来说国内的飞行员都是航空公司定向选拔培养，采用合同制的，如果学生自己从澳大利亚完成，回国应聘飞行员，可以自主选择航空公司，且薪水待遇会更好。但是申请开设相关专业和课程的澳大利亚院校并不多，澳大利亚的皇家墨尔本理工大学(RMIT)以及埃迪斯科文大学(ECU)开设有飞行员专业的课程，以及航空管理的课程。</p><p><strong>理财规划师</strong></p><p>金融危机，唤醒了人们的理财意识，越来越多的人开始选择专业的理财顾问来有效的规避风险，理财规划师也日趋成为炙手可热的职业。理财规划师的从业方向较广，可以是银行、专业第三方投资理财公司、证券公司等。据了解，目前国内理财规划师有近20万的人才缺口，因经验和专业方向不同，年薪为10万-100万不等。</p><p>对于很多想要通过学习&ldquo;会计&rdquo;移民的学生，可以考虑会计和金融双专业的课程，这样既可以满足移民的需求同时还可以了解金融方向的知识，拓展自己的就业面。</p><p><strong>动漫绘图师</strong></p><p>中国的动漫产业处于飞速发展的时期，对于有独立制作和创作动漫作品能力的动漫绘图师需求量极大，目前国内的很多动漫产品和影视产品很大程度上还在依附于国外的技术。优秀的动漫绘图师薪水均在年薪10万人民币以上，分别服务于广告公司、影视传媒公司等。</p><p><strong>护士</strong></p><p>护士目前已经成为全球紧缺的职业，紧缺人数达到200万人，在西方发达国家，如美国、加拿大、英国、澳大利亚等国紧缺状况尤其明显。据了解，国内目前就读护理专业的学生不少，但是较难找到工作，并且待遇较低；相比国内这种尴尬情况，国外的护士待遇要好得多。初级护士在澳大利亚平均年薪在5万澳币左右。但是护士专业在澳大利亚课程的位置容量比较有限。</p><p>一般来讲，对于原专业就是护理专业的学生来说，申请澳大利亚的院校是可以转学分的。比如，大专毕业的学生只需要在澳大利亚读2年的本科就可以了。国内本科毕业有护士证的，在澳大利亚再读1年的本科，就能满足成为注册护士的学术要求，再提供一个无犯罪记录证明和雅思4个7分，就可以成为注册护士了。</p><p><strong>机械工程师</strong></p><p>随着中国大型工业的复苏，工业制造类人才需求量越来越大，特别是有独立开发能力的数控人才，及机械设计制造人才更为稀缺。对于读本科的学生，如果理工科基础较好，先学习一门技术型较强的工科课程，在研究生阶段，或者工作一段时间以后继续攻读一个研究生的管理课程，对于学生整个职业发展道路更为有利。</p>'),
    (49,49,'<p>中国学生和家长的名校情结由来已久，在对待出国留学选校选专业问题也是这样。比如赴澳洲留学，就一定要读澳洲八大名校。然而，名校有名校的定位和标准，学生和家长盲目选择，只会陷入一些误区，导致留学失败。</p><p>出国留学的学生在选择名校的同时，要考量自身的条件。很多名校专业对申请者的要求非常高，如果不选好的话，会对自己的留学申请带来一定的障碍。</p><p>对于赴澳洲留学的学生来说，很多澳洲大学虽然综合排名不是很高，但其中的某一个专业或者学院由于其学术成就或师资力量而在相关行业领域内有着举足轻重的地位，这些专业是非常难申请的，以下的表格里总结出了入读难度较高的澳洲院校。</p><table><tbody><tr><td><p><strong>专业</strong></p></td><td><p><strong>院校</strong></p></td></tr><tr><td><p>会计</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">麦考瑞大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">墨尔本大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">莫纳什大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼科技大学</a></p></td></tr><tr><td><p>农学</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">昆士兰大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">西澳大学</a></p></td></tr><tr><td><p>建筑学</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">墨尔本大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">昆士兰大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">新南威尔士大学</a></p></td></tr><tr><td><p>建筑环境学</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">格里菲斯大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼大学</a></p></td></tr><tr><td><p>商科和管类类</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">麦考瑞大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">莫纳什大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼大学</a></p></td></tr><tr><td><p>通信专业</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">格里菲斯大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">墨尔本大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">昆士兰科技大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼大学</a></p></td></tr><tr><td><p>计算机和信息技术</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼大学</a></p></td></tr><tr><td><p>创造艺术类</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼大学</a></p></td></tr><tr><td><p>经济类</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">麦考瑞大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">莫纳什大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼大学</a></p></td></tr><tr><td><p>工程学</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">墨尔本大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼大学</a></p></td></tr><tr><td><p>环境学</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">麦考瑞大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">莫纳什大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">昆士兰大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">昆士兰科技大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">西澳大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">卧龙岗大学</a></p></td></tr><tr><td><p>健康服务</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">墨尔本大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">莫纳什大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">昆士兰科技大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">南澳大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼科技大学</a></p></td></tr><tr><td><p>人类学和社会学</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">格里菲斯大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">麦考瑞大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">墨尔本大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">莫纳什大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">昆士兰大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">斯威本科技大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">新南威尔士大学</a></p></td></tr><tr><td><p>语言学</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">墨尔本大学</a></p></td></tr><tr><td><p>数学</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼大学</a></p></td></tr><tr><td><p>护理学</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">科廷大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">格里菲斯大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">昆士兰科技大学</a></p></td></tr><tr><td><p>心理学</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">弗林德斯大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">格里菲斯大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼大学</a></p></td></tr><tr><td><p>复原学</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">科廷大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">弗林德斯大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">纽卡斯尔大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">昆士兰大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">南澳大学</a></p></td></tr><tr><td><p>理工类</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">格里菲斯大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">麦考瑞大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">墨尔本大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">莫纳什大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">昆士兰大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">斯威本科技大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">新南威尔士大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼科技大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">西澳大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">卧龙岗大学</a></p></td></tr><tr><td><p>社区服务</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">纽卡斯尔大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">昆士兰大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">西澳大学</a></p></td></tr><tr><td><p>运动学</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">昆士兰科技大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼科技大学</a></p></td></tr><tr><td><p>测量学</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">麦考瑞大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">昆士兰大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">西澳大学</a></p></td></tr><tr><td><p>旅游和酒店管理</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">昆士兰大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼科技大学</a></p></td></tr><tr><td><p>兽医学</p></td><td><p><a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">墨尔本大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">莫道克大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">昆士兰大学</a>、<a href=\"http://studyabroad.tigtag.com/major/89254.shtml\">悉尼大学</a></p></td></tr></tbody></table><p>&nbsp;</p>'),
    (50,50,'<p>第1类：商科类的会计、财务经理、财务总监、市场推广及销售等，这类职业收入比较可观。一个会计的入职起薪点大约为3万元，有经验及能力的人士薪水可达到六位数。税务会计师的起薪点是4.5&mdash;6.5万，税务顾问的报酬高达4&mdash;7万。</p><p>第2类：计算机类的程序员包括分析程序员及系统程序员、计算机应用、软件设计、系统设计等，这类职业是澳洲目前发展势头最猛的行业。具体地说，一个程序设计员的入职起薪点是4.5万元，而一个程序发展经理的薪水高达15万元。网络行政人员的薪金为4.5万元，而网络经理则是11万元。从年龄段来看，从事计算机行业的人员23&mdash;25年龄段的薪金明显高于其它行业。</p><p>第3类：管理类包括总经理、经理助理、人力资源管理、生产经理、工程经理、营销及市场建立推广经理、供应及销售经理、系统经理等各行业的管理人员。一般入职起薪点为3万元，最高可达到8万元，而其他同时具有专业技术资历的行业经理以此为基础薪金会高得多。</p><p>第4类：工程类如飞机工程、农务工程、物流工程、机械工程、矿务工程、建筑工程、化学工程、土木工程、电子工程、电机工程、石油工程、海事建筑、生产及工厂工程等，一个建筑工程的资深员工的薪金可达到10万元，而农业工程员工的薪水从3.5万&mdash;8.5万元不等。</p><p>第5类：医疗及护理类，包括牙科专家、牙医、职业治疗师、物理治疗师、足病治疗师、脊椎治疗师、各类放射治疗师、兽医、药剂师、验光师、整骨师等，护理最需要的是注册过的护士、助产士、残障发展护士、心理卫生护士和护士长。</p><p>医科及相关专业在澳大利亚是属于较难读出的学科，对语言要求高、学制又偏长，但学生完成学业后就业前景很好，比如护士入职起薪点是3.1万元，加上值班等实际收入可达到4万多元，而护士长的薪金就可达到8.7万元，目前在澳洲男护士尤其缺乏。</p><p>第6类：教师，包括幼儿教师、小学教师、中学教师，其实有关澳洲教师短缺的预言早有先兆，整个澳大利亚中学的科学教师、计算机教师和数学教师都有严重短缺的情况，而外语教师也已不足。一般教师的薪水从3.5万元开始，预计在未来十年内可达到5万元。</p><p>第7类:社会工作者和心理医生，如社工、福利工作者、临床心理学家及心理医生、语言病理学家等，近期澳大利亚联邦政府的一个调查表明，心理辅导正在蓬勃发展，越来越多的心理学被应用到实际工作中，具体如临床心理学、组织心理学及法庭辩论心理学等。有经验的人士薪水可达到5.5万元。</p>'),
    (51,51,'<p>第一种：570类型签证，是指去澳洲单纯的学习英语强化课程</p><p>第二种：571类型签证，指申请人赴澳洲读中学课程。</p><p>要求：</p><ol><li>具有初中毕业证或同等学历</li><li>读10年级的学生不能超过18周岁，读11年级的学生不能超过19周岁，学生不能直接申请读12年级课程</li><li>主课长度不能少于16个月，从语言课程开始，倒读不能超过18个月</li><li>雅思豁免：</li></ol><p>A）若学生不满16周岁，雅思直接豁免</p><p>B）若学生大于16周岁且小于18周岁，申请的澳洲学校要出雅思豁免信 C）要求学生在国内就读的学校初三年级的英语平均分不能低于75分</p><p>&nbsp;</p><p>第三种：572类型签证，指学生申请读DIPLOMA课程，长度一般在1年到2年左右，使馆要求5。5分可免语言课程，直接读主课，但是也要看具体的学校的相关要求。要求最高学历：有高中毕业证或同等学历（中专、职业技术学校）</p><p>第四种：573类签证，指申请高等教育，读GC，GD，本科或研究生课程，要有高中毕业证书</p><p>第五种：574类型签证，指申请硕士或博士的研究课程</p><p>第六种：575类型签证，只是单纯去学习课程，没有文凭和学位，只是一段学习经历</p><p>第七种：576类型签证，去参与澳洲国家项目的研究</p><p>第八种：580类型签证，也称监护人签证，是指未满18周岁的学生家长或家长提名人，在澳洲监护学生的一种签证，要求监护人与学生在澳洲同进同出。</p>'),
    (52,52,'<p>每年的7、8月份是澳大利亚的开学高峰期，如果想在这一时间段入学的学生，现在要开始着手签证申请工作了，因为澳大利亚的签证申请，尤其是常规申请的周期较长，如果不早做准备的话，很有可能耽误开学。现编者就签证申请需做的准备工作以及不同的签证方式流程等方面做重点的介绍。</p><p>担保金最重要</p><p>一般来说，澳大利亚留学签证，要求申请人的担保金存满6个月，并且在这期间不能转存。如果去澳大利亚学习，预科每年的学费在12万元人民币左右，生活费6万元人民币左右;本科所需的学费在每年13万-15万元人民币，生活费6万元人民币。</p><p>澳大利亚要求的担保金数额为40万到80万元人民币，主要是根据选择留学方式的不同，担保金数额会有所不同。</p><p>同时，需提供父母收入证明，以保证孩子在澳大利亚留学所需费用。据了解，一般要求父母的合计年收入至少在6万元以上，如果父母的年收入比较低，比如在2万元到3万元人民币左右，会影响学生顺利拿到签证。针对这种情况，建议申请者可以把直系亲属的收入证明也列入其中，如爷爷、奶奶、外公、外婆等。但还是应该以父母的为主，其他亲属的为辅。</p><p>允许办理留学贷款</p><p>如果准备好了资金，但是最后发现存款的时间不够，可以申请办理留学贷款，而澳大利亚对于贷款所得资金的存期是没有要求的。目前，民生银行、上海浦东发展银行、深圳发展银行、建设银行、中国银行、中信银行、工商银行都提供了留学贷款的业务。资金担保中，不够6个月的需要贷款，比如资金担保需要50万元人民币，如果已经有10万元人民币存够了6个月的存款期限，那么可以贷出40万元人民币。</p><p>房屋抵押需提前一个月</p><p>如果资金准备不足，除了考虑申请办理留学贷款外，也可以根据个人条件考虑房屋抵押。如果是房产抵押的话，姚丽钦建议大家在递交签证的一个月前就要开始抵押交易，因为往往整个抵押交易的过程会持续一个月。比如学生打算4月份申请签证的话，那么3月份就要开始房产抵押。</p><p>雅思要求5分以上</p><p>除了担保金，对有留学意向的学生来说，语言成绩也是非常重要的一环。澳大利亚签证要求雅思5分(除570语言课程签证和571高中生签证外)以上，而每个学校对雅思的要求各不相同，但往往高于5分。如果学生的语言低于学校要求，建议学生提交申请配套的语言课程。</p><p>通常，每低于0.5分，要加读10周的语言先修课程。比如学校的语言要求为6分，而学生只有5.5分，那么就需要加读10到15周的语言课程。如果学生的语言要求低于学校要求却并不加读足够的语言课程，在签证申请时容易引起签证官的怀疑，给签证带来不必要的麻烦。</p><p>时间紧迫可考虑电子签证</p><p>电子签证又称e-Visa是澳大利亚移民部为了提高学生签证审批效率而开发的一整套网上申请操作系统。它以e&mdash;electronic电子技术为手段，通过一个专门的网络系统，以电子文档的形式将相关的签证申请资料发送到澳大利亚政府的海外学生签证审理中心(OPC)，进行评审，OPC则通过电子文档交换的形式将档案号、体检表、签证审批函等文件发送到代理申请签证的留学服务机构，整个签证程序大大简化，效率得到极大的提高。</p>'),
    (53,53,'<p>1、（1）16岁以下初中及初中以下学历学生<br />如需要出国留学，有两种变通方式处理：<br />其一、先到新西兰读完初中以下课程，再到澳大利亚留学。<br />其二、学生家长办理澳大利亚移民或长期商务签证，让学生作为副申请人被家长带到澳大利亚接收免费的政府小学至高中的免学费教育。但是家长必需满足移民或长期商务签证的申请条件[点这里查看澳大利亚163移民及457商务签证要求]。<br />（2）18岁以上学生也可以通过父母移民澳大利亚或父母办理澳大利亚长期商务签证的方式免雅思到澳大利亚留学或发展[点这里查看澳大利亚163移民及457商务签证要求]。<br />2、赴澳大利亚读语言、高中、预科的条件<br />※ 入读澳大利亚语言、高中对学生的基本要求：<br />1、没有刑事记录；<br />2、身体健康；<br />3、在读高一，高二学生，高三第一学期在读学生或刚毕业的初中生（年龄16周岁以上，不超过18岁）可免雅思申请留学签证；<br />4、注：高三第二学期在读学生要求雅思5.0以上，入读个别公立中学要求学生提供雅思成绩5分以上；<br />5、有足够资金支持，详细解释见《澳大利亚留学担保金的计算与留学贷款的问题》一文。<br />※ 直接入读预科的条件：<br />1、雅思成绩5.5分以上，5分的学生需要配套一定时间的语言；<br />2、高中毕业；<br />3、有足够资金支持，详细解释见《澳大利亚留学担保金的计算与留学贷款的问题》一文。<br />3、留学澳大利亚---大学、大专的入学要求<br />1、没有刑事记录；<br />2、身体健康；<br />3、在读大一、大二、大三学生，毕业的高中生，职高、中专、大专或相关学历； 4、IELTS考试成绩5.0以上可以办理签证，赴澳后首先进行语言的学习，通过考试后，达到大学所要求的英语成绩方可进入大学学习。<br />4、 留学澳大利亚---研究生的要求（申请研究生、博士生）<br />1、没有刑事记录<br />2、身体健康<br />3、已获学士学位（硕士学位）<br />4、雅思成绩(5.0以上) ，部份院校可以接受5.5分学生直接入读研究生正式课程，具体请电话向我们咨询；<br />5、有些院校要求申请报读工商管理硕士课程的学生另外提供&ldquo;工商管理研究生课程入学测验&rdquo;(GMAT)的成绩。<br />5、有雅思成绩的中国专科学生可以直接赴澳大利亚部份院校读研</p>'),
    (54,54,'<p>签证材料由于经济状况导致拒签的情况，也特别提出了申请人必须有足够的经济能力支付你在澳洲学习生活的全部费用。顺利拿到签证的理由主要集中在以下三个方面：</p><p>第一条，保金必须具备两个关键因素，&ldquo;可被接受的资金证据&rdquo;和&ldquo;存期满半年&rdquo;，这是办理签证必须满足的条件。</p><p>&nbsp;</p><p>所谓&ldquo;可被接受的资金证据&rdquo;是指现金存款(股票、房产不能作为现金存款)，这点是十分明确的。&ldquo;存期满半年&rdquo;是这么理解的：你所提供的资金，一定要在递交签证申请日前半年就已经存入银行了，哪怕是活期的，存期为三个月的，一年的，两年的，都无所谓，但一定要存够半年。澳洲移民局也是通过这种方法来界定这笔资金是不是申请人可使用的。</p><p>第二条，&ldquo;可接受的资金来源&rdquo;是指什么呢？</p><p>澳洲移民局对此定义十分明确：申请人本人，其父母，祖父母，外祖父母，兄弟姐妹或配偶名下的，在认可的金融机构存足六个月的存款；从认可金融机构获得的贷款，或政府贷款；由教育提供者或者某个机构同意提供的经济支援；非现金财产，例如股票和房产是不被接受的。</p><p>第三条，就是收入和所提供的资金相一致。</p><p>很好理解，就是你所提供的资金要是你收入的累积所得，但这条往往又是机动性最强的一个因素。中国人为了使子女今后得到良好的教育，从很早就开始为孩子存钱，家中的消费与收入的比例也相对较低，而存款与收入的比例却相对较高。但因为文化背景和生活习惯的不同，澳洲人是不怎么存钱的，而是去投资或消费了，所以澳洲签证官的存款理念与中国人还是略有不同的，但移民局还会对家庭的经济能力Financial Capability进行考虑的，只要是客观、合理的阐述如何累积的资金，都不会有问题的。</p><p>综合以上三条资金条件我们不难看出，移民局从经济能力的各个方面去考察申请人的资金能力，只要是符合签证条例的签证申请就会得到签证官的批准。最后预祝每一位按照签证政策办理留学申请的学生都能够顺利获得签证。</p>'),
    (55,55,'<p>出国留学的高峰又要到了，根据海关规定，出境最多只能带５０００美元现金或等值外币。那么对于出国留学的人来说，汇款就成为必不可少的程序。现在汇款方式多种多样，主要的包括电汇、汇票、西联汇款、速汇金、国际卡、旅行支票等，但是这些方式的到账时间、费用不等。如何选择适合、最省钱的汇款方式呢？江苏省中行汇款业务专家日前给市民支招。</p><p>电汇是目前最普遍、使用最广泛的汇款方式。如果知道收款人开户银行和开户账号等信息，即可选择电汇，到账时间一般为３至４个工作日。以中行为例，目前的费用包括１&permil;的汇款费和１５０元邮电费，其中汇款费最低为５０元。</p><p>汇票是由付款人在银行开立外币汇票后将票据携带出境，在当地银行办理款项托收或直接交付给境外个人及机构，或者将票据直接寄往境外个人或者机构，作为款项的支付。汇票是指由银行签发的，以外汇标明面额的，由客户持有、携带，并到境外凭已办理外汇支付或取款的银行票据。汇票的汇款费用较低，中行目前只收１&permil;的汇款费（最低５０元）。但由于国外银行的解付情况不同，所以解付的时间长短有所差异，而且，当地的解付也需要另外支付费用。</p><p>西联汇款和速汇金都是通过汇款公司的网络办理的汇款业务，速度很快，一般２０分钟左右就可完成由汇款人到收款人的整个过程，但如果汇出金额大费用就比较高，且要求收款人所在地必须有业务受理机构。目前，国内受理的汇入、汇出汇款币种仅限于美元。</p><p>国际卡不同于其他汇款方式，它的主要功能还是体现在消费上，境外取现一般要收取３％的费用，相对较高。</p><p>旅行支票在境外可用于日常消费、缴纳学费等。它有不同的面额和币种，购买、兑付、使用不受时间、地点限制，可以直接兑换当地货币，即时挂失，使用起来和现金一样方便，但是购买费用一般为面值的１％，兑付需要另外付费，各国费率不同。</p><p>汇款如何选择最划算？</p><p>一般小金额的汇款还是汇款公司的汇款费用相对较低，但是大金额则是电汇比较划算。以汇出５００美元为例，速汇金费用为１２美元，约９０元人民币，西联汇款为１５美元，约１１２．５元人民币，电汇约为２００元人民币；以汇出５０００美元为例，速汇金费用为２３美元，约１７０元人民币，西联汇款为３０美元，约２２０元人民币，电汇约为２００元人民币；以汇出１００００美元为例，速汇金费用为３０美元，约２２５元人民币，西联汇款为４０美元，约３００元人民币，电汇约为２２５元人民币。</p><p>如果在年底前出国的留学人士也可以考虑使用中行的美国运通旅行支票，近期有优惠活动。在购买的时候，理财专家建议尽量选择和目的国相同的币别，比如说去英国可以买英镑旅行支票；可以根据用途选取面额；此外，要尽量避免使用外币现钞购买旅行支票，减少钞转汇的损失。另外，要保管好购买合约书，这样可以在丢失或被窃时办理挂失补偿。</p><p>最后，这位人士从风险的角度给大家两个汇款建议：&ldquo;一般情况下，如果在国外有账户，还是采用电汇最方便安全。如果没有账户的话，旅行支票是不错的选择。&rdquo;</p>'),
    (56,56,'<p>申请留学热门国澳大利亚签证的中国学生常常遇到被拒签的情况，那么申请澳大利亚签证的难点和重点到底在哪里，为什么留学澳大利亚会被拒签呢？</p><p>&nbsp;</p><p>澳大利亚对留学担保金有比较严格的规定：所有担保金都要有半年的存期，如果课程长度超过3年，最长按3年的学费和生活费算保证金，不足3年的，就按实际年限来算学费和生活费。公立高中费用每年约15万元，私立学校会稍贵，约20万元，而本科和硕士每年费用约为18万－22万元。</p><p>申请澳洲签证被拒签的常见原因有三：</p><p>1、申请人的经济担保文件做得不充分。因不了解移民局对担保资金的计算要求，导致担保金数额不足或者担保金存期不足半年而遭拒签。有些学生对担保金的计算方法不了解，不清楚担保金包括学费、生活费、机票费等而少算了，或者由于汇率的变动导致担保金不足。</p><p>2、申请人提供了不真实的材料。申请人除了提供经济担保类的文件，还要提供有关教育背景的材料、雅思成绩单等，所有递交材料都必须真实。</p><p>3、申请人不了解移民局对签证类别的具体要求，导致未满足递交申请的基本要求。学生签证的每一个类别对学生年龄、英语、学历、资金都有不同的要求。如果不满足，就会被拒签。比如移民局规定，就读硕士的学生第一次最多只能申请30周的语言课程，但学生的IELTS只考到5分，单科还有3.5分，学校会帮学生配40周的语言课程，如果学生不了解使馆要求，直接以40周语言课程的录取通知书申请签证，就会被移民局拒签。如果学生有拒签的记录，则在下次申请时，必须对上次的拒签原因有合理的解释。</p>'),
    (57,57,'<p>签证周期是和很多因素密切相关的，主要分以下几个因素：</p><p>第一、雅思成绩</p><p>大家都知道IELTS要考至少5分才能申请签证，如果去读研，只考5分是不够的，大部分学校需要考到6.5分，单项6分以上。是否来得及签证，和读语言的周数有关系。比如你准备7月份开学，但IELTS只有5.5分，因为大部分学校需要15-20周的语言学习才能达到学校的语言入学要求，我们倒推回来，20周的语言开课时间在2月中下旬，因此，签证是来不及了，只有安排8月的语言和来年2月的主课。</p><p>当然了，这里面又延伸出很多问题，常见的有：</p><p>问：我中途又考出了更好的成绩，是否可以缩短语言？</p><p>答：可以。如果你第一次雅思6.0,后来考出了6.5，满足了条件，那么你甚至可以不读语言了。但是如果你第一次没有到6.0,语言是不可以完全减除，只可以缩短。</p><p>第二、签证材料的完整和阐述</p><p>我们通常说，签证官审理签证材料是要看你是否满足签证条件，签证条件就是我们把握的要点，是签证材料中最核心的部分。很多人可能会说，不就是材料清单吗？！这和材料清单完全是2个概念。签证官凭什么要给你贴签证呢？是因为你满足签证条件，为什么拒签呢，也是因为他们的材料不满足签证条件。如果但是一个材料清单的问题，那么中国学生就不会有35%的拒签了。</p><p>如果签证材料准备的合理可信，阐述的详尽全面，满足所有签证条件，签证官再不需要去CONFIRM和电话调查的话，签证周期就短了。材料可以做得很强，也可以很弱，虽然后者也可能通过签证，但是作为专业公司，我们一定得把材料做得很强，减少出现移民管误解的机会，也就减少了调查机会和拒签可能。</p><p>第三、PVA通过后到正签FINAL DECISION的时间</p><p>预签PVA目前来看只是一个步骤，能不能如期拿到签证，和PVA过后交学费领取COE，以及COE后等过程也密切相关。要申请COE要考虑几个步骤</p><ol><li>如何尽快换到学校的Full offer,要检查你的offer的condition，是否缺材料或者没有达到一些条件，换不到full offer, COE是肯定申请不到的；</li><li>如何最短时间换汇；要确认银行何时可以换汇，需要哪些材料？手续费多少？</li><li>如何把学费支付到学校，如电汇、汇票、澳洲朋友代付、信用卡等；</li><li>如何催学校尽快制作COE，COE出来一定要检查，因为学校也经常出错；</li><li>处理出来后要尽快发给移民局，同时确保移民局在PVA清单上面的补充材料及时补到.常见的有体检报告、贷款合同和相关证明、学历等</li></ol>'),
    (58,58,'<p>据统计，近几年澳大利亚留学签证申请获签率颇高，但这并不意味着澳大利亚签证是可以轻而易举的获得，整个申请过程中有诸多事项需要注意：</p><p>1、签证申请需要符合澳大利亚各类签证规定</p><p>针对不同学历的学生，都有其所对应的澳大利亚签证类别和具体规定，不要小看也不要忽视这个签证类别，因为签证成败的第一步就是这么迈出的。比如，572类学生签证所配语言最长不能超过20周。如果超过了规定的语言周数，会出现以下两种情况，一种是直接拒签，还有一种是只能拿到语言课程时间的签证，结束语言后还要回国续签。当然，这只是其中一个小例子。澳大利亚签证政策不仅条款多，而且还会时时更新。建议学生在不了解这些政策的时候，不要盲目自己递交申请，需要找专业的咨询顾问。</p><p>2、签证材料不能照搬照抄</p><p>每个学生家庭经济条件情况都是不一样的，千万不可模仿别人的签证材料来递交申请。比如周围的同学和朋友中有已经办好签证的，家长只出了两份收入证明和其它常规材料，如果申请人是个人开公司的高收入者，也只出一份收入证明的话，那么被调查的风险就非常高了!所以一定要让您的顾问老师针对您的情况量身制定签证文件。</p><p>3、递签时间要合理安排</p><p>澳大利亚签证现在有两种方式：普签和电签。以这两种方式递交的签证评审时间和过程都不一样。所以在递交签证之前，一定要考虑清楚，学生还考不考雅思了?5分怎么递、6分怎么递?如学生还有两个月就开学了，就需要选用电签的方式。</p><p>提醒：澳大利亚的电子签证申请不对学生个人开放。</p><p>4、担保金一定要准备充分</p><p>澳大利亚使馆明确了担保金的计算公式：学费+生活费+国际旅费。如有配偶或小孩的话需要再计算他们的生活费用。</p><p>5、担保金的形式</p><p>澳大利亚使馆承认的担保金有两种：满足6个月的存款历史或贷款(后者不要求有存款历史)。在某些条件下，活期存款或理财金也是可以用的。还有的家长会问，签证申请递交一个月后，有笔存款就够6个月了，此笔费用是不能作为担保金当的，使馆承认的是在递交使馆时资金就要有六个月的存款历史才可以的。</p><p>6、交学费</p><p>交学费是获得签证之前最重要的步骤之一。这点上，澳大利亚每个学校对于交学费的方式都是不一样的，比如有的要求汇票，有的要求电汇，汇错了则容易丢失和延误时间，交付学费钱需要找您的顾问老师指导和确认。</p>'),
    (59,59,'<p>适用于申请赴澳大利亚留学的常住在中国或新西兰的中国公民</p><p>&nbsp;</p><p>学生签证的主申请人在递交(http://immi.gov.au/students/prc.htm)申请时需递交以下材料。本清单仅规定了在递交申请时所必须提供的基本材料，而并未对申请人可提供的材料作任何其他限制。申请人可同时递交他们认为有助于签证评审的其他任何材料。</p><p>&nbsp;根据1958年移民法的有关规定，签证审批部门可在申请人递交申请时所提供材料的基础上作出决定，而不必要求申请人再提供进一步材料。因此，在递交申请时请尽量完整地提供签证申请材料，这一点对申请人是至关重要的。</p><p>&nbsp;所有表格需用英文填写。申请人提供的除英文之外的其他任何语种的材料均需附上英文翻译件。所有材料必须是原件或者是经公证或认证的复印件。在中国，复印件可由公证处公证或认证。</p><p>&nbsp;申请人递交申请后，如果所提供的信息发生变更，必须书面通知签证审批部门。否则移民部将依据申请人递交申请时所提供的材料进行签证评审。</p><p>&nbsp;</p><p>个人及一般性材料:</p><p>&bull;签证申请费以澳币支付可通过信用卡，汇票或银行支票的方式汇款至澳大利亚移民及多元文化土著事务部,必须支付申请费，否则本次学生签证申请无效。</p><p>&bull;一份填写完整并签了名的学生签证申请表格(157A表) &ndash;必须递交申请表格，否则本次学生签证申请无效。</p><p>&bull;一份填写完整并附有签名的家庭成员表(54表)。</p><p>&bull;一份本清单的复印件，标明您在递交申请时所提供的材料。</p><p>&bull;如已有护照，请提供主申请人及随行人员护照首页和备注页的复印件。请不要在此时提供您的护照原件。</p><p>&bull;请提供主申请人及随行人员身份证的复印件。</p><p>&bull;如果您所提供的通信地址在中国，请提供四张写有姓名及地址的中文的不干胶贴条。</p><p>&bull;如果您所提供的通信地址不在中国，请提供四张写有姓名及地址的英文的不干胶贴条。</p><p>&bull;主申请人及随行人员，每人需提供四张近六个月内拍摄的护照照片。</p><p>&bull;提供户口本每一页的清晰复印件的公证书。</p><p>&bull;如果你未满18周岁，并且/或者你的父母为你支付在澳大利亚学习期间的费用，请提供注有你父母姓名的你的出生证明的公证书。</p><p>&bull;如果你的祖父母/外祖父母为你支付在澳大利亚学习期间的费用，请提供注有你父母姓名的你的出生证明的公证书，以及注有你祖父母/外祖父母姓名的你的父母的出生证明的公证书。</p><p>&bull;如果你的兄弟姐妹为你支付在澳大利亚学习期间的费用，请提供注有你父母姓名的你的出生证明的公证书，以及注有其父母姓名的、你的兄弟姐妹的出生证明的公证书。</p><p>&bull;如果你未满18周岁，并且在澳大利亚不与父母双方中任何一人或法定监护人共同居住，请提供由每所你即将就读的学校签署的监护证明，证明有关学校将负责你在澳期间的食宿，生活保障和基本福利问题。或者由你父母书面指定的一名常住澳大利亚的21岁以上亲属出具的法律声明书，证明他/她将负责你在澳期间的食宿，生活保障和基本福利问题；以及相关人员的出生证明的公证书和能证明你们之间亲属关系的法律文件；以及在过去10年中你的指定在澳亲属曾居住过超过12个月的每一个国家警方所出具的无犯罪记录证明原件。有资格成为指定看护人的亲属包括兄弟，姐妹，祖父母/外祖父母，姨母/姑母，叔伯/舅父，侄女/外甥女，侄子/外甥，继父母, 异父母兄弟, 异父母姐妹, 继祖父母, 继叔伯, 继伯/婶母, 继侄子（女）.</p>'),
    (60,60,'<p>超过70所的学校已获澳大利亚政府批准，在头两年的英文IELTS成绩豁免规定期间可以接受AEAS考试的成绩。随着更多的学校向澳大利亚政府提出申请，获澳大利亚政府批准的可以接受AEAS考试成绩的学校数量还会增加。对于这些学校来说，更提倡学生参加AEAS考试，因为它更适合在校中学生，同时，AEAS考试还向学校提供有关学生的英语水平、数学推理能力和综合能力的信息，以便协助学校做出是否录取等决定。目前，北京、上海、广州和深圳已开设了AEAS考点，中国学生须在www.aeas.com.au网站报名参加考试。申请签证时，学生必须收到澳大利亚学校出具的允许学生在豁免规定下参加</p><p>AEAS考试的书面声明，校方的书面声明和AEAS考试成绩必须与其他有关证件一起附在学生的签证申请上。</p><p>澳大利亚政府规定学生必须取得</p><p>AEAS成绩如下：如英语水平考试成绩不低于36分，需就读30周以下的英语强化课程；如果英语水平考试成绩在61分以上，则无需就读英语强化课程。</p><p>AEAS考试包括：英语水平、数学推理能力和非词汇部分综合能力。考试大约需要3小时。</p><p>英语水平</p><p>考试题目包括词汇、阅读理解、写作、听力和口语。</p><p>■词汇（包括各种题型，例如选择题、同义词搭配和句子填空），考试时间为20分钟，试题数量为20-25题。</p><p>■阅读理解（包括2-3篇不同类型和题目的文章。学生结合所阅读的文章回答问题），考试时间为30-35分钟，试题数量为20-30题。</p><p>■写作（要求学生选择自己感兴趣的并适合他们年龄和背景的题目写一篇200字的作文），考试时间为30分钟，试题数量为1题。</p><p>■听力（包括4-6篇不同类型如对话、说明文的文章，学生需根据这些文章的内容回答不同题型的问题，包括选择题和句子填空），考试时间为20分钟，试题数量为20-25题。</p><p>■口语（包括各种会话，例如就熟悉或不熟悉的话题来回答问题，就某个题目作简短的陈述和对话。这项考试旨在考核学生所掌握的词汇量和语法的广度、深度和准确性，口语流利程度以及发音。口语考试一般需要录音），考试时间为10-15分钟，试题数量为3-4题。</p><p>数学推理能力</p><p>下列年级的学生可以参加数学推理能力考试：</p><p>数学推理能力考试的所有试题都是选择题。监考人可用学生的母语解释考试注意事项。学生参加这类考试时可使用计算器和词典。这些辅助工具在英语水平考试时不能带进考场。</p><p>综合能力</p><p>综合能力考试不受英语语言的限制。考试大约需30分钟。这是一项非语言类的推理选择题考试，他能反映学生的综合能力水平。监考人可用学生的母语解释考试注意事项。</p><p>AEAS考试评估报告提供以下信息：</p><p>■英语水平考试各单元的考试分数和英语水平考试总分。</p><p>■建议学习英语强化课程的时间长度。</p><p>■综合能力和数学推理能力考试的原始分数和标准化分数。</p><p>■建议入读澳大利亚学校哪个年级。</p><p>澳大利亚AEAS总部出具考试评估报告，副本将寄送到：所申请的学校，申请人以及中介代理（如果在注册考试时委托了中介代理机构）。</p><p>英语水平考试的评估结果还可以直接交给澳大利亚政府，以协助评审签证申请。</p><p>学生必须在www.aeas.com.au网站报名考试。</p><p>学生根据AEAS网站所列信息选择考试地点和日期，学生必须填写注册考试的详情。一旦注册，将收到电子邮件通知把考试费用汇到指定的银行帐号。将银行出具的付款收据传真到GRAYPERKINS律师事务所，付款得到确认后，将另发电子邮件再确认所注册的考试日期和考点。如果在考试当天缺席或者在距考试14天之内取消考试，考试费将不退还。</p><p>考生参加考试需携带：4张护照照片，学校成绩单原件和2份复印件（须提供英文翻译件），护照或其他身份证件的原件和2分复印件。</p>'),
    (61,61,'<p>2009年，雅思成绩提高得比较明显的是澳洲院校。比如澳洲蒙纳士大学，从以前的6.5分提升到7分；墨尔本大学商学院将提高其研究生课程入学的雅思要求，在原要求的基础上，要求学生加考GMAT，且需达550分以上。2008年尽管美国院校对雅思成绩的承认度大大提升，然而对雅思的要求并没有降低，申请美国前50名大学、前100名的大学的雅思要求并无降低，申请前者大学，无论是本科或研究生，一般需雅思成绩6.5分以上，而申请后者大学，则需雅思6分。</p><p>此外，据了解，一些主流留学国的热门专业的雅思要求也不低，比如英国的法律、语言学、心理学和教育学等，这些专业对写作和阅读这两项的要求较高，并且规定单项不能低于6分。而澳洲研究类硕士如翻译、传媒和护理等专业，基本上澳洲所有的院校对这几个专业的语言要求普遍较高，雅思成绩要求为7&mdash;7.5分。</p>'),
    (62,62,'<p>日前，来自澳大利亚6大城市的15所顶级中学来到广州，参加了由广东侨谊举办的澳大利亚中学教育展。留学费用、语言考试、住宿以及在当地读完高中后如何考大学成为家长们咨询的热点问题。留学顾问建议，去澳大利亚读中学，不妨先参加澳大利亚教育评估服务机构组织的英语水平考试AEAS考试，该考试被称为&ldquo;中学生的雅思&rdquo;，已经有相当数量的中学获得澳大利亚政府的批准，允许招收完成AEAS考试评估的学生，而且该考试分数越高，越有可能申请到好的中学。</p><p>据广东侨谊的留学顾问介绍，作为澳大利亚政府唯一指定的除雅思以外的国际学生中学入学考试，AEAS考试主要考查学生在英语、数学推理和非语文综合三方面的能力，内容包括面试、聆听及笔试。它比雅思更有优势：专门针对中学生而设，笔试题目难度适中。面试环节是与考官进行口语交流，而不是雅思考试中的主题演讲，考生会更加放松。此外，许多学校都把AEAS考试结果作为制定学生语言课程长短的标准，澳大利亚政府规定，学生的AEAS成绩在36分以上61分以下的，需要再读30周以下的英语预备课程；成绩在61分以上的，则无需就读英语预备课程。</p><p>据了解，AEAS考试已经在中国设立了考点，广州作为全国定点考场之一，每月会组织一次统考。</p>'),
    (63,63,'<p>随着新托福难度增加但认可范围的缩小，雅思考试成为越来越多准备出国人员的不二选择。据相关统计2007年雅思考试参加人数比2006年增长了50%，以往天津每月1场的考试现在已增加到平均每月2场，考生仍需要提前3-4个月报名才能获得考位。据英国文化处官方消息，2008年雅思考试将在阅读方面加入商务英语文章，以提高考试的学术色彩。</p><p>半分制拔高低分</p><p>年内雅思最引人注目的改革即为写作、口语引入半分制。教育专家表示，总体上看，半分制的引入使雅思整体考评系统更加细化和科学，而半年来的实践也证明该项改革对于中国学生是一个利好。</p><p>据介绍，改革对成绩稍差的学生是件好事，但是成绩好的学生可能稍有吃亏。&ldquo;以往5-6分的学生，如果考到5分多一点，现在很可能被提高到5.5分，但是6.5-7分的考生，如果成绩不到7可能还会被下降到6.5分，她表示，&ldquo;宽待低分，控制高分是雅思评分的特点。但是半分制无疑给了更多中国学生出国的机会，国外大学一般要求雅思最低5分，考改后原来5分左右的考生普遍可以达到5.5分，在申请学校和签证时就会具备更多的优势。&rdquo;</p><p>观点表达是软肋</p><p>对于中国学生来说，写作和口语是丢分的主要科目，长期以来对阅读、词汇、语法的重点关注使考生普遍缺乏表达独立观点的能力，而雅思考官在口语、写作等主观题目的考查上重视的恰是观点是否独特，视野是否开阔。例如谈&ldquo;网上购物&rdquo;的话题，很少有考生能以实际例子说明自己的观点，而实际上一旦有考生举出实例则会获得很高的分数。</p><p>专家指出，在雅思考试中，独特的观点是中国学生普遍匮乏的，应考者可以多关注discovery、国家地理、世界地理等全英文的节目和读物，在开阔眼界的同时学习用全球化的角度思考问题，有了这些积累在考试的时候才能从细小处打动考官。</p>'),
    (64,64,'<p>2008~2009年雅思考试政策有不少变化本报特邀专家进行解读</p><p>回眸2008年</p><p>2008中国雅思年会即将在11月拉开帷幕，我们特别走访了本次年会的主讲嘉宾之一的房挺老师，邀请房老师就2008年全年的雅思考试情况进行权威分析。</p><p>考生人数再次井喷</p><p>近年来，中国大陆地区的IELTS考生人数逐年递增。据雅思官方数据，2007年中国大陆雅思考生人数总体增加了57%，其中学术类增加幅度为64%。虽然2008年尚未结束，但从雅思考试(包括加考)的频次增加、考点的增设、考位的紧缺程度和留学及雅思培训市场的火爆，不难推测出今年的雅思考生人数增长幅度至少在三成以上，达到破纪录的25万~30万人，成为名副其实的国内第一大出国类英语语言考试。</p><p>考生低龄愈演愈烈</p><p>在雅思考试的考场、在雅思培训学校的教室里，在各类展会的雅思现场咨询点前，越来越多地看到一张张稚气未脱的面孔。他们是被称作&ldquo;小小烤鸭&rdquo;的特殊群体。据官方统计，18~22岁的雅思考生已经成为了中国大陆雅思考生最庞大的群体，其中18岁以下的考生，大多为高中生，人数增长的幅度最大，2007年达到了74.83%(学术类)，预计2008年仍会保持可观的增幅。</p><p>美国认可雅思成绩</p><p>在很多人的传统观念里，雅思成绩就是为了申请英联邦国家的学校或者移民时适用，如果要去美国，一定要考托福。但实际上，雅思成绩在美国的认可程度已经相当高。截至2008年10月，已有超过1800所的美国大专院校及专业机构认可雅思成绩。根据雅思主办方的权威统计(截至2008年8月)，在US New &amp;World Report公布的美国排名前130位的院校中，其中115所院校接受IELTS成绩，占总数的88.5%；在前五十位院校中有47所接受IELTS成绩，占94%。朗阁海外考试研究中心的专家建议一些希望留美的学生，在托福报名报不上的时候，不妨尝试使用雅思成绩进行申请。</p><p>口语发音评分变化</p><p>2008年受很多考生和雅思业内人士所关心的一条新闻就是&ldquo;雅思考试口语发音评分量表变化&rdquo;这一消息。口语本身就是中国考生的弱项，评分标准的变化更是引起了一部分考生的紧张情绪，相互间流传着诸如&ldquo;口语考试变难了&rdquo;、&ldquo;考官变严格了&rdquo;之类的小道消息。</p><p>事实上，本次变化并没有对考试的形式、难度和考官的评判方式产生任何影响。官方的解释很到位：&ldquo;整个发音评分量表和评分标准都不会受任何影响。口语考试的结构及形式也没有任何变化。唯一的变化就是此量表更精确地反映考生的发音水平。&rdquo;</p><p>多所国内院校加入雅思全球认可系统</p><p>2008年国内多所着名高校首次加入雅思全球认可系统，加入此系统意味着该院校将和其他国际知名院校一起向世界范围内更多莘莘学子敞开大门。</p><p>据悉，在雅思官方网站的全球认可系统搜索引擎中，可以寻找到已加入GRS系统的中国高校名称。</p><p>最新发布：</p><p>明年雅思将安排47次考试</p><p>雅思明年考试安排日前公布，全年共安排47次考试。考生即日起可报名。</p><p>据了解，明年雅思考试将在全国28个城市的30个考点进行，其中包括9个周四考试日期以满足考生的不同需求。</p><p>北京、上海、南京等考生数量众多的城市，平均每月将举行3~5场考试。在大多数考点，例如广州、合肥、大连等，每月平均2场的考试安排可满足考点周边的考试需求。</p><p>雅思考试主办方表示，将密切关注市场的需求和变化，采取不同措施使考生的报名等待时间降至最低。</p><p>写作和口语易栽跟头 10月出题热点预测</p><p>备受&ldquo;烤鸭&rdquo;们关注的9月雅思考试&ldquo;变题热议&rdquo;答案揭晓，9月考题比8月稍有变化，但主要难倒考生的还是写作和口语两项。如何提高这两项的成绩，已经成为通过新一轮雅思考试，完成海外留学心愿的一个关键性问题。</p><p>9月13日进行的雅思考试大作文为环保类，小作文为柱状和饼状图。写此类作文的考生应抓住&ldquo;极点&rdquo;、&ldquo;比较&rdquo;和&ldquo;趋势&rdquo;3点来展开话题。</p><p>而预计10月份雅思写作则是，大作文：媒体类、科技类、社会发展类。小作文：曲线图、表格。口语方面，从综合口语考试的总体情况和学生考后反馈，可以看出最近几个月虽有几个新出现的口语话题(比如说：法律、厨师等)，但还是没有超出课堂上讲到的解题思路，只是在旧的题型框架上有小小变形，&ldquo;烤鸭们&rdquo;大可不必有如临大敌的感觉。</p><p>另外一条要注意的就是：考生要注意在整个口试三个部分中保持&ldquo;水平的稳定性&rdquo;，因为有些学生只注重一、二部分的话题准备，到第三部分就哑口无言了。考官往往最反感背诵死答案时很流利，对于没有背到答案的题回答时就语无伦次、断断续续，反差很大。学生在回答问题时，要把自己想表达的信息连贯、有逻辑并准确地表达出来，这样才能相对拿到一个比较好的分数。</p>'),
    (65,65,'<p>今年，恰逢雅思(IELTS)考试在中国迎来自己二十周岁生日，对雅思考试来说，其在中国的发展已日臻成熟、并迅速成长为值得依赖的国际性英语考试。正如英国文化协会考试部中国业务总监史哲明所言，&ldquo;去年，全球有超过一百二十万考生参加了雅思考试，其中两成多为中国考生，总数超过二十六万人。中国学生保证了雅思作为全球英语(论坛)考试领头羊的地位。&rdquo;</p><p>随着在中国参加雅思(IELTS)考试的人数逐年迅猛增长，我们有必要对雅思考试做一些了解，回顾21世纪的今天，毋庸置疑，雅思成绩已被世界上40多所国家所认可。</p><p>雅思(IELTS)全称：国际英语语言测试系统(International English LanguageTestingSystem)，它是由&ldquo;剑桥大学测试中心、英国文化委员会和澳大利亚高校国际开发署&rdquo;共同管理。与托福考试一样，雅思(IELTS)也是一门国际英语水平的测试。</p><p>此项考试是为申请赴英联邦国家(英国、澳大利亚、加拿大、新西兰等)留学、培训的非英语国家学生必须通过的英语考试，以此来评定考生运用英语的能力。现在许多英联邦国家对申请本国技术移民的人士也采用这项考试，作为申请人英语能力达标的认证。目前，在美国，它也越来越受到欢迎。</p><p>因此，雅思(IELTS)考试得到了广泛的国际认可，据统计，每年在世界各地有近百万人次参加IELTS考试。</p><p>那么，雅思考试具体情况如何呢？由于目的不同，雅思考试现分为学术A类和培训G类两种。它包括四个部分组成，依次为听力、阅读、写作和口语，也就是说，简而概括为听、读、写、说四部分。</p><p>其中，A类和G类的听力和口语使用相同的试题，阅读和写作使用不同试题。雅思听力、阅读、写作一般在周六上午进行，雅思口语一般安排在周六下午和周日全天。在考试时间上共2小时45分钟。每一部分都独立评分，四部分得分的平均分作为考生的雅思综合得分(小数部分取舍到最近的一分或半分，即如果平均分为6.125分，雅思得分算作6分)。</p><p>因为在中国，据有关本年度第一季度的统计数据显示，今年中国雅思考生数量，还可能呈现比较强劲的增长。而且从中国参加雅思(IETLS)的实际情况来看，雅思考试大部分的增长都是学术类考生数量的增长。</p><p>这意味着，中国学生对雅思A类考试的需求显著增长。去年，在中国参加雅思A类考试的考生中，据统计，近六成年龄处在19岁&mdash;25之间，且大部分为考虑出国学习硕士课程的学生。</p><p>针对中国参加雅思A类考生数量显著上升的趋势，故对雅思A类考试的评分做进一步介绍。雅思A类考试分为听、说、读、写四部分，每部分各为9分。譬如，对雅思A类听力考试的评分标准，答对17-18道，得4分，答对19-21道，得4.5分，以此类推，答对37-38道，得8.5分，答对39-40道，得9分。</p><p>再比如，对雅思A类口语的评分标准，依据流利度与连贯性、词汇资源、语法结构的范围和准确性及发音的不同进行评分，例如，如若能够得到满分9分，则第一，发言时极少有重复或自我更正，偶尔停顿也是由于在思考内容，而非搜寻合适的词汇和语法；发言连贯，语言中上下文流畅，联系自然而充分，全面而得体的围绕话题展开发言。</p><p>第二，面对任何话题都能灵活、准确的使用词汇；自然、准确的使用习语。第三，在语法结构上，自然准确的使用多样语法结构，语法结构的使用自始至终保持准确，虽然偶尔犯一些英语为母语者也会犯的&ldquo;口误&rdquo;。因此，对于雅思口语，那些能够获得雅思口语高分的中国学生，是通过自己不懈努力、付出更多辛勤汗水才得来的。</p><p>上述介绍，只是对雅思A类考试成绩的评分标准简单叙述一二。而学生在参加完考试之后，自然关心考试成绩，雅思(IETLS)考试成绩从考试结束后第一天算起，10个工作日，也就是两周可以出成绩。</p><p>目前，雅思考试在中国设有的固定考点，在北京和上海每月举办一次，其它地区2-3个月举办一次。由于中国对外交流的迅速发展，北京的考试每月通常增加一次。法定的提前2星期报名，现在也需要提前1&mdash;2个月报名。</p><p>另外，关于雅思(IETLS)考试，从学生长远的角度，在中国除了留学必考外，在如今21世纪人才竞争储备上，雅思考试因其听、说、读、写具有较强提高应用语言的能力特点，对中国学生在国内就业、英语充电也有益处，如果学生想要全面提升英语水平的能力，不妨也多了解一下，即使不参加考试，试着去做一些往年雅思(IETLS)考试的各类题型。</p><p>当然，这只是一点建议，学生应结合自身实际状况审慎为妥。特别说明的是，由于各方面情况的不断调整与变化，现提供的所有雅思考试信息仅供参考，如果学生们想详细了解，请以权威部门公布的正式信息为准。</p>'),
    (66,66,'<p>在北京召开的IELTS记者招待会上，IELTS考试专家透露了IELTS考试2008年的中国发展计划以及全球发展趋势，并回顾了IELTS考试在中国所取得的成就。</p><p>中国拥有世界上人数最多的IELTS考生，这个数字还在不断增长。在过去一年中，全球IELTS考生将近100万人，而中国的IELTS考生数量超过了20万。作为一项衡量考生英语交流能力的可靠指标，IELTS考试得到了全球6,000多家机构的认可，这其中包括超过1,800所美国高等教育机构。</p><p>在此次会议上，来自IELTS全球合作伙伴的决策者们透露了IELTS未来的主要发展趋势，并表达了将IELTS不断创新与发展的决心。这些IELTS专家包括英国文化协会(在中国大陆作为英国使领馆文化教育处运作)全球英语教学及考试业务总裁Bhaskar Chakravarti(柴世杰)、IDP澳大利亚教育国际开发署总裁Tony Pollock、剑桥大学考试委员会ESOL考试部总裁Mike Milanovic和英国文化协会考试部中国业务总监James Shipton(史哲明)。</p><p>IELTS考试未来发展趋势包括：</p><p>通过聘用来自美国的命题团队以确保IELTS考试内容的国际化。除了在新西兰、澳大利亚和英国的专业团队之外，现在美国也设立了专业命题团队，提供高质量的考试材料。此举强化了IELTS考试的全球认可度，同时可最大程度上减少文化和语言的差异性。</p><p>开发IELTS机考(CB-IELTS)将使考生可以在纸笔考试的基础上多一个选择。通过对部分考生的调研，IELTS专家发现考生对纸笔考试和机考各有倾向，那些偏爱机考的考生将可以选择这种考试形式。与其他通过互联网进行测试的考试相比，IELTS的机考有一个重要优势，即试题是在考试前通过互联网下载下来的，可确保其安全性。然后考生在线下答题，这样可以保证考生的发挥不受网络连接问题的影响。 IELTS考试将在中国开设更多的考点，以进一步缩短中国考生的报名排队时间，同时也满足不断增长的考试需求。</p><p>2007年IELTS在中国开设了三个新的考点，分别是在北京和上海开设的第二考点以及在太原开设的新考点。为满足华东地区对IELTS考试不断增长的需求，2008年该地区将计划开设新的考点。</p><p>英国文化协会考试部中国业务总监James Shipton(史哲明)说：</p><p>&ldquo;IELTS考试目前是世界领先的英语语言考试，这一考试帮助考生在全世界范围内接受教育和实现就业，从而切实改变其生活。&rdquo;</p><p>&ldquo;IELTS考试因其高质量的考试内容而受到广泛认可，在中国享有极高的声誉。我们与合作伙伴密切合作，努力保持考试的高水准，并满足不断增长的考试需求，同时也确保考生的报名排队时间比以前有所缩短。&rdquo;</p><p>美国大学对IELTS考试的认可度提高近三成</p><p>(2008-5-26)2008年的前5个月，认可并接受IELTS考试成绩的美国大学从1400家增加到1800家，美国学术机构对IELTS的认可度持续大幅提高。</p><p>新增加的院校和之前已经认可IELTS成绩的常春藤盟校(例如哈佛大学、耶鲁大学和普林斯顿大学)一样，都将IELTS考试成绩作为评测国际学生英语能力的可靠标准。新增院校包括密西西比大学(University of Mississippi)、乔治亚州立大学(Georgia State University)和肯特州立大学(Kent State University)等等。</p><p>作为一项稳定可靠的衡量指标，IELTS考试成绩能够真实地反映出申请者用英语进行沟通和交流的能力。在这1800个美国学校里，几乎全部常春藤盟校都认可IELTS成绩。并且，根据美国《新闻与世界报道》杂志的2007年&ldquo;最佳院校&rdquo;排行榜，美国排行前50名的院校中有90%以上都认可IELTS成绩。IELTS成绩也在美国招收国际学生最多的前10所大学中获得了高度认可。</p><p>前往美国就读的学生对IELTS考试的信心也在迅速增长。从中国寄往美国的IELTS考试成绩单的数量增长可以印证这一点，这一数字增长在135%以上，占寄往国外大学全部成绩单的30%。</p><p>获得IELTS高分的学生在申请美国大学和奖学金的时候具有更强的竞争力。</p><p>正在美国宾厄姆顿大学读书的都岚岚说：&ldquo;我是清华大学的一名博士研究生，在2006年10月14日的IELTS考试中，我获得了7.5分的高分。凭借这个成绩，我申请了美国&lsquo;富布莱特项目&rsquo;主办的联合培养博士生子项目，从24名候选人中脱颖而出。IELTS考试的题型设计以实际应用为目的，能够反映考试者真实的英语水平。我真的非常感谢IELTS考试，它为我带来了重大的机遇和个人发展空间。&rdquo;</p><p>被乔治亚大学录取并获得了奖学金和学费减免的程心瑛说：&ldquo;我选择参加IELTS考试的主要原因是因为IELTS考查英语交流所必需的四个技能。另外，在中国，申请IELTS考试的程序非常简便快捷，而且有多个考试时间来供考生选择。&rdquo;</p><p>中国拥有全世界最多的IELTS考生，而且这个数字还在不断增加中。去年有超过20万考生在中国参加了IELTS考试，而全球参加IELTS考试的人数则将近100万。</p><p>IELTS考试是由英国文化协会(在中国大陆作为英国使/领馆文化教育处运作)、澳大利亚教育国际开发署(IDP)和英国剑桥大学ESOL考试委员会共同主办的。英国文化协会考试部中国业务总监James Shipton(史哲明)说：&ldquo;IELTS考试因其高质量而享誉全球。我们做的一切努力都是为了确保考生们可以信赖IELTS考试，并通过IELTS考试成绩获得学习和就业上的机会。&rdquo;&ldquo;我们的工作通过世界一流学术机构的认可得到了回报，这些学校都认可IELTS成绩，认为其在考察英语交流能力方面是一个安全可靠的指标。&rdquo;&ldquo;IELTS考试打开了通往世界的大门。&rdquo;</p><p>2007年考生数直逼百万IELTS再度领跑全球</p><p>全球考生数翻番，中国考试规模全球第一</p><p>全球备受认可的&ldquo;国际英语语言测试系统&rdquo;&mdash;&mdash;IELTS考试，近年呈持续火爆趋势。据考试主办方英国大使馆文化教育处透露，2007年IELTS考生数再度出现井喷，全球约有93.8万考生参加考试，较三年前数量上翻了一番，距离百万大关仅咫尺之遥。中国作为IELTS考试的主要生源地，亦呈现强劲增长势头。全年共逾21万人参加考试，较06年同比增长近60%，创下历史新高。无论在中国或全球IELTS都已当仁不让稳坐出国英语考试头把交椅。</p><p>赴美学生报考IELTS成为强劲增长动力</p><p>IELTS考试被普遍认为是出国留学及移民的人士的首选，在68个国家的逾6000政府机构和院校得到广泛使用。近年IELTS考试的适用范围更突破英联邦国家范畴，获得美国约1800所院校和机构的认可，其中包括哈佛大学、麻省理工学院、哥伦比亚大学和普林斯顿大学等名校。07年持IELTS成绩赴美考生人数是06年的近三倍。大量赴美学生转而报考IELTS成了07年IELTS增长的强劲动力之一。究其原因，IELTS考试美国执行总监贝瑞&middot;梅隆女士认为她&ldquo;在与美国院校和政府部门的交流中发现他们普遍认为IELTS考试能准确评测考生的英语听、说、读、写能力，这为他们评估学生和移民英语素质提供了可靠的依据。从而越来越多的美国机构希望看到申请人提交IELTS成绩。&rdquo;</p><p>报名压力有所缓解，提前报名仍有必要</p><p>IELTS考试需求骤增一度对考试报名造成较大压力，考试主办方采取了诸多措施以缓解报名紧张情况，比如在现有考点加大考场容量，增加考试次数，增设新考点以及出台反&ldquo;黄牛&rdquo;政策等。2008年的考试日期将从07年的33个增加到47个，而考点由以前的27个增至30个，考试场次增加了75场，考试名额倒卖现象也已得到有效遏制。尽管目前IELTS报名压力得到缓解，英国大使馆文化教育处官员仍强烈建议广大考生早作计划，尽快确定考试日期，以免陷入被动。</p><p>杭州新增IELTS临时考点，哈尔滨/长春/乌鲁木齐和太原增加一场考试</p><p>鉴于华东区广大考生对IELTS考试急剧增加的需求，英国文化协会(在华东地区作为英国总领事馆文化教育处运作)和中国教育部考试中心共同决定在杭州新增浙江省教育考试院保俶北路考场作为IELTS考点，力求能有效缓解考生在暑期报考IELTS考试的需求，缩短考生排队报考的时间。</p><p>该临时新增的考点将于2008年7月12日起开考，近日已经开始接受考生报名，共提供9场IELTS考试(具体考试时间见下表)。新考场笔试地点位于杭州保俶北路92号浙江工商大学9号楼，口试地点位于文晖路321号浙江教育大厦。除7月24日考试的口试安排在7月19日至21日进行之外，其余考试的口试安排在笔试之后的周一至周三进行。</p><p>另外，哈尔滨和长春考点在7月12日加考一场，乌鲁木齐考点在7月26日加考一场，太原考点在8月21日加考一场。更多信息请查询报名网站http://ielts.etest.net.cn和www.britishcouncil.org.cn 。</p><p>IELTS将推出计算机化测试</p><p>为了适应新形势的需要，雅思考试将推出计算机化(CB-IELTS)测试。通过对部分考生的调研，IELTS专家发现考生对纸笔考试和机考各有倾向。未来纸笔测试与计算机化测试将会同时存在。开发IELTS机考将使考生可以在纸笔考试的基础上多一个选择,那些偏爱机考的考生将可以选择这种考试形式。与其他通过互联网进行测试的考试相比，IELTS机考有一个重要优势，即试题是在考试前通过互联网下载下来的，可确保其安全性。然后考生在线下答题，这样可以保证考生的发挥不受网络连接问题的影响。IELTS口语考试会继续保持考官面对面与考生交流的形式。</p><p>IELTS口语考试发音评估量表细化</p><p>IELTS口语考试有四个评分标准：流利程度和连贯性、词汇量、语法结构及精确度、发音。现行的口试评分中，对于发音的评分，考官根据9级发音评分量表给出2分、4分、6分、8分四种评分结果。IELTS拥有方所做的持续的市场调研结果显示，考官为发音评分时，应涵盖9级发音评分量表中的1到9级九个等级，这样的评分结果会更精确地反映考生发音水平。此发音评估量表将于2008年8月开始实施。</p><p>整个发音评分量表和评分标准都不会受任何影响。口语考试的结构及形式也没有任何变化。唯一的变化就是此量表更精确地反映考生的发音水平。IELTS拥有方通过全面深入的测试，广泛听取了考官及考官培训人员的建议，才决定把评分结果由原来的四个等级细化为九个等级。</p><p>英国移民系统近日认可IELTS考试作为主要英语语言考试</p><p>IELTS现被英国最新的&ldquo;计分制&rdquo;移民系统认可。自2008年2月底起，英国内政部开始对非欧盟国家实施一个新的计分制移民系统。作为移民申请程序中的一个环节，申请者需要提供其英语语言水平的证明。移民申请者在系统中被分为五个&ldquo;级别&rdquo;，其中针对第一级别，即最高技能级别的移民者，如医生、科学工作者和企业家等，按照现在英国政府的规定，IELTS 6.5分及6.5分以上均符合移民申请的语言要求。该要求相当于&ldquo;欧洲语言学习、教学、评量共同参考架构(CEFR) &rdquo;的C1级别。这个新规定将取代现有的英国高新技术移民条例(HSMP)之相关规定。</p><p>IELTS考试在英语国家高校录取要求、新的移民政策以及专业认证需求增长的促进下，报名数在过去的三年中翻了一番。2007年全球考生更接近100万。英国文化协会首席执行官Martin Davidson说：</p><p>&ldquo;我们非常荣幸IELTS考试能够获得英国最新的&ldquo;计分制&rdquo;移民系统的认可，同时我们也很高兴看到2007年全球的IELTS考生数量激增至近百万。无疑，IELTS考试已经成为全球主要的国际英语语言考试之一。现在，英国文化协会在101个国家和地区提供约400个考场以服务考生、满足考生的需要。&rdquo;</p>'),
    (67,67,'<p>这句话听起来好像很耳熟，但又不完全正确，没错！上帝为你关上一扇门，一定会为你打开一扇窗是原版，但经过这次小转折后，觉得上面的这句话更能体现出我此时此刻的心情。</p><p>经过高考淤血奋战后，未能如我所愿考入理想专业的本科院校，或许这就是梦想与现实的差距吧，不能也更是无法逃避的事实，只有面对！转瞬即逝的三年大学生活接近尾声，做出重大决定&mdash;&mdash;出国深造。</p><p>现在不知是否有着跟我一样际遇的同龄人都在干些什么？！找一份普通的工作？还是继续上学？临近毕业，越是迷茫，一只迷途的羔羊，不知何去何从？</p><p>20几岁年轻人，正是你积攒财富的年龄，如果一旦走上工作岗位，恐怕学习对你来讲纯属力不从心了。上帝为你关上一扇门&mdash;&mdash;没能进入期盼理想的大学，但我们不能放弃心中的梦想、要有信仰。相信还有很多其他的机会在等待我们。这里行不通，能不能换个地方？正是为了让自己独自打开一扇明亮且充满未来希望的窗，随便换个视角，就可能会发现还有其他的道路等着你去走，自己创造的窗才是最好的。</p><p>出国这条路是我自己选的，专科生们不知道你们有什么样的打算呢，至少现在我只是想把我的感受写出来与大家一起分享，顺其自然的是找中介咨询相关事宜，意外的从网上看到四达中介留学，觉得还不错，在这里我很放心，因为这里的咨询顾问都是颇有经验，俗话说就是：针对不同人的境况做出不同的留学计划，当然也会尊重个人意见为主流，综合来讲都是以换位思考的角度来做这项工作，更多的像我这样专科毕业的学生，正在为今后的道路犹豫不决、他们都能给予你一个对未来发展很好的前景规划，不管你最后下决心是否出国否，都是在将心比心的为我们勾画今后未来美好憧憬。之前我个人来咨询出过事宜，很是担心自己学历文凭，也对出国的事情不是很有信心，在四达我的顾问吕老师一直在强调对自己充满信心、你肯定没问题，在未来的学习中提出了很多的参考性意见，对个人前途发展很有影响，吕老师也详尽的对我要所学的专业进行简单描述，做到心里有数。不要再没有任何准备下就出去。无论是身体还是心理上都必须做好吃苦准备，我想这就是四达留学中介服务的不同之处吧。</p><p>不能排除专科生出去读个本科在国外很好找工作，并且还想移民在国外有个绿卡，但是这毕竟不是出国的最终目的，而是能让自己更有竞争力，哪怕是到时回国发展也不失为一种很好的锻炼，既开阔眼界也增强了自身的社会知识、以及独自生存的能力。</p><p>一个事物都有它的两面性、利与弊的权衡，看你是那一部分占的大多数，我应该就是属于更深层次需要完善自我，走上留学道路，不管前面等待我的是否光明或是黑暗也好，人生短暂，还是希望大家能勇敢而坚定的向前迈出一步吧！</p><p>在此，有着跟我一样的朋友们不妨可以准备着为自己量身定做一扇崭新的窗，或许你该感谢上帝关门的同时，让我们有了凸显另一面的机会等待释放我们青春、富有激情阳光的日子！</p>'),
    (68,68,'<p>获取学生签证的十五岁以上的外国学生经父母许可可在澳洲兼职工作。学生在读书期间每周最多可以工作20小时；假期可以全日工作(每周约35小时)。但是外国海外学生必须向移民和多元文化事务部提出工作申请，并在抵澳开始学业后才能工作。学生申请工作的费用是55澳元。学生家属工作的权利有所不同（研究生家属打工不受每周20小时限制），因课程长短而异，但要到当地移民部申请兼职学生签证。</p><p>雇主们十分重视工作经验，所以鼓励学生在澳大利亚学习期间工作。即便工作与学习内容不直接相关，也会为学生提供有益的经验，比如提高交际能力和增加责任感。这些兼职工作经验也有助于外国学生结交朋友，加深对澳大利亚的认识。但学生必须确保自己的学业不会受兼职工作的影晌，也不应把兼职工作视作其在澳大利亚上学的主要经济来源。</p><p>外国学生如果把业余工作做为经济收入的主要或唯一来源，那会是一个冒险，很多时候也会得不偿失。我们建议学生在留学之初先不要工作，等第一学期结束后再决定怎样工作才不影响自己的学习。</p><p>如何找工作</p><p>许多高等院校学生服务部都会帮助学生找工作或提供如何找工作、填写申请和支付费用的信息；学生也可以通过报纸或中介机构找到工作。当然，也可以通过网络。网络的优点是便捷，快速，省时省钱。政府有一个关于全国雇佣服务的工作网，该网提供各种行业的雇佣情况。</p><p>雇主们在决定是否雇佣之前，要先看求职者的简历。其中包括工作经历和学历，以及个人联系信息。这会使雇主了解求职者的个人背景与能力。学生可以会在图书馆找到许多关于如何写简历的书籍和信息。</p><p>如果求职者的简历足以打动雇主，雇主会通知面试。面试给求职者提供了一次展示自己的机会，求职者也应争取通过这个机会让老板决定雇佣你。学校的就业中心咨询顾问或是职业介绍所会给学生提供一些面试技巧指导.</p><p>收入</p><p>在零售业或服务业打工，一个学生每小时可以赚大约8到16澳元，但也因其所在城市和工作类型的不同而有差异(不满19岁的学生被认为是青少年，收入会略少一点)。基本上，在悉尼打工平均每小时收入在10-15澳元之间；在墨尔本为8-12澳元；而布理斯班为6-10澳元左右。每一行业均有固定的规定，雇主必须遵守。多数情况下，雇主会把钱打入雇员的制定帐户，雇员因而必须交税；也有很多雇主为了逃税或省去不必要的麻烦会直接给现金支付现金（特别是在很多华人餐馆）。所以提醒大家在找工作之前，都要把这些情况问清楚，以免吃亏。</p><p>不管如何，学生不应把兼职工作视为自己在澳大利亚上学的主要经济来源而荒废了学业。</p>'),
    (69,69,'<p>澳大利亚中学体制来说，虽然也是一个学年分为两个Semester(学期)，但这个学期的概念在当地人的心中非常模糊或者说几乎没有，他们主要是说Term(学期)。然而此学期(Term)非彼学期(Semester)，一个大学期(Semester)由两个小学期(Term)组成。换句话说，澳大利亚中学学期设置里面一个大学期包括有两个小学期，一个学年总共就有了四个小学期。</p><p>不同于国内一般是9月份新学年开学，澳洲中学新学年一般是1月份开学，结束于12月份，学制安排正好跟自然年略有相同。四个小学期(Term)的开学时间分别为：一月份，四月份，七月份和九月份。第一个和第二个Term之间，第二个和第三个Term之间，第三个和第四个Term之间分别有两周的假期。其中第一个和第二个Term、第三个和第四个Term之间的两周假期叫StudyBreak(学习假期)；而第二个和第三个Term之间的两个星期假期称为寒假；第四个Term和来年第一个Term之间有两个月的长假，这个假期就是暑假了。如果国内的学生和家长对他们寒暑假的日期有疑惑，请别忘了，澳大利亚是南半球国家，寒暑假跟我们正好相反。　</p><p>会不会有人开始觉着澳大利亚的中学生很轻松？学习两个月就有两周假期，加上正常的周六周日休息，一年下来可以放的假可真不少？的确如此。因为升学的考核标准不同于国内的中高考模式加上灵活的选课制度，他们既可以轻松愉快的选择自己喜欢的课程学习，也完全没有那么大的升学压力(澳大利亚中学选修制、评估制等教育制度，接下来的几期再和大家详聊)。两个Term之间的两周假期，学生是不必去学校的。有的学生会利用这段假期来温习前面一个Term所学的内容，再预习接下来一个Term的课本；也有一些学生会利用这段假期出去旅游放松一下，领略一下国外的美好风光，接触一下校外的风土人情，增长一些学校里所没有的见识。</p>'),
    (70,70,'<p>对于初次来到澳洲的中国学生来说，住宿一直是家长和学生相对比较关注的问题。对于海外学生来说，澳洲的住宿大致可以分为，住宿家庭，学校公寓和校外合租3种，但是对于刚刚踏上澳洲国土，对身边的环境还非常陌生的中国学生来说，一般住宿家庭和学校公寓会他们首先会考虑的。然而，既然有住宿家庭和学校公寓两种选择，那学生到底应该选择哪一种才适合自己呢?</p><p>&nbsp;</p><p>住宿家庭是澳大利亚政府对于海外留学生专门提供的一种最Local化的住宿方式，其目的在于帮助学生在最短的时间内接触并了解澳洲的学习和生活方式。通过每天和住宿家庭的家庭成员的沟通，学生的语言和对澳洲生活的了解都会有显著的提高。虽然住宿家庭对所有的海外学生开放，但是并不是所有的学生都适合选择这样的住宿方式。一般来说，年龄未满18周岁的小留学生或刚刚国内高中毕业的学生最适合住宿家庭的选择，其原因有三：</p><p>1、此类学生年龄比较小，在生活和学习上还没有完全的独立，很多事情需要在第三方的监管和帮助下才可以完成，所以这时候的住宿家庭就起到了监护和指导的作用。</p><p>2、这些学生的英语水平相对来说比较弱，但是语言的学习和适应能力却比较强，所以住宿家庭的全英语环境非常适合这些留学生的语言能力的提高。</p><p>3、对于中国的传统观念，孩子越小，家长越担心，那住宿家庭就替国内的家长解决的后顾之忧。而且，澳洲的住宿家庭每年都要经过当地警察局严格的审核，所以对于这些家庭的背景条件及提供的服务，中国的家长可以完全放心的。</p><p>除了以上说到的这些小留学生，还有很多中国学生会选择本科，硕士或其他一些课程。一般来看这些学生已经成年并具备了独立生活的能力，所以在住宿的选择上面，他们更适合学校的学生公寓，其原因也有三：</p><p>1、相对来说，学生公寓的管理不会像住宿家庭来的那么严格，成年学生不会感觉到拘束。而且由于学生公寓里住着来自世界各地和澳洲当地的学生，这样的环境对中国学生结交朋友，融入当地的文化非常有利。</p><p>2、往往学生公寓都坐落在学校里，所以学生可以非常方便来去教室和宿舍之间，甚至连交通费也省了不少。</p><p>3、学生公寓一般都是不包餐的（有些是包餐的，价格会贵一些），所以学生需要自己解决吃的问题。好在公寓里都设有厨房和各种炊具，所以这样的环境下，学生的独立生活能力在短时间内也会有显著的提高。</p>'),
    (71,71,'<p>澳洲寄宿家庭（Homestay）的定义是澳大利亚的家庭向国际学生开放，接受海外学生成为他们的家庭成员。海外学生可和这个家庭成员一起吃、住、购物、郊游，参加该家庭的各种活动。寄宿家庭服务是适应于澳洲教育输出，接受外国留学生来澳所应运而生的。这不仅给海外学生营造了一个良好的语言环境，同时为学生了解异地文化、历史、风俗习惯创造了良好的环境和机会。更重要的是这些家庭为学生们提供了安全舒适、友好的居住环境。家庭式的帮助及生活上的照顾，也提供了那些未满18岁的海外学生监护及相关法律保护，使得他们有更多的机会融入西方社会，更快适应新的生活环境。</p><p>&nbsp;</p><p>在澳洲，并非每一个家庭都可提供这种住宿家庭服务的。可以提供这种住宿家庭服务的一般必须为澳洲本地居民，受过良好的教育、没有犯罪记录、没有不良嗜好、身体健康、诚心接受外国学生成为自己家庭的一员，无任何种族歧视意识。作为寄宿家庭的成员，政府每三个月要进行一次检查。同时，也必须受相关法律的监督。</p><p>初次入住寄宿家庭的海外学生一般会被要求先付4周的住宿费。住满两周后必须决定4周满后是否继续住宿。如果是，则应在第三周开始时再付两周住宿费。决定离开的时候，必须提前两周通知主人。</p><p>寄宿家庭的收费包括住宿、水电费及周一至周五一般提供早、晚餐，周末提供早、午、晚三餐的费用。对于未满18岁的学生，寄宿家庭也提供周一至周五的午餐，这类午餐一般以三明治和水果为主。如果你的寄宿家庭不提供午餐的，学生就需自己解决午餐，或是要求寄宿家庭增加此项服务，不过，寄宿费用会有增加。同时，寄宿家庭提供洗衣机、冰箱、电视及各类家电设备的免费使用，电话、上网的使用是要收费的，关于电话和上网的使用，在入住后要和你的寄宿家庭详细讨论付费和电话计算方法。由于牵涉长途电话费用较高的问题，因此，有些寄宿家庭不提供电话和上网的使用，但容许学生自己安装电话和网络，需自用自付。</p><p>作为一个中国留学生千万不要忘记自己的言行举止代表着你的国家，代表着你的民族，代表你个人的文化素养。千万不要认为你付钱给住宿家庭就应当享有一切，也千万不要认为住宿家庭的成员就是你的奴仆。我们提醒申请住宿家庭的留学生注意以下几点：</p><ol><li>入住到西方家庭，是一个体验西方生活的机会，家里的成员会非常友好，寄宿家庭的父母也把学生作为自己的孩子看待，要尽量与他们融洽生活，不要将自己关在房中，拒绝和他们交流和攀谈。更不要因为自己的英语较差而不理不睬房东。</li><li>要有礼貌，主动打招呼，早、晚问Good morning 和 Good night。做错事要说Sorry, 对为你服务的人要多说Thank you，学会说Please。不要打断别人的讲话，必须打断时要说excuse me，这是一个很好的锻炼讲英语的机会，同时也表现出我们是既礼貌又文明的学生。</li><li>务必保持个人房间、卫生间的整洁，特别是在使用完洗浴设备或便器设备后，一定要将周围的水渍和污渍清理干净。千万记住必须在使用完便器设备后放水冲洗。个人用品和衣物要放进专用的壁橱或衣柜里。向房东了解每周的房间清洁安排，弄清楚是由房东打扫清洁还是你自己收拾。用家里的东西要先打招呼，用后记得还，并要告诉主人。如果卧室里有暖气机，睡觉时间和不在房间的时候请不要打开。只可在晚上学习时使用。由于澳洲气候的原因，不是每家居民都有空调设备的。</li><li>刚吃西餐时会不习惯，与国内的西餐大不一样，要尽量去适应，如有吃不惯或吃不饱的情况可主动告诉你的寄宿家庭。吃饭时不要将盘碗弄出声音，不要将饭掉到桌上。吃饭要文明，不要有喝汤和咀嚼的声音。</li><li>每天吃过饭要主动将自己的盘碗收到厨房的水池中。可能会要求你分担家务例如洗碗、上菜、收拾餐桌等，这在澳大利亚人的家庭里是很常见的，也是练习英语的好机会。</li><li>去卫生间洗澡时，时间不要过长，以免影响他人使用。澳洲是个缺水的国家，请记住节约用水和随手关灯。</li><li>如果你要外出，请一定告知寄宿家庭有关你的去向，如果你未满18岁，且你的寄宿家庭是你的监护人的话，你的外出必须征得他们的同意，因为，他们对你承担法律保护的责任。如果外出回来较晚或夜宿不归的话，务必告知你的寄宿家庭，这在澳洲是基本的礼貌和责任。</li><li>如果你邀请你的同学或朋友来家里玩，你必须事先征得寄宿家庭的同意，根据西方人的习惯，不是每个寄宿家庭都同意的。如果寄宿家庭同意，你的同学或朋友来访不得超过寄宿家庭正常的作息时间。你独自晚上看电视或听音乐要注意音量和时间，以不影响寄宿家庭和隔壁邻居的休息为重要前提。</li></ol>'),
    (72,72,'<p>澳大利亚的生活基本用品不是很贵，因此根据个人情况，有选择的携带即可。对于学生来说，可多带休闲装。同时，最好携带一些和中国不同的东西，比如三眼电源转换插座、个人护理护肤用品和电脑用的网线电话线等。此外建议学生可以带些当地的邮票和明信片，作为礼物既不会太贵重、又比较有特色。</p><p>1、行李携带</p><p>澳大利亚的生活基本用品不是很贵，因此根据个人情况，有选择的携带即可。对于学生来说，可多带休闲装。同时，最好携带一些和中国不同的东西，比如三眼电源转换插座、个人护理护肤用品和电脑用的网线电话线等。此外建议学生可以带些当地的邮票和明信片，作为礼物既不会太贵重、又比较有特色。</p><p>2、住宿</p><p>(1)寄宿家庭：东西方人生活习惯不同，建议学生应该尽量尊重房东习惯，什么事情都先询问再行动，尽量不要晚归。中国学生刚到可能会对肉类食品感到不习惯。(2)住校：学校宿舍的管理不会太严，普遍是独立卧室，公共设施通常是合用的，距离基本都是靠近学校或者购物中心，不过价格相对较贵。</p><p>3、英语学习除了语言中心学习的内容，学生仍需寻找机会多听多练，参加教会在学校组织的每周活动是一种方式。西方人的教会活动可以帮助了解当地社会。此外，还可以参加学校中本地学生和国际学生的交流项目。</p><p>4、经济带澳元到澳洲是最为方便的，当地大部分银行不能存美金，部分银行则可以兑换，但手续费较高。St。George银行和中行的汇率较低。学生如果需要开账户存款最好选择在校内的银行，较为方便，如果申请学生账户，可以免手续费、利息税等。一般每5000澳元为一个利率分界，建议学生存款一定要看清利息。国外电汇很便宜，没有钞转汇的问题。</p><p>5、交通情况澳大利亚的公交汽车或者火车都是按照时刻表运行的，时刻表在车站、学校都可以免费领取。可以通过网站查寻所有车次航班。不过周末车次很少，建议买车票可以买10次票，周票、联票会比较优惠。值得提醒的是，国际学生非移民没有折扣，如果逃票被发现会被罚款并且记录到签证记录中。此外，建议在乘火车时，可避开每个地区高峰时段，因为非高峰时段票价折扣可近50%。</p><p>6、医疗保险学生所交的医疗保险费用，可保证学习期间免费治疗感冒等小病，但其他药均不免费，看牙病和眼病不仅不属于医疗保险，而且费用很贵。因此在出国前，可以自备一点日常药物，特别是夏天防蚊虫叮咬的药。</p><p>7、手机通讯可以选择不同公司的签约合同，总有公司有免费时间优惠。一般选择当地的手机卡，免费服务较多。澳洲每个城市都有多种国际长途电话卡，而且经常变换费率，价格最低时，打回中国的电话费在每分钟0.01澳元左右。</p>'),
    (73,73,'<p><img src=\"../../picture/20130809160647.jpg\" alt=\"\" width=\"600\" /></p><p>堪培拉, 澳大利亚的首都, 联邦政府各级分支机构的聚集地, 请看它的电子导游图</p><p><a href=\"http://www.australiaeguide.com.au/travel-guides/canberra-travel-guide.pdf\" target=\"_blank\">http://www.australiaeguide.com.au/travel-guides/canberra-travel-guide.pdf</a></p><p>&nbsp;</p><p>布理斯班, 昆士兰的首府, 以温暖宜人的气候闻名的现代化城市, 请看它的电子导游图</p><p><a href=\"http://www.australiaeguide.com.au/travel-guides/Brisbane-Travel-Guide.pdf\" target=\"_blank\">http://www.australiaeguide.com.au/travel-guides/Brisbane-Travel-Guide.pdf</a></p><p>&nbsp;</p><p>黄金海岸, 世界一级的旅游城市, 昆士兰最著名的游览胜地, 请看它的电子导游图</p><p><a href=\"http://www.australiaeguide.com.au/travel-guides/gold-coast-travel-guide.pdf\" target=\"_blank\">http://www.australiaeguide.com.au/travel-guides/gold-coast-travel-guide.pdf</a></p>'),
    (74,74,'<p><iframe src=\"https://www.youtube.com/embed/8ZkGd-IVVTc\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p><p>中国留学生在澳大利亚注册入学人数已近20万，是澳大利亚最大的留学生群体。如今澳大利亚已遍布中国留学生的脚印。本期《留学这些事》从两代中国留学生的讲述里，我们可以了解更多澳洲留学环境的变化和时代的变迁。</p><p>如果您不能观看来自YouTube视频，请点击这里观看：<a href=\"http://v.youku.com/v_show/id_XNTUyMTg4MjY0.html\" target=\"_blank\">《留学这些事》：两代留学生谈澳洲生活体验</a></p>'),
    (75,75,'<p><strong>澳大利亚商业投资移民</strong><strong> 188</strong><strong>签证申请评分标准</strong></p><p>&nbsp;</p><table border=\"1\"><tbody><tr><td><p><strong>家庭资产</strong></p></td><td><p>　</p></td><td><p><strong>年龄</strong></p></td><td><p>　</p></td></tr><tr><td><p>过去2年80万澳元以上</p></td><td><p>5</p></td><td><p>18-24</p></td><td><p>20</p></td></tr><tr><td><p>过去2年130万澳元以上</p></td><td><p>15</p></td><td><p>25-32</p></td><td><p>30</p></td></tr><tr><td><p>过去2年180万澳元以上</p></td><td><p>25</p></td><td><p>33-39</p></td><td><p>25</p></td></tr><tr><td><p>过去2年225万澳元以上</p></td><td><p>35</p></td><td><p>40-44</p></td><td><p>20</p></td></tr><tr><td><p>　</p></td><td><p>　</p></td><td><p>45-54</p></td><td><p>15</p></td></tr><tr><td><p><strong>生意背景（仅创新生意类）</strong></p></td><td><p>　</p></td><td><p><strong>投资背景（仅投资类）</strong></p></td><td><p>　</p></td></tr><tr><td><p>超过4年生意经验</p></td><td><p>10</p></td><td><p>超过4年投资经验投资</p></td><td><p>10</p></td></tr><tr><td><p>超过7年生意经验</p></td><td><p>15</p></td><td><p>超过7年投资经验投资</p></td><td><p>15</p></td></tr><tr><td><p><strong>公司营业额</strong><strong>(</strong><strong>过去</strong><strong>4</strong><strong>年</strong><strong>)</strong></p></td><td><p>　</p></td><td><p><strong>语言</strong></p></td><td><p>　</p></td></tr><tr><td><p>有2年超过50万澳元/年</p></td><td><p>5</p></td><td><p>　</p></td><td><p>　</p></td></tr><tr><td><p>有2年超过100万澳元/年</p></td><td><p>15</p></td><td><p>IELTS 每门5分</p></td><td><p>5</p></td></tr><tr><td><p>有2年超过150万澳元/年</p></td><td><p>25</p></td><td><p>IELTS 每门7分</p></td><td><p>10</p></td></tr><tr><td><p>有2年超过200万澳元/年</p></td><td><p>35</p></td><td><p>　</p></td><td><p>　</p></td></tr><tr><td><p><strong>学历</strong></p></td><td><p>　</p></td><td><p><strong>创新能力</strong></p></td><td><p>　</p></td></tr><tr><td><p>　</p></td><td><p>　</p></td><td><p>1年以上注册专利/设计</p></td><td><p>15</p></td></tr><tr><td><p>澳洲证书/大专/学士</p></td><td><p>5</p></td><td><p>1年以上注册商标</p></td><td><p>10</p></td></tr><tr><td><p>海外学士</p></td><td><p>5</p></td><td><p>1年以上正式的联营公司</p></td><td><p>5</p></td></tr><tr><td><p>澳洲/海外学士(商科/科学/技术专业)</p></td><td><p>10</p></td><td><p>4年有2年出口占销售50%</p></td><td><p>15</p></td></tr><tr><td><p>　</p></td><td><p>　</p></td><td><p>州政府认可特别贡献</p></td><td><p>10</p></td></tr><tr><td><p>　</p></td><td><p>　</p></td><td><p>过去4年有被政府奖励1万澳元（新公司/产品市场化/生意拓展）或吸引风投超过10万澳元</p></td><td><p>10</p><p>&nbsp;</p></td></tr><tr><td><p>　</p></td><td><p>　</p></td><td><p>公司成立不超过5年，连续3年销售额每年增长超过20%，最少有1年雇员超过10人</p></td><td><p>10</p></td></tr></tbody></table><p><strong>评分细节：</strong></p><ul><li><strong>年龄</strong></li></ul><ol><li>主申请人的年龄分，是按邀请信下发时的年龄来计算。</li><li>如果主申请人年龄在55岁以上(含55岁)，那么除非申请人的生意能为州经济带来特殊经济利益（Exceptional economic interest），否则将无法通过创新测试。</li></ol><ul><li><strong>英语能力</strong></li></ul><ol><li>雅思成绩中各单项均达到5分以上的申请人会被认为具有基本的职业英语能力，可以得到5分。</li><li>雅思成绩中各单项均达到7分以上的申请人会被认为具有熟练英语能力，可以得到10分。</li></ol><ul><li><strong>学历资格</strong></li></ul><ol><li>在澳洲教育机构取得本科文凭（Bachelor degree）、学位文凭（Diploma）或从业资格证书（Trade Qualification）的申请人可以得到5分。澳洲教育部认可的他国教育机构的本科文凭也可以加分。</li><li>在澳洲教育机构取得商科类(Business)、技术类(Technology)或科学类（Science）的本科学位证书（Bachelor degree）可以加10分。澳洲教育部认可的他国教育机构的本科文凭也可以加分。</li></ol><ul><li><strong>商业和投资经验</strong></li></ul><ol><li>申请人若能证明曾在一定时间内（specified amount of time）专注于某商业或投资领域，拥有一定经验，则会获得加分。但是所具有的商业经验必须和签证材料内的商业工作有相关性。也就是说，申请&ldquo;商业创新类别&rdquo;的投资者不会因为具有&ldquo;投资经验&rdquo;而获得加分，反之亦然。</li></ol><ul><li><strong>个人和公司净资产</strong></li></ul><ol><li>所有申请人的净资产都必须达到规定要求，否则无法申请。商业创新类别申请人必须至少拥有800,000澳元的个人和公司净资产。投资类别申请人必须至少拥有2,250,000澳元的个人和公司净资产</li><li>达到上述最低标准即可加分。同时净资产显著高于最低标准更可能获得额外加分。</li></ol><ul><li><strong>营业额</strong></li></ul><ol><li>对于&ldquo;商业创新类别&rdquo;申请者来说，他们的生意至少要达到500,000澳元的年营业额。但是对&ldquo;投资类别&rdquo;申请者没有要求。</li><li>任何一个类别的申请人，若其生意能够达到某个指定的营业额（须至少在过去四个财年中达到两次），则可以获得加分。</li></ol><ul><li><strong>创新能力</strong></li></ul><p>以下几个类别规定了具体的加分条件。同时达到多个类别加分条件的申请人可以多次重复加分，但每个类别只能加分一次。</p><ol><li>注册专利或注册设计（15分）</li></ol><p>条件：符合&ldquo;注册专利&rdquo;或&ldquo;注册设计&rdquo;的定义。注册时间不能太接近签证邀请下发的时间（至少1年以上），申请人须证明它们确实一直被用于主要的日常商业运营。</p><ol><li>注册商标（10分）</li></ol><p>符合&ldquo;注册商标&rdquo;的定义，注册时间不能太接近签证邀请下发的时间（至少1年以上），申请人须证明它们确实一直被用于主要的日常商业运营。</p><ol><li>合资协议（5分）</li></ol><p>符合&ldquo;合资协议&rdquo;的定义。申请人需要证明是生意主要股东，并以公司高层身份直接参与了日常管理。签证邀请下发前的1年内的形成的合资协议不被移民局承认。</p><ol><li>出口贸易（15分）</li></ol><p>申请人需要证明自己是出口生意主要股东，并且50%以上的营业额源于出口贸易（过去4个财年内至少要2次达到这一要求）。</p><ol><li>高速发展（10分）</li></ol><p>新近成立（注册时间小于5年），并在短时期内高速发展（20%年营业额增长率，至少维持3个财年）的生意有可能得到加分。同时需要雇佣10名以上全职员工（至少维持3个财年）。</p><ol><li>因商业创新得到政府资金担保或其他风险投资（10分）</li></ol><p>首先，申请人必须是生意早期起步、产品商业化以及生意扩张的功勋人物。在签证邀请下发的过去4年内，申请人若得到来自母国政府机构超过10000澳元以上的资金担保，则可以获得加分。在签证邀请下发的过去4年内，得到过来自风险投资机构100,000澳元以上的资助也可以获得加分。</p><ul><li><strong>特殊情况</strong></li></ul><p>在很少数情况下州或领地政府认定申请人具有重要价值，这种情况下直接加10分。</p><p>&nbsp;</p><p><strong>额外说明：</strong></p><p><strong>&nbsp;</strong>虽然新的188商业创新及投资移民对申请人的要求有了一定幅度的提高，根据新的打分系统需达到65分的及格线，且在SkillSelect技术甄选系统中提交EOI才能获得被邀请的可能。但是，条件越优秀，获得的分数也就越高，排名自然也就越靠前，就可以优先获得邀请。新政策下的计分系统不但会考虑申请人个人及商业的净资产、企业营业额等指标，更会针对申请人的年龄，学历，英语水平等分别计分，同时会根据一些特定因素进行评分，如经商经营和技术贡献/专利等。具体打分项目共7项类别，单项可以是0分，其中包括年龄、英语、学历、管理经验、资产、公司营业额、创新能力。其中特别值得注意的就是最后一个类别&ldquo;创新能力&rdquo;，其中可以加分的具体项目包括，拥有注册专利或注册设计，可以加15分（分数等值于企业年营业额达到100万）；拥有注册商标可以加10分（分数等值于英语雅思达到每一项7分）；拥有合资协议可以加5分（分数等值于英语雅思达到每一项5分）；拥有出口贸易生意可以加15分；成立时间在5年内且处于高速发展的企业可以加10分；最后，因商业创新得到政府资金担保或其他风险投资的可以加10分。</p><p>新的商业移民政策非常鼓励创新能力，这无疑对于那些拥有注册专利，商标的企业主而言是一大契机，因此这次的变革也可以说是一场移民&ldquo;大筛选&rdquo;。大浪淘沙之下，对于部分条件甚好，占尽优势的申请人而言，优胜劣汰并非坏事。门槛的提升自然会引发申请数量的下降，申请数量少了，速度自然也会提升，等待获批的那一天也更快了。</p>'),
    (76,76,'<p><span style=\"font-size: 11px;\">&nbsp;2012年5月25日，澳洲移民局宣布了商业移民新政的整体框架，政府彻底改革了现有的商业技术签证项目，将其重新命名为&ldquo;商业创新与投资&rdquo;项目，并对其指导纲要进行修改。原先13类商业移民项目合并为3类，而之前颇受国内同胞青睐的163转892商业移民正式退出历史舞台，为新的188转888签证类别所替代，新的商业移民政策已从2012年7月1日起正式施行。</span></p><p><strong>这个新的方案由三部分组成：</strong></p><p><strong>188商业创新和投资签证（四年临时</strong><strong>签证</strong><strong>）：分创新，投资，巨额投资者三类</strong></p><p><strong>888商业创新和投资签证（永居签证）：分创新，投资，巨额投资者三类</strong></p><p><strong>132杰出商业人士签证（永居签证）：分</strong><strong>显著商业背景类和风险投资企业家类</strong></p><p>&nbsp;</p><p><strong>一)&nbsp;&nbsp;&nbsp; </strong><strong>188</strong><strong>商业创新，投资，巨额投资签证（四年临时</strong><strong>签证</strong><strong>）</strong></p><ul><li><strong>188</strong><strong>商业创新类移民签证</strong></li></ul><p>188商业创新类签证（类似于原澳洲163商业投资移民签证）。此签证申请对审计要求相对较松、注重公司的营业额，对投资金额要求不高，投资方式可灵活变通。尤其适合：中、小型企业主、大型企业管理者。</p><p>188商业创新类移民申请条件：</p><ol><li><strong>向商业甄选系统提交意向书，并获得邀请函</strong></li><li><strong>取得州</strong><strong>/</strong><strong>地方政府担保</strong></li><li><strong>年龄</strong><strong>55</strong><strong>岁以下，除了能给州</strong><strong>/</strong><strong>地方带来特殊经济效益的申请人得到豁免的除外</strong></li><li>个人净资产<strong>，要求申请人（与配偶加起来）拥有合计澳币</strong><strong>80</strong><strong>万以上（约等于</strong><strong>RMB560</strong><strong>万元）</strong></li><li><strong>公司营业额，要求过去的四年中申请人的企业（最多可以两个企业加起来计算）年营业额达到</strong><strong>50</strong><strong>万元澳币以上（约等于</strong><strong>RMB350</strong><strong>万元）</strong></li><li><strong>申请人持由企业股份：年营业额为</strong><strong>40</strong><strong>万澳币以上，要求申请人持由企业股份</strong><strong>30%;</strong><strong>年营业额为</strong><strong>40</strong><strong>万澳币以下，要求申请人持由企业股份</strong><strong>51%</strong><strong>；若该企业为上市公司，申请人持企业股份</strong><strong>10%</strong><strong>即可。</strong></li><li>公司净资产<strong>，要求在过去的四年中的两年，申请人（与配偶加起来）持有澳币</strong><strong>20</strong><strong>万元以上（约等于</strong><strong>RMB140</strong><strong>万元）</strong></li><li>申请人必须在&ldquo;创新打分测试&rdquo;中得到至少65分&nbsp;</li></ol><ul><li><strong>188</strong><strong>投资类移民签证</strong></li></ul><p>188投资类签证是专门为那些从事投资活动（如：股票、期货、基金、外汇等）的投资者而设立的一种四年期的临居签证（类似于原来的165商业投资移民签证）。要求申请人有突出的投资经历和经验，通过州政府担保，可选择将投资资金转到澳洲政府指定的债券持有四年，即可转永居。尤其适合：专业投资成功人士。</p><p>188投资类移民申请条件：</p><ol><li><strong>向商业甄选系统提交意向书，并获得邀请函</strong></li><li><strong>取得州</strong><strong>/</strong><strong>地方政府担保</strong></li><li><strong>年龄</strong><strong>55</strong><strong>岁以下，除了能给州</strong><strong>/</strong><strong>地方带来特殊经济效益的申请人得到豁免的除外</strong></li><li><strong>公司净资产，</strong><strong>1</strong><strong>）要求直接参与管理自己或配偶的投资且投资额达澳币</strong><strong>150</strong><strong>万元以上（约等于</strong><strong>RMB1050</strong><strong>万元）；</strong><strong>2</strong><strong>）满足持股要求，即年营业额为</strong><strong>40</strong><strong>万澳币以上，要求持股</strong><strong>30%</strong><strong>；年营业额为</strong><strong>40</strong><strong>万澳币以下，要求持股</strong><strong>51%</strong><strong>；上市公司持股</strong><strong>10%</strong><strong>。</strong></li><li><strong>个人</strong><strong>净资产，过去的两个财政年里，要求申请人（与配偶加起来）持续拥有合计澳币</strong><strong>225</strong><strong>万以上（约等于</strong><strong>RMB1575</strong><strong>万元）</strong></li><li><strong>进行指定投资，在签证批下来的时候申请人需完成政府指定的</strong><strong>150</strong><strong>万元澳币的投资。</strong></li><li><strong>商业或投资经验，申请人需要有至少三年直接管理企业或投资的经验，且该申请人从未涉及不合法或不被认可的商业行为</strong></li><li><strong>申请人持续商业行为的承诺，申请人承诺在政府指定投资期满以后仍持续操作生意或进行投资管理</strong></li><li>申请人必须在&ldquo;创新打分测试&rdquo;中得到至少65分</li></ol><p>&nbsp;</p><ul><li><strong>188</strong><strong>巨额投资者类移民签证（</strong><strong>500</strong><strong>万澳元投资）</strong></li></ul><p>188巨额投资者类移民申请条件：&nbsp;</p><ol><li><strong>向商业甄选系统提交意向书，并获得邀请函</strong></li><li><strong>取得州</strong><strong>/</strong><strong>地方政府担保</strong></li><li>没有年龄限制，没有英语要求，不需打分；</li><li>资金来源证明宽松，汇款要求宽松；</li><li>投资500万澳元到规定的投资产品；</li><li>签证下来后的四年里，主申请人累计在澳洲住满160天；</li></ol><p><strong>&nbsp;</strong>&nbsp;</p><p><strong>二)</strong><strong>888</strong><strong>商业创新，投资，巨额投资者签证（永居签证）</strong></p><ul><li><strong>888</strong><strong>商业创新类签证</strong></li></ul><p>888商业创新类移民申请条件：</p><ol><li><strong>申请人必须是过去</strong><strong>188</strong><strong>签证的主申请人，并且持有该签证在澳洲四年内累计居住满两</strong><strong>年</strong></li><li><strong>取得州</strong><strong>/</strong><strong>地方政府担</strong><strong>保</strong></li><li><strong>企业营业额及所有权，申请前</strong><strong>12</strong><strong>个月申请人应满足：</strong><strong>1</strong><strong>）申请人在澳洲的企业营业额达</strong><strong>30</strong><strong>澳币；</strong><strong>2</strong><strong>）申请人满足对企业的持股要求，即年营业额为</strong><strong>40</strong><strong>万澳币以上，要求持股</strong><strong>30%;</strong><strong>年营业额为</strong><strong>40</strong><strong>万澳币以下，要求持股</strong><strong>51%</strong><strong>；上市公司持股</strong><strong>10%</strong><strong>；</strong></li><li>以下3个条件满足2个：</li></ol><p>1)&nbsp; <strong>申请人与配偶在申请前</strong><strong>12</strong><strong>个月持续拥有澳洲企业净资产在</strong><strong>20</strong><strong>万元澳币以上</strong></p><p>2)&nbsp; <strong>个人净资产加上企业净资产，要求申请人与配偶在申请前</strong><strong>12</strong><strong>个月持续拥有</strong><strong>60</strong><strong>万元澳币以上</strong></p><p><strong>3)&nbsp; </strong><strong>雇佣要求，申请人申请前</strong><strong>12</strong><strong>个月应满足持续雇佣相当于</strong><strong>2</strong><strong>个全职的员工，员工不是您的家庭成员且是澳大利亚公民、澳大利亚永久居民、新西兰护照持有者。</strong>&nbsp;</p><ol><li><strong>申请人用作申请永居签证的企业，不能是曾经被其他人用作申请永居签证的企业</strong><strong>。</strong></li></ol><p><strong>&nbsp;</strong></p><ul><li><strong>888</strong><strong>投资类签证</strong></li></ul><p>888投资类移民申请条件：</p><ol><li><strong>申请人必须是过去</strong><strong>188</strong><strong>签证的主申请人，并且持有该签证在澳洲四年内累计居住满两年</strong></li><li><strong>取得州</strong><strong>/</strong><strong>地方政府担保</strong></li><li><strong>年龄</strong><strong>55</strong><strong>岁以下，除了能给州</strong><strong>/</strong><strong>地方带来特殊经济效益的申请人得到豁免的除外。</strong></li><li><strong>达到四年的指定投资期限，在签证获批之前，申请人（与配偶一同）满足政府指定持续投资</strong><strong>4</strong><strong>年的期限。</strong></li><li><strong>商业或投资经验，申请人从未涉及不合法或不被认可的商业行为</strong></li><li><strong>申请人持续商业行为的承诺，申请人承诺在政府指定投资期满以后仍持续操作生意或进行投资管理。</strong></li></ol><p>&nbsp;</p><ul><li><strong>888</strong><strong>巨额投资者类签证</strong></li></ul><p>188巨额投资者签证有效期四年，必须满足四年总共160天的居住要求。四年后转永居有2个选择：</p><ol><li>可以申请888绿卡。但拿到888绿卡后，就必须符合一般的绿卡居住要求，如5年中在澳洲住2年延续5年绿卡，或4年中在澳洲住3年拿澳洲护照。</li><li>可以续签2次，每次2年。每延长2年，需要额外多住80天。6年后或8年后，符合了居住要求，可随时转888绿卡。</li></ol><p>&nbsp;</p><p>888居额投资者类移民申请条件：</p><ol><li><strong>取得州</strong><strong>/</strong><strong>地方政府担保</strong></li><li><strong>在持有</strong><strong>188签证的期间，仍然保持在澳洲500万澳元的投资项目</strong></li><li><strong>持有</strong><strong>188签证四年以上，并满足居住要求</strong></li></ol><p>&nbsp;&nbsp;</p><p>三)<strong>132</strong><strong>杰出商业人士签证（永居签证）</strong></p><p>&nbsp;<strong>向商业甄选系统提交意向书，并获得邀请函</strong><strong>，</strong>但不需<strong>创新技能打分</strong>。新的132签证类别包含&ldquo;显著商业背景类&rdquo;（即旧的132商业天才移民）和&ldquo;风险投资企业家类&rdquo;。 &ldquo;显著商业背景类&rdquo;基本与原132签证类别条件基本保持不变，&ldquo;风险投资企业家类&rdquo;即需要企业家必须通过澳大利亚风险投资协会有限公司的一个成员在风险投资基金处至少筹集一百万澳币。该资金将为投资者提供早期启动资金或产品的商业化资金或经营发展及扩张的资金。该类别的具体细节尚未出台。</p><p>&nbsp;</p><ul><li><strong>132</strong><strong>显著商业背景类签证</strong></li></ul><p>132显著商业背景类移民申请条件：</p><ol><li>杰出的经商背景;</li></ol><ol start=\"2\"><li><strong>向商业甄选系统提交意向书，并获得邀请函</strong></li><li><strong>取得州</strong><strong>/</strong><strong>地方政府担保</strong></li><li><strong>年龄</strong><strong>55</strong><strong>岁以下，除了能给州</strong><strong>/</strong><strong>地方带来特殊经济效益的申请人得到豁免的除外</strong></li><li><strong>个人净资产，要求申请人（或与配偶一起）合法拥有</strong><strong>150</strong><strong>万澳币（约</strong><strong>RMB1050</strong><strong>万）以上净资产，并在被授予本签证后</strong><strong>2</strong><strong>年之内将该资产转移到澳洲。</strong></li><li>公司营业额，<strong>要求在过去的四年中的两年，申请人主要企业（或两个主要企业加起来）年营业额超过</strong><strong>300</strong><strong>万澳币（约</strong><strong>RMB2100</strong><strong>万）</strong></li><li>公司净资产<strong>，要求在过去的四年中的两年，申请人（与配偶加起来）持有澳币</strong><strong>40</strong><strong>万元以上（约等于</strong><strong>RMB280</strong><strong>万元）</strong></li><li><strong>公司持股要求，年营业额为</strong><strong>40</strong><strong>万澳币以上，要求持股</strong><strong>30%;</strong><strong>年营业额为</strong><strong>40</strong><strong>万澳币以下，要求持股</strong><strong>51%</strong><strong>；上市公司持股</strong><strong>10%</strong></li></ol><p>&nbsp;</p><p>虽然132类别的签证条件相对其他临时居留签证而言稍微偏高，但其优势明显，132商业天才人士签证有着它无与伦比的优势，在登陆澳洲的第一天拿到的就是绿卡。</p><p>&nbsp;</p>'),
    (77,77,'<table border=\"1\"><tbody><tr><td width=\"60\">&nbsp;</td><td><p><strong>188</strong><strong>（原</strong><strong>163A</strong><strong>）</strong></p><p><strong>商业创新签证</strong></p></td><td><p><strong>188</strong><strong>（原</strong><strong>165</strong><strong>）</strong></p><p><strong>投资签证</strong></p></td><td><p><strong>188</strong><strong>（新类别）</strong></p><p><strong>巨额投资签证</strong></p></td><td><p><strong>132</strong></p><p><strong>杰出商业人士签证</strong></p></td></tr><tr><td><p><strong>适用人群</strong></p></td><td><p>中小型企业主，准备在澳投资100万元澳币以下，主申请人可以在澳洲居住2年以上，并愿意打理一个生意。</p></td><td><p>专业投资成功人士。从事投资活动（如：股票、期货、基金、外汇等）的投资者。愿意投资150万元澳币在政府指定的项目，不愿在澳洲做小生意，但愿意4年内住2年。</p></td><td><p>有巨额资产的生意成功人士。愿意投资500万元澳币在政府指定的项目，不愿在澳洲做小生意，不愿意在澳洲常住。</p></td><td><p>大中型企业主，准备在澳投资150万元澳币以上，主申请人5年内可以在澳洲居住2年以上，并持续管理自己的投资。</p></td></tr><tr><td><p><strong>签证类别</strong></p></td><td><p>4年临居（可延签2年），2年后可申请永居</p></td><td><p>4年临居，4年后可申请永居</p></td><td><p>4年临居，4年后可申请永居</p></td><td><p>一步到位永居签证</p></td></tr><tr><td><p><strong>申请永居条件</strong></p></td><td><p>在澳做2年符合条件的生意</p></td><td><p>持有政府指定的投资项目4年</p></td><td><p>持有政府指定的投资项目4年</p></td><td><p>在澳有实质性投资</p></td></tr><tr><td><p><strong>在澳洲的居住要求</strong></p></td><td><p>申请永居前住满2年</p></td><td><p>申请永居前住满2年</p></td><td><p>4年中居住160天。可延签2次，每次2年。申请永居前住满2年</p></td><td><p>5年住满2年</p></td></tr><tr><td><p><strong>年龄</strong></p></td><td><p>55岁以下</p></td><td><p>55岁以下</p></td><td><p>无要求</p></td><td><p>55岁以下</p></td></tr><tr><td><p><strong>个人净资产</strong></p></td><td><p>80万元澳币</p></td><td><p>225万元澳币</p></td><td><p>无要求</p></td><td><p>150万元澳币</p></td></tr><tr><td><p><strong>公司营业额</strong></p></td><td><p>50万元澳币</p></td><td><p>150万元澳币（投资）</p></td><td><p>无要求</p></td><td><p>300万元澳币</p></td></tr><tr><td><p><strong>公司股份</strong></p></td><td><p>30%以上</p></td><td><p>10%以上</p></td><td><p>无要求</p></td><td><p>30%以上</p></td></tr><tr><td><p><strong>公司净资产</strong></p></td><td><p>20万元澳币</p></td><td><p>无要求</p></td><td><p>无要求</p></td><td><p>40万元澳币</p></td></tr><tr><td><p><strong>打分测试</strong></p></td><td><p>65分以上</p></td><td><p>65分以上</p></td><td><p>无要求</p></td><td><p>无要求</p></td></tr><tr><td><p><strong>获签证后在澳投资</strong></p></td><td><p>在澳资产60万元澳币，生意营业额30万元澳币</p></td><td><p>政府指定的项目（如债劵）150万元澳币</p></td><td><p>政府指定的项目（如债劵）500万元澳币</p></td><td><p>150万元澳币</p></td></tr></tbody></table><p>&nbsp;</p><p>&nbsp;<strong>注意：</strong>所有获得永居签证（绿卡）的移民，如果不入澳洲籍，就一直都要满足澳洲的居住时间（移民监）要求：5年之内要住够2年，如果少于2年，则必须符合&lsquo;与澳大利亚有紧密联系&rsquo;的条款，且只能申请有效期仅为一年的居民返回签证。</p><p><strong>澳大利亚入籍要求规定如下： </strong></p><ol><li>在申请澳大利亚入籍之前的4年中必须有澳州合法居住身份不少于 4 年，并且有至少 12 个月的永久居民身份。</li><li>并且，在这申请前的 4 年中离开澳大利亚的全部时间加起来最多不能超过 12 个月，同时在申请前 1 年的以永久居民身份居住的过程中离澳的时间不能超过 3 个月。</li></ol>'),
    (78,78,'<p>澳大利亚移民部长2012年8月29日公布了《巨额投资者类签证》详情，只要投资500万澳元，无论其年龄、英文如何，均可以申请澳洲188商业移民签证，4年以后满足居住条件，就可得到888永居签证。新签证从2012年11月24日起实施。</p><p><strong>申请人条件：</strong></p><ol><li>要求通过EOI投资意向申请</li><li>获得州政府的担保</li><li>投资至少500万澳元到符合规定的投资项目中</li></ol><p><strong>投资项目：</strong></p><p>可以投资澳大利亚证劵投资委员会（ASIC）授权管理的基金，或者非上市的正规注册和经营的公司。</p><p>投资澳大利亚证劵投资委员会（ASIC）授权管理的基金，包括：</p><ul><li>澳洲基建项目</li><li>澳洲银行存款</li><li>澳洲州政府，领地政府债券</li><li>澳洲上市公司发行的债券或资产</li><li>澳洲金融机构债券或定期存款</li><li>澳洲不动产物业</li><li>澳洲ASIC管理的基金</li></ul><p>投资非上市的正规注册和经营的公司</p><ul><li>生意必须符合资格，合法经营</li><li>申请人必须持有公司的股份</li><li>必须是澳洲注册的正规公司</li></ul><p><strong>居住要求：</strong></p><p>持有188签证的4年期间，投资人只要总计在澳洲居住160天，而且签证可以延签2次，一次2年。如果签证延期到6年，需要总计在澳洲居住240天，第二次延期到8年则为320天。</p>'),
    (79,79,'<p>对申请人来说，获得商业临时签证（如163签证）还只是获得永久居留成功的第一步。他们在获得临时签证抵达澳洲后，还会有大量事务性的事情需要操办，如购买房产，孩子入学，注册公司，寻找生意等。尽管有些申请人在澳洲有亲友，但总的来说，他们对澳洲的情况并不十分熟悉，在初期安排家庭生活和开展生意方面会存在很多困难。因此我们建议你首先要与经验移民代理讨论今后的发展计划，签好代理892的协议，然后在他们的指导下，尽快完成所有程序性内容，为今后的发展打下坚实的基础。</p><p>&nbsp;<strong>登陆澳洲</strong></p><p>商业临时签证获得者全家必须在签证规定的登陆期内到达澳洲，副申请人可同时或晚于主申请人抵达澳洲，但不能晚于规定的登陆期。临时签证有效期为四年，如果你不能在登陆期内登陆，签证将会失效。首次登陆澳洲，需要随身带好相关的个人文件，如护照，出生公证，孩子的学习证明，照片，准签信，英语培训费收据，驾照原件和公证件等。到澳洲后还要办理一些相关的证件和手续。</p><p>&nbsp;<strong>办理驾照</strong></p><p>在澳大利亚，年满16岁即可申请驾照。考试分为两步：首先通过交规考试（可使用中文试卷）取得&ldquo;学习驾照&rdquo;；然后上路学车，通过道路考核获得&ldquo;临时驾照&rdquo;。商业移民在抵达澳洲后的3个月内可使用中国驾照驾车。中国驾照因无英文，所以要在抵澳后，马上办理一份带英文翻译的驾照公证。为方便起见，建议尽快办理澳洲驾照。有中国驾照的商业移民只需参加理论笔试取得学习驾照，然后可直接参加路考，通过后就直接获得正式驾照（无须3年临时驾照！）。</p><p>&nbsp;<strong>银行开户</strong></p><p>在澳大利亚银行办理银行开户需要很重要的身份证明文件，如护照，驾照，同时还需要你有关住址的证明信等。澳洲人很少随身携带大量的现金，借记卡，信用卡和个人支票非常普及。澳洲的银行全国联网，可以在任何一个城市的任何一个代理处办理开户、存款、取款、汇款等手续。澳洲有些银行在中国的分行可以在赴澳前就协助你开好账户，这样可以先汇款过去，到澳洲就能使用。建议新移民申请和使用信用卡，积累信用为将来办理银行按揭打好基础。</p><p>&nbsp;<strong>申请个人税号（</strong><strong>TFN</strong><strong>）</strong></p><p>所有在澳洲有工作许可的人都应该申请一个税号，该号码通常为9位数，工作、报税、交税以及使用政府各项服务和申请福利时都会用到。税号可在第一次登陆后申请。申请人到税务局网上可当场申请。若你没有把税号提供给你的开户银行，银行就会因此协助税局从利息中扣除你的税。因此，将个人税号提供给银行是非常重要的。</p><p>&nbsp;<strong>优惠学生待遇</strong></p><p>商业投资移民的孩子享受优惠的学生待遇，包括学费减免等。各州对商业投资移民子女的待遇不尽相同！但这项优惠政策仅限于移民被担保州，若小孩在其它州读书，就要支付全额国际学生学费。公立中学按学区招生，因此可带小孩到就近的中学注册报名。若有空余名额，在简单考试后就能上学了。由于报名程序的原因，新移民必须在到澳洲后，有了固定的住所才能办理。若要就读私立学校、大学预科或大学，必须支付全额国际学生学费。由于不受学区限制，在中国就可办理报名手续，抵澳后就可上学。</p><p>&nbsp;<strong>医疗保险</strong></p><p>澳洲的医疗保健制度和服务体系优良。所有居民包括新移民都可以享受公费医疗。政府发给每人一张MEDICARE CARD（医疗卡），凭此卡可去医院或附近的诊所就诊。澳洲人习惯找固定的家庭医生或到就近的诊所就诊，这类医生被称为GP（全科医生），他们认为有必要时才推荐病人去看SPECIALIST（专科医生）。没有全科医生的推荐，专科医生一般不直接接收病人。病人去公立医院每次要凭医疗卡，否则要支付挂号费，购买药物需自己付费。</p><p>商业临时签证持有者无法享受公费医疗，因此必须购买私人医疗保险，转为永久居民后即享受免费医疗保险。医疗费用在澳洲是非常昂贵的，因此我们建议商业移民在拿到临时签证后，全家应立即购买医疗保险。</p><p>&nbsp;<strong>学习移民英语</strong></p><p>商业移民在抵达澳洲并安顿好之后，可报名参加专门为新移民举办的英语语言培训班(AMEP)，其学费已经在签证获得批准前支付给澳洲政府了，不用的话也不会获得退款。新移民最多可享受510个小时的免费英语学习。</p><p>&nbsp;<strong>注册公司</strong></p><p>在安顿好新生活后，绝大多数商业移民，特别是163签证持有人要面临投资生意的问题了。鉴于多数申请人转永居的急切心情，我们事务所会协助申请人尽快注册新公司，并通知担保州政府，在投资生意的过程中定期与州政府保持联系，以确保申请人顺利取得892担保。你在抵澳后必须与州政府联系。若改变你的投资计划，也必须通知州政府。在找到住所或搬家后，你必须填写922表以通知移民局。</p><p>&nbsp;</p>'),
    (80,80,'<p>&ldquo;机不可失，时不再来。&rdquo;首次700个发放移民指标，数量有限，很有可能一抢而空，因为很多潜在的申请人除来自中国大陆外，东南亚、印度、南美、俄罗斯和中国台湾的富商也十分感兴趣。&ldquo;先到先得，不能保证未来不会提高各种门槛，或许将不复存在也未可知。&rdquo;</p><p>&nbsp;</p><p><strong>签证申请条件很宽松：</strong></p><p>&nbsp;第一、没有年龄上限的要求（18岁以上）。其他商业移民的年龄上限是55岁，而如果申请重大投资者签证，即使你很年轻，一样也可申请。</p><p>第二、没有从商背景要求。许多有实力、有财力的投资人未必有过传统的从商经验，这就成为他们移民时的障碍，现在规定没有从商背景要求，正好满足他们的需要。</p><p>第三、没有英语水平要求。不要求英语水平，无疑对中国的移民开了&ldquo;恰到好处&rdquo;的绿灯。</p><p>第四、宽松的资金来源证明。移民局对&ldquo;重要投资者签证&rdquo;项目申请人的资金来源解释并未做出详细的规定，这就省了投资人在申请时要提供充分且复杂的资金来源证明等诸多麻烦，鼓励更多有财力和实力的人士投资移民澳大利亚。</p><p>&nbsp;</p><p><strong>申请流程已简化，审批更快速</strong></p><p>第一、在SkillSelect系统上提交意向书(EOI)，但无需打分；</p><p>第二、获得州或地区政府的担保/提名；</p><p>第三、在符合要求的投资类别中投资至少500万澳币。</p><p>&nbsp;</p><p>此外，因为没有积压个案的缘故，移民局对于这一类别申请的处理速度会很快，也就是投资者投资的金额愈多，审批的过程会愈容易。</p><p>投资方式可以灵活选择，安全系数高（投资有风险，选择要谨慎）</p><p>500万重要投资者签证项目的投资范围包括以下三类：</p><p>&nbsp;</p><p>第一、联邦，各州或各领地政府债券；</p><p>第二、澳大利亚股票和投资委员会（ASIC）监管及授权的在澳洲投资的基金；</p><p>第三、直接投资给非上市的澳大利亚私营/私人企业。</p><p>&nbsp;</p><p>该签证申请人的投资类别既可以跨越以上三个领域，也可以在它们之间变换，只要满足持续投资的要求即可，在满足各地区州政府要求的前提下，申请人可以自由选择、自主决策、合理安排自己的投资计划。</p><p>此外，500万的投资可以是政府债券或澳大利亚监管下的基金，以及非上市的澳大利亚私人企业，相对来说风险系数较小。</p><p>&nbsp;</p><p><strong>&ldquo;移民监&rdquo;时间缩短，方便照顾国内生意</strong></p><p>&nbsp;500万重要投资者签证转永居时，在澳居住时间只要满足：4年内住满160天。如果不想转永居，可以续签2次，每次2年。每延长2年，需要额外多住80天。</p><p>&nbsp;其他澳大利亚投资移民通常都要求临居签证的持有人在申请永居签证时，每年或者每两年在澳洲至少住满一半或以上的时间，也就是说一年中大部分时间都要待在澳大利亚。这对国内有生意的人士来说，确实不方便，现在时间缩短到160天，一年只要住上40天，方便照顾国内生意。</p>'),
    (81,81,'<p>踏上澳洲移民之路纯属一个偶然, 在中国工作创业的10多年,我从事的一直是比较前端的广告营销,市场推广新兴行业,随着业务的不断发展,感觉自己的事业慢慢达到了一个瓶颈状态,非常希望到海外获取一些新的发展平台以及新的创业思路.尤其是英语能力的提高. 在对澳洲进行了一系列的考察后,觉得澳洲是个非常适合工作和生活的国家,在这里可以吸取一些西方发达国家对于金融,市场及社会形态的优点,同时也在这里看到了商机, 结合中西方的优势,开拓新的市场将成为我后5年发展的一个主要目标.</p><p>在充分了解了澳洲小生意的模式后,我分析了自身的优劣,&nbsp; 优势在于首先我有国内创业的经验,其次年轻,单身没有家庭负担,有一定的英语基础,适应性强等.&nbsp; 在充分比较了各个行业的优劣性后, 我把可持续发展作为我在澳洲创业的主要目标, 无论什么生意一定要有可持续发展性, 另外也一定可以结合我在国内的生意模式和经验,只有这样才能发挥我的长处,在一个陌生的国度,最有效的开展自己新的一片发展空间.</p><p>在一个意外的机会下得知我目前从事的该旅行社由于原OWNER夫妇准备放弃澳洲的生活,去美国发展, 同时也由于前几年金融危机的关系,旅行社生意一直不好,已经进入的亏损状态,他们想找到合适的人选接手经营他们的生意.&nbsp; 在得知这个消息后,我马上非常感兴趣,一方面我自己非常喜欢旅游, 喜欢了解世界各地的文化风情, 另外对于旅游行业也不陌生,因为在我中国的生意中, 商务会展的安排,各大企业销售会议的组织, 全国商业活动的巡演等无不是和旅游组织相关联的, 对于其细节和流程我也是非常的清楚, 另外我也想到,如果我做旅游行业,还可以利用我在中国的社会资源,&nbsp; 发展新的销售平台. 在经过充分的考虑之后, 我和该公司负责人进行了磋商和洽谈, 了解到该公司目前的经营状况并不良好,除去负债以后,已经亏欠了员工的一些福利待遇等,从这方面看,该公司已经没有什么商业价值. 但是从另个角度来看, 改公司品牌在墨尔本当地已经有了15年的经营历史,它在澳洲各个旅游行业的SUPPLY中还是有一定的知名度,另外其原有的一些本地客户群体也有一定的累积. 经过几轮洽谈后,我终于说服该夫妇以收购其股份的形式接手了该公司, 并成为拥有其70%股权的经营人.</p><p>接手该公司后, 我和我的现有搭档决定用1年的时间首先对这个公司的经营模式进行过渡转化,由于该公司原来属于RETAIL的门店形式, 在澳洲目前的市场环境下, 华人机票市场低价竞争,已经没有太多的利润空间, 澳洲本地市场由于金融危机的后期影响以及猪流感的影响,市场购买力下降比率很高,什么时候可以恢复,? 后期有没有更多的自然灾害? 这些谁也无法预料,旅游行业受政治,人文,自然气候的影响是非常大的,因此公司业务范围的转型势在必然.&nbsp; 因此我们首先将租约到期的门店结束掉, 在CITY租了一个200平米大的办公室, 这么做的主要目的是为转型垫下基础,我们公司的未来2年将是是团队操作为主, 经营模式多样化为目标,利用旅游行业的平台逐步将公司转型为旅游相关行业的多种化经营模式, 只有这样才可实现利润化和风险最低化.</p><p>在搬家以后, 我和我的搭档很快达成共识,在业务上进行合理分工, 我主要负责中国团队入澳洲(inbound tour) 的业务发展和操作, 公司的日常行政管理, 公司的财务整合管理. 而他主要负责原有国际机票的管理以及未来开拓出境团( OUT BOUND)的发展. 在进行了业务分工后, 我马上开始熟悉公司的各项业务流程, 因为我知道作为一个合格的MANAGER,必须了解公司业务的每一个环节,随时可以成为各个岗位的支持人员. 因此我参加了机票业务操作的各项培训, 旅游行业管理人的培训( license),以及财务软件(MYOB),初级,中级及PAYROLL的各项培训. 并且很快熟悉并能熟练操作公司的各项业务. 另外,申请163VISA时我是提交了雅思成绩免去了英语的500小时培训课程, 为了更好的提高英语交流能力, 我利用晚上时间参加自费参加了英语提高培训.</p><p>公司搬家稳定后, 我开始拓展中国市场的业务, 经过一系列的努力,我联系到了北京王府国旅旗下专坐澳洲商务团队线的公司, 成为他们在澳洲市场上的唯一指定地接商, 负责澳洲境内的全线业务落实, 目前我们的INBOUND 业务量成为了公司主要的利润来源, INBOUND SALES总量由原先的10% 提高到了40%. 利润来源比率由原先的20% 提高到了90%. 团量由原来的每年10个团增加到现在每年将近150个团.</p><p>公司朝着理想的状态发展的越来越好, 可是在2010年的年底和2011年的年初,糟糕的事情发生了,首先是澳大利亚经历了百年未遇的洪水灾害, 昆士兰洲的旅游受到了很大的冲击,紧接着2011年春节期间, 凯恩斯又遭遇了巨大龙卷风灾害,我们许多入境团只能取消或者改变行程, 再接着日本发生巨大的海啸和核泄漏事故, 我们本地客人又纷纷取消了去日本的行程和机票,新西兰的基督城又发生了地震, 我们在这几个月的营业额,尤其是机票业务一下进入了亏损, 不过好在我们的业务转型已经初见成效, 虽然受到影响,但还是可以克服这些难关.</p><p>今年已经是我们公司新运营开始进入第三个年头了, 回顾前2年的努力,基本已经达到了我们的预期,虽然我们还没有做到公司的大盈利,但是稳妥的转型,打好基础是我们的基本目标.</p><p>从2012年开始,我们将着手于品牌竖立,和中国的合作伙伴联手打造澳洲最专业的商务地接公司.</p><p>同时也将发展澳洲本地最专业的商务咨询公司, 利用旅游平台, 结合中国商务考察团的需求, 积极开拓澳洲本地项目的开发,吸引中国投资.</p><p>&nbsp;另外最重要的是, 结合墨尔本展览中心每年的各个大型展览会, 我们将以此吸引更多的中国厂商和企业来澳洲参加展会, 将旅游参展一体化, 同时将结合参展企业的需求, 结合展会中所需要的展柜设计,制作, 参展单页的设计 ,印刷, 参展工作人员的配置等, 一条龙服务,力求成为墨尔本最专业的展会公司.</p><p>以上是本人从登陆澳洲以来的简单回顾, 即使在移民路上有多的困难,我还是很感激有这样的机会让我有如此的一个发展空间和平台, 非常有信心在澳洲继续我的个人生活和我的事业发展,期望我的努力也能为澳洲做出一份贡献.</p>'),
    (82,82,'<p>Regulation 1.03 - \"Settled\" to mean lawfully resident in Australia for a reasonable period</p><p>Good afternoon Migration Agents<br /> The following email has been received by me from the DIAC:<br /> Please find below response from Anne Vickers Acting Director, Family Section to a question raised by Liana Allan from Migration Alliance:</p><p><strong>Question:</strong><br /> I understand that at a recent MIA CPD , the manager of Contributory Parent Visa from Perth office had stated categorically that he would refuse all applications if the sponsor has not lived in Australia for the complete two years. I also understand several applications have been refused for failing to meet this \"two year\" \" SETTLED\" requirement . Unfortunately, this issue was not raised at the CPD session to challenge this narrow interpretation of the intention of the legislation and the policy guidelines. Agents have been advised individually to go to MRT by the CO when their non-adherence to legislation and policy guidelines are raised.</p><p><br /> The legislation and policy says: <br />Regulation 1.03 defines settled to mean \"lawfully resident in Australia for a reasonable period\".<br />\"Lawfully resident\" includes periods of lawful temporary residence.<br />Under policy, two years (as at time of visa application) is generally considered to be a \"reasonable period\". However, when assessing whether or not a person is \"settled\", each case is to be considered on an individual basis with regard given to the facts of the case, such as extended periods of temporary residence.</p><p><br />The above is the legislation and policy guidelines. Each case to be assessed on individual basis for assessing two year settled, anything else is ultra vires. The Manager\"s insistence with a cast iron approach of two years is obviously flawed. Unfortunately he was not challenged on the spot. I do not think the Perth Manager is going to be persuaded by any approach or submissions as he is stubbornly insisting on his way, contrary to what the legislation and PAM says. Taking the direction form the Manager case officers will stubbornly refuse to adhere to exercising their discretion lawfully than it has got to be brought to the powers that be, and MIA has the responsibility to undertake this. One does not wish to see MRT overloaded with cases where there is an apparent gross flaw at primary decision making level.</p><p><strong>Response:</strong></p><p>Legislative / Policy background</p><p>Under the Regulations, the applicant for a Parent visa must be the Parent of asettled Australian citizen, permanent resident or eligible New Zealand citizen.</p><p>Regulation 1.03 defines \"settled\" to mean \"lawfully resident in Australia for a reasonable period\". \"Lawfully resident\" includes periods of lawful temporary residence.</p><p>A reasonable period is not defined in the legislation, but under policy, is 2 years. Guidance on assessing this for Permanent Residents and eligible New Zealand citizens is covered in the PAM under paragraph 16.1, which says a reasonable period is 2 years, but \"when assessing whether or not a person is \"settled\", each case is to be considered on an individual basis with regard given to the facts of the case, such as extended periods of temporary residence.\" Further guidance is also provided in relation to assessing \"settled\" in relation to Australian citizens at paragraph 16.2.</p><p>Response to issue raised by MIA and Migration Alliance</p><p>A person is considered \"Settled\" if they have been \"lawfully resident in Australia for a reasonable period\", which is defined under policy as 2 years.</p><p>Policy is to be used as a guide, but cannot be applied inflexibly.</p><p>When assessing the \"settled\" requirement, the Department tries to adopt as consistent an approach as possible to ensure equity within the caseload. This is because the \"settled\" requirement is a time-of-application requirement, and as such, may influence the date on which applicants will lodge an application. That is, they will wait until they can meet this requirement before lodging. In some cases, this may mean they may lodge months or even more than a year later than they would otherwise choose.</p><p>If the 2-year policy guide is applied inconsistently, then this will allow some applicants to lodge and have their applications approved earlier than others, who may wait until the 2-year period is met. The practical effect of being able to do this is that the applicant will then receive a queue date few months earlier than another applicant. This may translate into a visa being available for grant years before the next person\"s. For this reason, we try to ensure equity in the management of the caseload by applying the policy as consistently as possible.</p><p>That said, each case must be assessed on its individual merits, and where there are compelling reasons to depart from policy, these need to be given serious consideration. For the purposes of consistency, only exceptional and compelling factors should lead to departure from policy. Factors that may give rise to such consideration may include, for example, cases involving minor children. Other examples may also be where the child has had previous long-term residence in Australia, but has been absent during the past 2 years or so to accompany a partner or spouse overseas for work commitments.<br />Yours faithfully<br />Liana Allan<br />Convenor <br />Follow me on twitter: @lianaallan </p>'),(83,83,'<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 澳大利亚移民和公民部部长，国会议员克里斯&middot;鲍恩宣布：吉拉德政府将延长澳大利亚公民和永久居民的父母探亲签证的逗留期限，以使他们来澳洲探亲时能够呆得更久。 &nbsp;&ldquo;我知道许多人都在耐心地排队等待父母签证，因此我们想提供更宽松的探亲签证，以满足定期延长探亲期限的需要。&rdquo;鲍恩先生说道。</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &ldquo;政府将向合格的已经递交澳大利亚境外父母签证（103签证）的申请人颁发五年期的探亲签证，每次入境后准许逗留12个月。&rdquo; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &ldquo;政府也考虑为目前没有进入父母签证（103签证）等待队列的人提供长达三年的探亲签证，每次入境后准许逗留12个月。&rdquo;</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 这些变化认可了父母在澳洲对于子女和孙辈所起的重要辅助作用以及这样的探亲所带来的社会公益性。 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 这些变化已在2012年11月24日实施。</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &ldquo;父母探亲签证的下签将会视情况而定，而且可以使父母在等待父母签证下签期间在澳洲与子女共处更长的时间，&rdquo;鲍恩先生说道。 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &ldquo;要想获得父母探亲签证，申请者必须满足澳大利亚的健康与品格要求，需有足够的资金，有能覆盖他们在澳洲停留期间的医疗保健花费的健康保险，并且应该有来澳探亲的真实意图。&rdquo; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 父母探亲签证的持有人需服从在澳洲期间申请其它签证的限制条件。与其它旅游签证持有者一样，每一次来澳洲探亲之后他们需要在澳洲境外呆上一段时间才能再次入境澳洲。</p>'),(84,84,'<p>申请人必须通过家庭平衡测试</p><p>申请人的子女至少有一半在澳洲定居; 或者申请人在澳洲定居的子女比在其他任何一个国家都多。&nbsp;</p><p>只有&ldquo;年老&rdquo;父母可以在澳洲境内申请884（或864）签证（年老指的是男性65岁，女性约62岁，根据出生日期不同而定），但父母双方只需一人在申请时满足&ldquo;年老&rdquo;即可。</p><p>如果父母在澳洲境内申请884（或864）签证，父母在澳必须持有实质签证，不能是亲属担保旅游签证，没有&ldquo;8503&rdquo;不准境内延签（或申请新的签证）的限制条件。</p><p>如果父母的签证上都有8503条件的限制，他们只能申请143付费父母签证（永居）或173付费父母签证（临居）。</p><p>具体做法是：递交申请时，他们可以在澳洲境内，也可以在澳洲境外。他们的旅游签证到期时，必须按时离境。当父母签证批准时，他们必须在境外贴签。</p><p>&nbsp;</p><p>移民可以领取养老金或其它福利金吗？</p><p>不可以，无论付费和不付费澳大利亚父母移民都要在澳洲永居十年之后才能领取养老金。其它类福利金：以父母移民签证入境的父母，如果落地之后，成为残障人士可以领取残障人津贴，落地之前已经是残障人士的不能领取残障津贴。如果父母落地之后又生孩子，可以领取家庭税务津贴，但没有父母津贴，不能领取新开始津贴和学习津贴。</p>'),(85,85,'<ol><li>您的孩子需要是澳洲公民或永久居民或是符合要求的在澳新西兰公民，并满足在澳洲居住2年的要求。</li><li>您的孩子或者是孩子的配偶需要担保您（如果您的孩子在18岁以下，只要符合移民部要求，其他的人也可以担当您的担保人。）</li><li>如果是在澳洲境内申请，主要申请人需要满足年龄要求。</li><li>需要符合家庭成员分布比例测试（Balance of Family Test）。</li><li>有良好行为。</li><li>到达健康标准。</li><li>永居签证申请需要提供足够的经济担保来支付父母在澳洲最初2年（普通父母移民类）或10年（付费父母移民类）里可能会有的相关开销。</li></ol>'),(86,86,'<p>父母移民可分为普通父母移民（parent category）和付费父母移民（contributory parent category）。普通父母移民比较简单，仅仅以父母年龄来划分，分为parent（Subclass 103）和aged parent（subclass804）。这类移民首期申请费和二期申请费比较少，经济担保也只要在父母拿到签证后在澳洲住满两年即可。唯一的缺点是由于前几年大批移民涌入澳洲，这类队列排得很长。以移民局每年发放500个名额的速度，现在递申请至少也要10－20年才能拿到签证，可谓遥遥无期。付费父母移民也同样按照父母年龄划分，只是中间又加了一个两年临居种类。143付费父母签证（永居）；173付费父母签证（临居）；864年迈付费父母签证（永居）；884年迈付费父母签证（临居）。此类移民二期申请费金额巨大，而且费用每年上涨3％。2010年的二期申请费是A$34,330/人。但好处是速度飞快，平均一年搞定。划分父母年龄的界限大致在65岁（男），62（女），父母中若有一人到达年迈界限，便可申请年迈父母一类。</p><p>付费类别中永居和临居的区别则在于：永居一次性付完所有二期申请费，目前总数约7万(以父母两人计算），同时在交第二期申请费之前需要通过经济担保测试，最后直接拿到PR签证。临居类别的话只需要付60%二期申请费，而且不需要经济担保。但拿到只是为期两年的临居签证。这两年临居中，父母可以享受medicare等一切和永居同样的待遇，在两年临居到期中的任意一个时间，只要你觉得自己已经筹满另外40％的二期申请费，即可提出永居申请。申请费用大约为$180，申请后需要通过经济担保测试并交$15000（父母两人）抵押十年，再交上那剩余的40％二期申请费，拿到最后PR。注意，在临居转永居的时候不需要做身体健康检查。</p><p>&nbsp;</p><p>&nbsp;<strong>父母移民费用</strong></p><p>&nbsp;前面我们介绍了父母移民的类别，现在简要介绍一下各个类别的费用。以下费用我们以父母二人为例。</p><ol><li>首先，介绍一下普通父母移民的费用。因为周期很长，所以费用相对便宜。年轻类父母移民的首期申请费是AUD1705，二期费用是AUD1480/人。所以如果你的父母比较年轻，那么移民费用是AUD1705＋AUD1480&times;2＝AUD4665。年老类父母移民的首期申请费是AUD2525，二期费用是AUD1480/人。所以整个费用是：AUD2525＋AUD1480&times;2＝AUD5485</li><li>其次，介绍一下付费父母移民的费用。付费父母移民分临居和永居。临居和永居的区别在于：永居是一次性付完所有二期费用，而临居可以分2次付清；永居需要通过经济担保测试，而临居只有在转永居的时候需要通过经济担保测试。</li></ol><p>1)如果你的父母都在澳洲规定的领取养老金年龄（男65周岁，女的视出生年月而定）以下，那么你就可以申请年轻类父母移民，这里有2种选择：临居和永居。如果申请临居，其费用如下：首期申请费AUD1705，二期费用AUD20595/人&times;2，转永居的时候申请费是AUD230，二期费用是AUD13730/人&times;2，所以整个费用是： AUD1705＋AUD20595/人&times;2＋AUD230＋AUD13730/人&times;2＝AUD70585 如果直接申请永居，首期申请费是AUD1705，二期费用是AUD34330，整个费用如下： AUD1705＋AUD34330&times;2＝AUD 70365</p><p>2) 如果你的父母有一位在澳洲规定的领取养老金年龄（男65周岁，女的视出生年月而定）之上，那么你就可以申请年老类父母移民，这里也有2种选择：临居和永居。如果申请临居，首期申请费是AUD2525，二期费用AUD20595/人&times;2，转永居的时候申请费是AUD230，二期费用是AUD13730/人&times;2，所以整个费用是： AUD2525＋AUD20595/人&times;2＋AUD230＋AUD13730/人&times;2＝AUD71405 如果直接申请永居，首期申请费是AUD2525，二期费用是AUD34330，整个费用如下： AUD2525＋AUD34330&times;2＝AUD 71185 另外，如需担保父母二人担保金大约在AUD15000。如果你是普通类的父母移民，那么只要你的父母在澳洲住满2年以后就可以取回这个担保金。如果是付费类的父母移民，那么要10年以后才可以取回。</p>'),(87,87,'<p>关于配偶签证可以有两种选择：</p><ol><li>您回国与未婚妻见面，订婚，然后她申请subclass 300 临时签证来澳洲。她进入澳洲9个月内必须与您结婚，否则，她的签证将过期。她与您结婚后，可以申请永居签证（820/801），从递交申请之日两年之后，双方仍生活在一起和满足签证条件，申请人可获永居签证。</li></ol><p>subclass 300 临居签证费：1995澳币</p><p>subclass （820/801）签证费：965澳币</p><p>&nbsp;</p><ol start=\"2\"><li>您回国与未婚妻结婚，然后她同时申请subclass 309 两年临居签证及subclass100永居签证来澳洲。两年后申请人将再接受永久居留签证法规的评估，假如婚姻关系破裂，持有临时居留签证者将无法取得永久居留权。</li></ol><p>&nbsp;</p><p>subclass （309/100）签证费：1995澳币</p><p>&nbsp;第一种选择，要交两次签证费，第二种只交一次签证费省965澳币。但两种选择各有利弊。</p><p>&nbsp;</p>'),(88,88,'<p>1）在申请临时居留签证时，申请人需具备以下条件　</p><ul><li>由澳洲公民、永久居民及合格的新西兰公民为其担保，担保人至少18岁以上。　</li><li>与担保人结婚，属合法且真实持久的关系，打算到澳洲后继续此关系。　</li></ul><p>&nbsp;2）担保人条件</p><p>　　担保人必须是法律接受的担保人。通常必须至少在十八岁以上，如有需要，还必须提供经济担保。</p><p>&nbsp;3）作为配偶临时居留签证的担保人，还有哪些限制？</p><p>　　担保人除以上条件外，还须符合另一条件，就是五年之内不可有两次成功的配偶担保。另外如果担保人之前已成功担保一名配偶，那么在五年内，他/她不可以再担保另一名新配偶。如果担保人以前是通过婚姻关系被担保而获得澳洲永久居留权的，后来婚姻破裂，此担保人另寻配偶，新条文限制这类人员五年内也不可以担保其新配偶。</p><p>只有当申请在符合了上述全部要求时，申请人才会获得两年临居签证。在两年临居期间申请人可以工作。从递交申请之日起两年之后，双方仍生活在一起或满足以下条件，申请人可获永居签证。</p><p>&nbsp;&nbsp; 4）申请人获永居签证需具备的基本条件</p><ul><li>持续性地得到担保人的担保。</li><li>持有配偶临时居留签证。</li><li>仍与担保人保持真实及持续的关系，并且至少两年前已申请临时居留签证。</li><li>如与担保人的关系已中止，但若是由于家庭暴力、担保人死亡等原因造成关系中止，申请人仍有可能获取永居签证。</li></ul>'),(89,89,'<p>本文导读：一些中国人正以自己的方式撩拨世人的神经。他们在海外市场上甩出的大把钞票，让外国人一次次瞪大双眼。<br />　　一些中国人正以自己的方式撩拨世人的神经。他们在海外市场上甩出的大把钞票，让外国人一次次瞪大双眼。</p><p>　　3月26日，在法国南部城市图卢兹，正在拍卖的乾隆玉玺和清朝宫廷画精品《乾隆大阅图》第四卷《行阵》，均被不愿透露姓名的中国买家拍走。据法国媒体报道，乾隆玉玺被中国买家以1240万欧元的高价拍走，刷新了印章类拍品价格的世界纪录。《行阵》更是拍出2205万欧元高价，刷新了亚洲艺术品在法国的拍卖纪录。</p><p>　　国人这种一掷千金的派头，近年并不鲜闻，再加上中国对外投资规模的不断扩大，一些海外媒体甚至发出了&ldquo;中国正在购买世界&rdquo;的惊呼。根据英国广播公司的报道，一份在27个国家28000人当中进行的调查显示，这些国家的公众对中国经济实力的担忧正逐步增加。这些担忧主要存在于中国的一些关键贸易伙伴国中，在富裕国家尤其显著。</p><p>　　<strong>&ldquo;中国梦&rdquo;与&ldquo;中国口味&rdquo;</strong></p><p>　　多年来，中国经济跨越了一个又一个里程碑：全球最大的汽车市场、全球最大的能源消费国、头号出口国和全球第一的制造大国。对此，西方人可谓爱恨交织。但除了担忧，他们也很清楚，中国人越来越鼓的钱包，似乎意味着不可限量的游动资本和投资冲动。</p><p>　　中国人的老朋友、美国芝加哥市市长理查德&bull;戴利对这些资本早已充满期待。2011年3月18日到30日，戴利一直奔走于北京、天津、杭州、重庆和香港5大中国城市中。</p><p>　　他在芝加哥市长任上，已经干了22年，将在今年5月卸任。而他一直有个未曾实现的梦想&mdash;&mdash;从芝加哥市区修一条通往奥黑尔机场的高速铁路。</p><p>　　但芝加哥市政府的现状，让戴利无法实现他的梦想。在他治下的这座城市，经济已显萧条，市政府的财政也出现危机。</p><p>　　&ldquo;我现在的梦想在中国。&rdquo;出发前，市长在当地媒体上高调宣称。他要带着芝加哥市的商业领袖们，到中国寻找投资，以带给芝加哥市新的&ldquo;机会&rdquo;。美国的媒体也将戴利此行，比喻为芝加哥市长追逐他的&ldquo;中国梦&rdquo;。</p><p>　　在北京，戴利坦率地告诉新老朋友们，中国经济崛起所显示出来的巨大潜力，已经激起美国各个州市的极大兴趣，&ldquo;扩展我们与中国的联系，采取行动正逢其时&rdquo;。</p><p>　　就在戴利乘坐汽车，前往各地的讲台发表演讲，向中国推介芝加哥市时，一些顶级汽车制造商，已经将中国客户的脾性摸得一清二楚。</p><p>　　3月28日，英国《金融时报》报道，中国继德国和美国之后，成为奔驰公司的第三大市场，并且是其顶级旗舰车型&mdash;&mdash;S级轿车的最大市场。而去年，奔驰在中国大陆地区的单位销量增长了115%。</p><p>　　他们也比芝加哥市长更早地将目光投向了中国富人的腰包。去年，该公司甚至用飞机运送了100位中国客户到德国和美国洛杉矶，为他们即将生产的豪华汽车的外部涂饰与内部功能提意见。最终，他们得出答案，&ldquo;中国客户偏好最大、最昂贵的车型&rdquo;。</p><p>　　这些汽车制造商们的细心程度，恐怕超出很多人的想象。大众公司在设计生产奥迪Q5时，加入了温控杯架，因为他们发现，&ldquo;中国客户走到哪儿都喜欢带着茶杯&rdquo;。而通用汽车在设计新车型时，也专门为中国客户设计了宽敞、舒适的后座空间。加长车身并把后座设计得更舒适，也是这些制造商为中国客户设计豪华汽车时的共同特点，因为&ldquo;中国的有钱人一般都让专职司机开车&rdquo;。</p><p>　　中国客户的这些特殊癖好，已经对汽车制造商的生产设计产生影响，不过，有分析指出，这种影响暂时还停留在车型的配置及涂饰上，在未来，中国客户可能会更关注汽车的驱动速度，这将会影响汽车的核心技术。</p><p>　　中国人对速度的追求，也让越来越多的外国人无法忽视。令戴利市长一直印象深刻的是中国经济的快速发展。而这次中国之行，让他吃惊的，是中国高铁的发展速度以及中国高速列车前进的速度。</p><p>　　3月23日，从北京到天津访问时，戴利特意选择乘坐京津高铁。在天津匆匆7个小时的行程结束后，这位欣然接受了天津市&ldquo;荣誉市民&rdquo;称号的市长坦言，高铁留给他的印象最深。</p><p>　　芝加哥市长坐在乘客座位上，看着景物飞一般掠过车窗，感叹道：&ldquo;安静、高速，让人觉得不可思议。&rdquo;</p><p>　　<strong>世界市场上的中国面孔</strong></p><p>　　通过在几大城市的访问，已是第5次到中国访问的戴利，再次看到崭新的中国面孔。</p><p>　　而在世界各地的各种奢侈品市场上，人们也见到了一些&ldquo;不可思议&rdquo;的中国面孔。</p><p>　　图卢兹的高价拍卖事件，再次将人们的视线拉回4个多月前。那时，中国艺术品创造了亚洲艺术品拍卖的世界纪录，而买家则是中国上海的一名企业家。</p><p>　　2010年11月，在英国伦敦郊外的一场小型拍卖会上，一件清乾隆粉彩镂空瓷瓶被这名中国企业家以折合人民币约5.5亿元的天价拍走。这超过估价36倍，也打破了此前黄庭坚书法《砥柱铭》以4.3亿元人民币创下的中国艺术品拍卖纪录。</p><p>　　中国艺术品价格的飙升速度，令外国人咋舌，中国富人们出手之阔绰，也引起了海内外关注。</p><p>　　当时，《金融时报》记者史堤夫&bull;文森撰文称，天价花瓶背后是中国人的&ldquo;瓷器爱国主义&rdquo;。在他看来，中国的一些富人们，正带着爱国主义情结，急切地想买回本国文化遗产。这种&ldquo;瓷器爱国主义&rdquo;，当时在中国国内也引起广泛讨论。不过，不少人将这种&ldquo;爱国主义&rdquo;，看做是&ldquo;美丽的花环&rdquo;和&ldquo;浮云&rdquo;。</p><p>　　那件花瓶至今还引人关注，因为4个多月过去了，这位中国买家尚未付款。</p><p>　　但这桩悬而未决的大笔生意，似乎并未影响外国人对中国艺术品消费能力的判断。前不久出炉的《2010年全球艺术品市场：危机和复苏》报告称，中国在2010年已经超过英国，成为世界第二大艺术品和古董市场。</p><p>　　这份报告由欧洲艺术品基金会委托撰写。报告指出，由于去年富有的中国买家数量剧增，艺术品市场的价格也随之飙升。报告同时还指出，很多国家的奢侈品市场在2009年萎缩，但由于中国消费者的拉动，又在2010年开始出现复苏迹象。</p><p>　　在巴黎、在拉斯维加斯，甚至在香港的奢侈品店门口，人们时常会发现排队购买奢侈品的中国面孔。据报道，仅在2011年春节，就有多达5000名中国游客到拉斯维加斯的梅西百货购物，其中800名游客来自北京和广州，他们年收入在20万到100万人民币不等。</p><p>　　&ldquo;这仅仅是开始。&rdquo;北京大学文化产业研究院文化金融研究中心主任喻文益如此评价道。在他看来，目前中国人均收入在世界排名还不高，只有少数中国人在进行高端产品消费，随着中国经济的发展，中国人对奢侈品的购买能力，将会在世界上产生更大影响。</p><p>　　几乎在欧洲艺术品基金会发布报告的同一时间，知名咨询机构麦肯锡也发布了自己的一份报告，并作出类似的预测。他们认为，中国消费者在奢侈品上的支出，每年将以18%的速度增长，2015年将达到270亿美元左右。这意味着，中国的奢侈品市场规模那时将超过日本，位居世界第一。</p><p>　　这份报告也指出，中国富人与西方富人有天壤之别，中国富豪要比外国富豪年轻15岁，他们每笔交易的金额也更大。</p><p>　　对于这一点，伦敦的房地产商人感受更深。据英国媒体报道，最新研究显示，在伦敦市中心高端房地产市场，来自中国内地的买家去年在购买最昂贵住宅方面，超过了俄罗斯人，成为花钱最多的人。截至2011年2月，在过去的12个月时间里，中国内地买家在高端房地产方面的平均开支为650万英镑，中国香港的投资者则列第三位，平均花费是550万英镑。</p><p>　　这些中国买家尤其对面对海德公园、地处梅费尔区或玛丽勒地区以及波特兰街花园广场的房子感兴趣。他们的购房预算在800万到1500万英镑不等，并且已有中国买家以1175万英镑和2575万英镑的价格，购买了圣詹姆斯区的两处地产。</p><p>　　供职于北京一家公司的陈忆，专门从事海外投资置业的房地产营销代理业务，其业务重心是澳大利亚和新加坡等国的顶级滨海物业。在开展业务初期，陈忆发现，在澳大利亚置业的中国家庭，多是为了移民或留学，一般比较喜欢买公寓，房价算下来跟北京和上海差不多。但这几年，在澳大利亚购房的人呈增加之势，出于投资目的的购房者开始增加，大概占三分之一，买别墅者也已不是少数。</p><p>　　<strong>有谁可以购买世界</strong></p><p>　　&ldquo;更强劲的消费还在后头。&rdquo;喻文益说。他认为，经济发展带来了大量的资本聚集，这些资本都要寻求流通，最终都会导致对高端产品的大量购买。</p><p>　　卡内基国际和平基金会的中国问题专家佩蒂斯评论说，房地产、艺术品、邮票、珍稀波尔多葡萄酒等，都在以创纪录的价格交易，这种情况通常是在流动性过剩的时期出现。</p><p>　　投资银行家出身的哥伦比亚大学商学院教授贝姆认为，从1950年代中期到1970年代中期，日本也经历过高达两位数的经济增长时期，但后来增长逐渐放缓，到了1980年代中期，增长率只剩下5%～7%。银行的&ldquo;大量超额贷款&rdquo;人为推高了日本的经济增长率，也造成了1980年代末期股票和房地产市场的巨大泡沫。当时日经综合指数几乎触及40,000点，而20多年后的今天，日经指数已经跌破10,000点。因此，中国经济的走向令人关注。</p><p>　　那些跟着资本一起流动的中国富人，在澳大利亚当地人中间，也引发了不同的声音。&ldquo;有人觉得这些中国人会给城市带来新的活力，也有人认为中国人炒高了当地房价，增加了他们的生活成本。&rdquo;陈忆说。</p><p>　　纽约时报专栏作家和普利策奖获得者汤姆&bull;弗里德曼则指出：&ldquo;毫无疑问，中国的崛起与西方领军的民主国家的停滞和瘫痪相重合，这带给了西方人心理上的不安。&rdquo;</p><p>　　在欧洲，中国富人在伦敦和巴黎等地展现出的超强购买力，甚至有些让人惶恐。法国有媒体评论，富足的中国人&ldquo;从企业、土地到港口、债务，无所不买&rdquo;。英国的《经济学人》杂志也发表了&ldquo;中国全面购买世界&rdquo;的封面文章。</p><p>　　不过，戴利市长似乎不这么认为。他从美国出发前，有华人记者问这位即将到中国寻找投资的市长，是否会担心&ldquo;中国购买美国&rdquo;，或&ldquo;中国购买世界&rdquo;的情况发生。</p><p>　　市长觉得谈论&ldquo;中国购买世界&rdquo;为时尚早。他淡定地回应记者：&ldquo;美国在世界各地投资，我们也没有买下世界。&rdquo;</p><p>　　对于让海外讶异的&ldquo;中国人的超强购买力&rdquo;，喻文益认为，从统计学上来讲，国家经济发展带来的资本流通和转移，必然带来各种优质产品的消费人群的增加。新兴经济体在高速发展时期，都必然会出现这种情况。</p><p>　　&ldquo;不仅中国如此，俄罗斯、印度和巴西等国家，都在经历类似的情况，其实俄罗斯对奢侈品的消费比中国更厉害。&rdquo;他对中国青年报记者说。（来源：中国青年报 记者 王波）</p>'),(90,90,'<p>　　就在中国国内对房地产限购之际，不少先知先觉的炒房人将目光投向了澳洲。南京范女士3年前花200万元在墨尔本买了一套房，最近已升值了100多万，3年收益率近60%。据业内人士介绍，目前在南京的高端人群中已形成一股投资澳洲房产的热潮。不过，需要提醒的是，澳大利亚个人所得税最高45%，在卖房时可能要缴一大笔税，最好事先想好避税办法。</p><p>　　<strong>租金与房贷相抵，还赚了100万</strong></p><p>　　范女士昨天告诉记者，2008年她花32万澳元购入澳大利亚墨尔本这套2房1厅的物业时，只付了20%首付，共6.4万澳元，其馀80%通过当地银行贷款支付的，当时并没有想到会赚这么多。因为她每月要还银行1500澳元左右的贷款，不过当地租金也不便宜，她这套房每月出租的租金也刚好1500澳元左右，正好与房贷月供相抵。因此，这3年她基本上没贴钱就养了这套房。而且由于澳大利亚经济的走好，3年时间她的房子增值了18万澳元!她女儿在墨尔本上学每年花费在4万澳元左右，所以这套房为范女士省了女儿上大学3年的费用。</p><p>　　记者按照范女士说的数字计算了一下，按2008年时的汇价计算，她当初买房的32万澳元相当于国内200万元人民币，现在这套房市价已涨至50万澳元，相当于320万人民币，短短三年，范女士就赚了120万元人民币。</p><p>　　像范女士这样以房养学的不在少数，市民王女士2003年在墨尔本为子女买了一套三房的别墅，价值50万澳元，四年房租收入为8.32万澳元，房产增值40万澳元，除掉子女留学费用以及贷款利息，她还赚了24万澳元。</p><p>　　<strong>澳洲住房短缺，买房政府有补助</strong></p><p>　　&ldquo;澳大利亚房价上涨并非偶然，而且这种上涨还持续了很多年。&rdquo;在南京从事澳洲房产投资仲介业务的澳大利亚四海集团大中华区首席代表张刚伟告诉记者，澳大利亚是全球资源大国，盛产铁矿石、金矿等产品，由于全球金融危机后各国竞相实行经济刺激政策，铁矿石等资源品不断上涨，因此澳大利亚是危机后最先复苏的国家，房价也随经济发展不断上涨。当地的《太阳先驱报》曾刊文指出，澳大利亚百多年地产每年平均上涨9%。从上世纪70年代至今的统计来看，墨尔本的房价几乎在 7~10年的週期内就会翻一倍。而且，由于澳大利亚自然环境好，移民人口大量涌入，近年来澳大利亚的住房开始短缺，根据官方的估计，到 2013年澳大利亚将出现21.3万套房屋短缺，这也为房价的上涨给予了有力支撑。为了鼓励投资者购房，澳大利亚政府2008年11月还出台法律，每年给每个买房人平均补助近万澳元，以此来带动当地房地产开发。</p><p>　　张刚伟表示，澳大利亚房价的持续上涨已经引起国内高收入人群的关注，为分散投资风险，最近不少南京人都在向他们谘询如何在澳洲买房。</p><p>　　<strong>海外置业要量力而行，先搞清税率</strong></p><p>　　记者注意到，在新街口金鹰等高档写字楼里，隐藏了不少像四海集团这样的海外房产投资仲介。据业内人士介绍，这些海外投资置业仲介，主要分美国和澳大利亚两大类，由于国内投资渠道狭窄，而且又实行限购政策，因此这些仲介都将目光瞄准了手中有大量资金閒置的高端投资者。</p><p>　　那么，投资海外房产一定就会赚钱吗?还要注意些什么?对此，南京某银行理财分析师认为，在目前国内股市、房市不景气的情况下，投资海外房产虽然能分散风险，但在购买前一定要根据自己的风险承受能力，不要盲目投资。比如2008年金融危机爆发后，美国房价暴跌，很多人急急忙忙去抄底，结果2009年至今，美国房价还在下跌，把这些抄底的人都套住了。澳大利亚的经济虽然比较好，房价也在逐年上涨，而且买的房子都是精装修，享受永久产权，免征房地产遗产税，但是该国的税率比较高，个人最高大约要缴年收入的45%，因此再卖房可能要缴一大笔税。所以，建议投资者在购买前一定要了解清楚，最好是能採取一些避税策略，否则赚的钱都交税了，白辛苦。</p>'),(91,91,'<p>在澳洲，除了墨尔本之外没有哪座城市的人口有如此快的增长速度。随之给基础设施和公共服务带来了很大压力，公共交通拥挤、出行缓慢、医院急诊等待时间太长等等。这或许是工党2010年维省大选溃败的关键原因。人们不免担心，墨尔本多次名列世界最宜居城市前三甲，在人口暴增的趋势面前，还能保持优势吗？</p><p>∙自2001年以来，墨尔本新增居民60.5万，幅度达到17%，远远超过了悉尼的44.7万人，布里斯本的38万人和柏斯的30.3万人。墨尔本城市边缘朝四面八方急速扩张。</p><p>∙过去9年来，新墨尔本人足以填满6个巴拉瑞特（Ballarat）、3个霍巴（Hobart）和1个黄金海岸（GoldCoast）。</p><p>∙2010年澳洲的人口增涨了25.78万，而墨尔本增长了7.9万，平均每周增加1500余人。墨尔本连续九年蝉联澳洲人口增长最快的城市。</p><p>&nbsp;</p><p>总体上，澳洲省会城市的人口增长率从2008-2009年度的2.2%降到了1.8%。达尔文的人口增长最微弱，其次是柏斯。澳洲统计局（ABS）的数据显示，2009-2010年度产生的新澳洲人，足有三分之一都住在墨尔本。在这一年当中，移民澳洲热潮悄悄平息，而墨尔本却再一次成了澳洲人口增长的中心。</p><p>虽然悉尼依然是澳洲人口最稠密的城市，但它与墨尔本的差距已经不足50万人。到去年6月30日，悉尼的人口暂时定格在457.5万人，而墨尔本则是407.7万人。这是墨尔本30年来第一次与悉尼如此靠近，后者在2009-2010年间增添了7.56万居民。如果增长率保持不变的话，那么到2028年墨尔本就将超越悉尼，届时两个城市的人口都将在560万上下。</p><p>墨尔本的外围郊区比澳洲其它任何地方都发展得快，西南部的温德姆（Wyndham）人口增长率8.8%，西北部的梅尔顿（Melton）人口增长率7.1%，东南部的卡迪尼亚（Cardinia）人口增长率6.7%和北部的惠特尔西（Whittlesea）人口增长率6.1%，它们是澳洲人口增长最快的四个地区。相比之下，昆省海滨城市也好，西澳矿业重镇也好，都只能望尘莫及。</p><p>&nbsp;</p><p><strong>省政府不会放慢维省人口增长速度</strong></p><p>&nbsp;维省省长百鲁4月1日表示，维省不会停止引进人口，维省居民仍需忍受一段时间的交通堵塞和拥挤的公共交通现象。但维省政府保证会改善基础设施，以鼓励维省居民到墨尔本以外地区居住。</p><p>百鲁表示，蓬勃发展的人口对于维省非常有利，他并不想阻碍此发展。他对媒体说：&ldquo;我认为我们不应该打出拒绝人口进入的牌子。维省目前的人口急速增长对维省的规划和投资都很有好处。&rdquo;</p><p>他还表示，维省当前拥挤的公共交通及道路堵塞在一段时间内会无法得到解决，但这是由于前任工党政府在这方面没有进行投资造成的。他说：&ldquo;我知道维省目前的交通状况令人难以置信的沮丧，但我们却无法在一夜之间改变现状。&rdquo;</p><p>维省规划厅长盖伊（MatthewGuy）说，维省政府计划通过提高边远地区及大都会区的基础设施和就业来防止城市扩张，他于周五在ABC电台上说：&ldquo;我想没有人会认为墨尔本能发展到如沃勒格尔（Warragul）或西摩（Seymour）之外去，我们需要仔细了解墨尔本都会区和市区位于工作单位附近、位于现有的交通设施附近有哪些地方急需发展以及哪些地方可以容纳大量的人口变化及人口增长。&rdquo;</p><p>盖伊还透露百鲁政府已经拨款10亿澳元在位于Yarraville的Bradmill工厂的旧址上兴建一个占地26公顷的&ldquo;微型小区（mini-suburb）&rdquo;。这里距离市中心仅有8公里，公共交通便利。政府在这里建造1000套住宅、1个超市、1个医疗中心和1个图书馆。正在筹备中的同类项目还有FishermansBend、位于Kew的维省公路局（VicRoads）和位于墨尔本西面的E-Gate。</p><p>&nbsp;</p><p><strong>人口暴涨导致房市危机</strong></p><p>维省政府表示，在工党11年的执政时间里失败的房产政策是导致目前房市危机的原因。但反对党住房事务发言人RichardWynne对此称，工党2007年向社会和公营房产投入了5.1亿资金，创了维省历史上最大的一次性房产投资记录，可谓已经竭尽所能，而房市危机的真正的原因是人口暴涨。</p><p>据维省租户联盟（TenantsUnionofVictoria）发布的最新一期私人租金负担能力公报(PrivateRentalAffordabilityBulletin)显示，在任何一个大城市，一个最低年收入为2.95万澳元的四口之家要租住一户3室套房将花去他们收入的35%至60%。</p><p>事实上，任何家庭只要其房租超过总收入的30%就会承受&ldquo;租房压力&rdquo;，他们基本没有余力可以储蓄。在维省，一个维持最低收入、带2个小孩家庭租一间3室的房子要花去收入的36.8%。就算是像Preston这样的外城区，一套3室房393元的租金就占了他们收入的43.8%，这对典型的工薪家庭来说，仍是高不可攀。</p><p>那些靠政府补助为生者的情况，则更不容乐观。数据显示，为租住一个中等价位的单间公寓，墨尔本的养老金领取者必须付出收入的71%；一个单亲家长要为一个2室公寓支付补助金的68.1%。目前，若要租住墨尔本2室公寓中的一室，中等价位为每周170元，这占了任何一个拿找工津贴（Newstartallowance）者收入的63%。</p><p>&nbsp;</p><p><strong>去年官方利率数次上涨致住宅开工数量暴跌</strong></p><p>房产工业协会（HIA）的最新季度前景报告预测住宅开工数量的下滑将会导致全澳各地的慢性住房短缺危机恶化，使不断增加的人口更加难有安身之所。HIA称，今年全澳范围内开工建设的新住房预计将减少15%，只剩14万3430套。当前澳洲的住房缺口大约是20万套。HIA呼吁联邦政府引进新的刺激措施，譬如鼓励人们自己建房子的首置业补助。</p><p>维省的形势尤为严峻。这个曾经被称为澳洲新屋建设发动机的省份今年开工数将暴跌19%，只剩48170套的&ldquo;平庸&rdquo;前途。</p><p>在本文截稿时，获知MooneeValley赛马俱乐部将于未来数周内公布总体规划案的重头戏&mdash;&mdash;斥资14亿元在MooneeValley的赛马场上建造逾2000套公寓和排屋，开发面积达40公顷、预计将容纳6000人。</p><p>这也是继LatrobeValley的Latrobe市议会吁请省政府对其主要城镇（包括Traralgon、Morwell、Moe/Newborough和Churchill）边缘的574公顷土进行再分区，划为住宅开发区之后，又一应对墨尔本人口暴增的措施。</p>'),(92,92,'<p>澳洲政府一向把房地产业作为主要的支柱产业大力扶持，采取多项措施支持其发展，企业界尤其是金融界也采取了相应的举措。其中一项重要的政策就是鼓励海外人士买入澳洲房产，作为其个人投资组合的一部分，共同打造了一个对全世界开放的个人房地产投资市场。那末作为海外人士，甚至从未来过澳洲的人士，都可以享受到那些支持呢？</p><p>首先是在买房时可以享受到和澳洲本地居民买投资房同样的政策，即国民待遇。唯一需要多办的一个手续就是须经澳洲海外投资局（FIRB）的批准，只要买房人不是澳洲政府认为有损国家利益的人士，所买房产不是澳洲历史文化遗产名单上禁止出售的历史物业，通常都会在两周之内批准。除此以外，对海外人士没有其他特殊限制，在哪儿买，买什么，买几套都可以自由选择。</p><p>其次，澳洲银行对海外客户同样是积极支持，客人只需要提供简单的文件，如护照、驾照复印件，收入证明信，买房合同首页就可批出房价70%的贷款，有些项目、有些客户更可批出高达80%的贷款。而且利率和产品功能和澳洲本地客户完全一样。</p><p>第三，澳洲发达的金融业令海外投资人如虎添翼，有些支持甚至在其自己国家都不能享受到。如允许客户在前五年内只付利息，本金可以暂时不付，使贷款投资的客户轻松实现&ldquo;以房养房&rdquo;；房子升值后，不必卖房，只需简单地做个再评估，就可以把增值的部分兑现，把&ldquo;死钱变成活钱&rdquo;，实现滚动投资。</p>'),(93,93,'<p>2002年以来中国的房地产市场逐步升温，经过2003年的大幅上涨，2004年1到9月份的全国商品房价格涨幅仍达到了13%，商品房平均价格达到2777元，相比2002年底，在两年不到的时间里，价格上涨超过四分之一。对于住房这种关系到国计民生的特殊商品来说，这样的涨幅堪称暴涨。同时房地产市场繁荣火爆的景象从东南沿海局部地区开始，逐渐向全国大部分地区扩散，出现了经济基本面比较好的地区价格上涨，经济基本面不太好的地区价格也上涨的局面，甚至一些欠发达地区的价格上涨超过了发达地区。中国的房地产市场出现了住房市场化改革后的第一次全面繁荣，即使是2003年出现的&ldquo;非典&rdquo;和央行的121号文件对这一轮的房地产市场上行也没有构成多少实质性的影响。</p><p>伴随着这一轮房地产繁荣的，除了人均住房面积提高的统计数字和接连不断的违规拆迁、非法占用农田造成的惨痛故事外，留给人们印象最深刻的就是顽强上行的房地产价格和对房地产泡沫的各式各样的争论。早在2002年上半年，泡沫之说就已经出现，2002年11月，时任总理的朱容基表示了对房地产泡沫的担忧。在2003年6月央行出台了121号文件，此时对房地产泡沫的争论也达到了第一波高潮。此后开始的宏观调控更是引发了各界对房价涨跌的大论战。进入2004年后，随着每一季度经济统计数字的报出，看着日长夜大的房地产价格，对泡沫的争论也日趋白热化。2004年10月，建设部推出了关于房地产市场形势的报告，不久以后央行宣布了9年来的第一次加息决定，管理层对形势的看法和宏观经济条件的改变可能对房地产市场带来的冲击更成为利益相关各方关注的焦点，掀起了对房地产泡沫争论的第二波高潮，各路官员、学者、房地产商轮番上场，互联网上的讨论也是此起彼伏、异常激烈。</p><p>这场争论中，房地产管理部门、房地产商和一部分学者认为目前中国的房地产市场繁荣是有真实需求支撑的，所以不存在泡沫，而另一部分学者则认为现在的房地产价格远远超出了消费者的支付能力，出现了很严重的泡沫，并且泡沫即将面临破灭。对此，我们要用这篇文章来说明我们的看法，我们的看法可以用三句话来概括：第一，中国出现了明显的全局性房地产价格泡沫；第二，虽然房地产泡沫非常明显，但价格很难大幅下跌；第三，虽然价格不会大跌，但也决不是什么好事。</p><p>纵观历史上从郁金香狂热开始到上世纪末的互联网热潮历次著名泡沫事件，我们可以得出只要是泡沫就没有不破灭的结论。但是如果要把这个结论套在目前中国的房地产市场上似乎很难行得通，其中最根本的原因在于，目前中国的房地产市场是一个半市场化的市场，市场价格的形成不完全是买卖双方讨价还价、利益均衡的结果。在现在的房地产市场运行机制中牵扯到了太多的利益，因此价格形成远远不是供需平衡那么简单。如果有一天市场的力量强大到了利益任何一方都无法抵挡的地步，中国的房地产市场才是真正实现了市场化。</p><p>我们对此的价值判断与经济学告诉我们的结论是一样的：是泡沫，最好让它破灭，而且越早破灭越好。因为泡沫的出现扭曲了市场价格体系，会导致资源的无效配置，泡沫持续时间越长，资源误配的效率损失越大，泡沫破灭越早，对整体经济的冲击越小。然而这个看起来谁都明白的道理在现实中似乎不那么容易把握，否则就不会有泡沫破灭后连续衰退14年的日本经济。</p><p><strong>中国出现了明显的全局性房地产价格泡沫</strong> <br />在对这个论点进行论证之前，我们要先说明一个本不需要说明的问题，那就是究竟什么是泡沫？在我们看到的争论中，相当一部分学者没有表现出基本的专业素质，比如有人就凭中国人多地少就可以喊出了&ldquo;房价若干年要涨若干倍&rdquo;的口号，反映出其对资产价格的规律缺乏起码常识。在我们不愿意怀疑其动机的情况下，只能怀疑其专业素质。</p><p>在经济学里，影响最大的泡沫定义是以研究金融危机著称的经济学家金德尔博格（Kindleberger）在《新帕尔格雷夫经济学大词典》中给出的： <br />&ldquo;泡沫状态&rdquo;这个词，随便一点说，就是一种或一系列资产在一个连续过程中陡然涨价，开始的价格上升会使人们产生出还要涨价的预期，于是又吸引了新的买主&mdash;&mdash;这些人一般只是想通过买卖牟取利润，而对这些资产本身的使用和产生盈利的能力是不感兴趣的。随着涨价常常是预期的逆转，接着就是价格的暴跌，最后以金融危机告终。通常，&ldquo;繁荣（Boom）&rdquo;的时间要比泡沫状态长些，价格、生产和利润的上升也比较温和一些，以后也许接着就是以暴跌（或恐慌）的形式出现危机，或者以繁荣逐渐消退告终而不发生危机。</p><p>金德尔博格对泡沫的定义比较形象，但是在理论研究中比较难以操作。现代的经济学研究通常将泡沫定义为资产价格对其基本价值的持续性偏离。这样的定义简化了对泡沫的判断，所需要做的工作有两点，一是决定资产的基本价值，二是看资产价格的偏离是持续性的还是在很短的时间内就消失。</p><p><strong>1. 当前的房地产价格反映其基本价值吗？</strong> <br />要回答这个问题并不困难，我们可以从两个层面来分析房地产的基本价值。房产做为一种商品，与其他商品&mdash;&mdash;比如面包和股票相比，有着比较特殊的属性。那就是它既可以像面包一样做为一种消费品满足人们的消费需求，又可以像股票一样做为一种投资品满足人们投资获利、实现消费跨期替代的愿望。只有弄清楚房产做为这两种商品属性的价值，才可以确定的它的基本价值。</p><p>首先做为消费品，房产的基本价值可以这样确定，微观经济学告诉我们，完全竞争的市场中，商品的均衡价格等于其生产的边际成本，在现代经济学中并不特意区别价值和价格，可以认为，供需决定的均衡价格就是它的基本价值。做为投资品，可以由资产定价的基本原理决定，生息资产的基本价值等于预期的未来现金流的贴现和。对于房产来说，把预期的未来每一年的租金和最后一年房产的残值贴现到当前，就是它的基本价值。我们可以从这两个方面来衡量房产做为消费品和投资品的基本价值。</p><p>先来看看做为消费品，现在中国的房子应该值多少钱。首先从供给这一方看，因为近年来房地产市场一片火爆，许多地方的楼盘都是在开盘前几天开始排队，开盘当天甚至几个小时之内就销售一空，在卖方市场的情况下，开发商没有理由以低于边际成本的价格卖房，这样实际的成交价格一定是高于边际成本的。因为定价权掌握在卖方手里，做为买方的消费者就成为价格接受者。卖方要做到利润最大化，可以将价格提高到买方所能接受的最高价格，在经济学上称为保留价格。如果我们很难得到开发商的边际成本数据，我们可以利用消费者这一方的数据推算出购房者的保留价格。如果房子的实际价格高出了消费者的保留价格，那么做为消费品，它的价格可以认为是被高估了。值得一提的是，即使是以保留价格成交，价格仍有可能是高估的，因为开发商可以采用囤积不卖的方式提高价格直到达到购买者的保留价格。这种情形在整个市场处于上行的阶段，即使开发商之间是完全竞争的，仍然有可能出现。自2003年以来，已经有几个城市政府针对开发商有房不卖出台了惩罚措施，也从一个侧面反映了这个现象。</p><p>下面我们估算一个代表性的消费者所能接受的对住房的保留价格，或者说是代表性消费者所能接受的住房的价格。假定这个代表性的消费者拥有全国城镇居民的平均财富和平均收入，她利用自己现有的财富和未来的收入为购买住房融资。按2002年6月进行的我国首次《城市家庭财产调查》报告，我国城市居民户均资产22.83万元，其中金融资产7.98万元，占34.9%，房产10.94万元，占47.9%，其他为耐用消费品和经营性资产。2003年底，我国城镇居民人均可支配收入为8472元，户均人口为3.1人，这样每户平均的可支配收入为26263元。</p><p>假定这个消费者将自己的现有房产以9折变现，做为首付款购买新房，未来收入中的一部分支付按揭款。那么收入中究竟有多大一部分可以用作房款支出对可买新房的售价有很大影响。我们可以这样分析这个问题，2003年底，我国城镇居民的恩格尔系数为37，就是说居民有37%的收入用于食品支出，如果假定消费者用30%的收入支付按揭款，剩下的33%支付衣物、交通通讯、娱乐教育、医疗保健等其他生活支出和必要的储蓄，事实上这样的生活已经算不上宽裕了。就是说对于中等收入家庭来说，30%的收入用于供房已经是上限了。这样可以用于支付按揭款的收入为7879元，按照现行的5.31%的按揭利率，加上以现有房产支付的首付款，代表性消费者所能支付得起的住房价格为：当采用20年按揭时，为19.4万元，当采用30年按揭时，为21.5万元。</p><p>因为住房是一种不连续的商品，所以在市场上不可能买到任意大小的房子。根据对房地产市场的调查，一般两居室的住宅建筑面积为90～120平方米，三居室的住宅建筑面积为110～140平方米。假定消费者可以买到的房子平均为100平方米，按照当前的价格，房屋总售价为27.8万元。这个价格比消费者采用20年或30年按揭时的保留价格要分别高出43.3%和29.3%。</p><p>有人会说，在上面的计算中，没有考虑消费者未来收入的增长。如果消费者未来的收入增长了，她可以用来支付的按揭款也可以增长，那么她可以购买的住房价格会有所增加。这个看法是正确的，但是在当前的现实中还很难实现，因为通常银行不会允许递增还款的方式，这样做等于要求银行确信消费者未来的收入一定会以某一速度增长，这增大了银行的经营风险。虽然这样的融资方案在现实中还不可行，我们还是算出当消费者收入增长时，她可以支付的范围价格。假定消费者可以用于住房按揭的支出每年增长4%（我国目前城镇居民人均收入增长约为7%，考虑未来二、三十年的时间尺度内的风险调整因素，4%的增长速度是比较理性的），则采用20年或30年按揭的时消费者可以支付的房价分别为23.2万元和28.7万元。在前一种情形下，实际价格高出保留价格19.8%，后一种情形下，保留价格比实际价格略高3.2%。必须指出的是，这里的价格度量是基于资源配置效率的度量，即认为让平均收入水平的消费者可以买得起平均价格的住房有着较高的配置效率，因为在这种情况下大部分居民的住房需求可以通过市场这个交易成本最低的配置手段解决。</p><p>综合上面的计算结果，目前国内的房屋价格远远高出中等收入消费者的承受水平，相对于消费者的保留价格，房屋价格大约高估了20～30%。</p><p>我们还可以从上面的计算结果得出隐含的消费者可以承受的房价收入比。我们认为房价收入比可以做为衡量价格泡沫的一个参考指标，但是这个指标要结合各个国家的不同情况做一些调整。比如由于经济结构和税制上的原因，每个国家的居民可以用于支付住房费用的能力是不同的，另外住房贷款的可获得性以及利率高低都是影响房价收入比的合理水平的重要因素。根据上面的计算，当不考虑住房支付能力增长时，中国城镇居民可以承受的房价收入比为7.4～8.2，考虑增长时，这个数据为8.8～10.9。必须指出的是，这两个数据均远远高于3～6的国际标准，这是因为我们这里计算的是消费者所能承受的最高的房屋价格，而不是让她感觉能轻松支付的房屋价格。当她以这个价格支付住房消费时，她应该正过着紧紧巴巴的生活。然而更不幸的是，现实中的房价比这个价格还要高出20～30%。</p><p>为了使讨论更富启发性，我们把这一轮房地产市场火爆的明星城市&mdash;&mdash;上海的这几项数据也列在这里。2003年，上海的人均可支配收入为14867元，是全国城市平均水平的1.75倍。假定上海的户均资产也是全国城市平均水平的1.75倍。其他数据和上面的计算一样。我们得出的结果是：当不考虑住房支付能力增长时，上海中等收入家庭采用20年和30年按揭可以支付的房价分别为34.0万元和37.7万元，当考虑增长时，这两个数据分别为40.6万元和50.3万元。按照2004年9月上海住宅8200元的实际成交均价，四种情况下，实际价格比保留价格高估了141.2.1%、117.5%、102.0%、63.0%。</p><p>按照这个计算，即使是上海最乐观的拥有平均收入消费者也绝对没有可能性去买一套平均价格的住宅。值得指出的是，这里的计算数据是有事实基础的，在上海2003年的两次房交会上，对希望购房居民的调查表明，70%以上的居民表示可以接收的住房价格不高于5000元每平方米，这个数据与这里的计算是一致的。</p><p>上面分析了做为消费品，目前中国的商品房价格是被远远高估的，那么如果做为投资品，是否可以解释如此高的房价呢？按照资产定价模型，资产当期的价值等于未来现金流的贴现和，所以资产的基本价值与以下几个因素有关：租金、租金的增长速度、投资的要求回报率、房屋的残值。因为我国房屋的设计使用年限是50年，而房屋产权年限是70年，因此考虑折旧以后，房屋的残值可以忽略不计。</p><p>在一段时间里，如果房屋的价格出现持续上涨，而且这个上涨是由于房屋资产的基本价值的提高造成的，那么必定会出现以下情况中的一个或几个：租金增加了；租金增长的速度加快了；投资要求的回报率降低了。</p><p>但国内的现状如何呢？从1998年全国房价出现稳步上扬开始，全国的房屋租赁价格指数保持平稳，2000年以后房屋租赁价格指数开始稍有上涨，每年的涨幅大约为1%，而同期房屋价格的涨幅每年约为7%，同时房屋价格与租赁价格之间背离呈现越来越大的趋势。至于投资的要求回报率，如果用银行储蓄利率做为度量，则也没有太大的变化，自2002年2月开始，利率水平始终保持稳定。就算从1999年起算，储蓄利率也不过是从2.25调整到1.98，下调幅度仅仅12%而已。并且投资要求回报率的变动也没有利率变动这么敏感，因为投资者不太可能预期未来的几十年里始终保持这么低的利率水平。</p><p>从这几个与房屋基本价值有关的基本面的因素来看，近年来尤其是2003年以来的房地产价格上涨与基本面因素变化的关系不大。 <br />总之，无论是做为消费品还是做为投资品，当前的房地产价格都不能反映其基本价值。从全国来看，房地产价格高估的程度应在20%以上，部分城市高估的程度则更为严重。因此，我们说中国的房地产市场出现了明显的价格泡沫现象。</p><p>另外之所以说这一次的房地产泡沫现象是全局性的，是因为我们可以看到从沈阳到海口、从上海到成都，全国主要城市都出现了房地产价格同步上扬的现象。房地产价格本应该是区域经济发展的一个动态反映，如果在遍布各个区域的大城市中都出现了价格大幅上涨，应该称得上是全局性的。即使在日本泡沫经济的巅峰时期，也有部分偏远地区地价基本没怎么上涨，但谁又能否认日本出现的是整体的泡沫经济呢？虽然我国当前出现的房地产泡沫与日本当年相比还有一定距离，但也不能说非要等到石河子、海拉尔都出了泡沫的时候才能叫全局性泡沫。</p><p><strong>2. 当前中国的房价水平究竟高不高？</strong> <br />上面我们说明了相对于居民的收入，目前的中国的房价确实被高估了，尤其是在大城市，价格高估现象非常明显。如果中国的房价放在世界范围里来看，究竟算不算高呢？</p><p>首先我们看看日本房地产价格在泡沫经济前后的表现。日本从上世纪80年代中期开始到90年代初破灭的泡沫经济是人类历史上最著名的泡沫事件，既便是一贯爱吵架的经济学界对当时日本泡沫经济的实质的认识也达到了空前的一致，国内的学者在讨论泡沫问题时也通常是言必称日本泡沫经济。那么我们看看在这个最著名泡沫事件中房地产价格究竟表现如何。</p><p>按一般的看法，日本的泡沫经济自1985年的&ldquo;广场协议&rdquo;开始，到1990年泡沫开始破灭结束，泡沫膨胀阶段用了5年的时间，1990年泡沫破灭以后，日本经济陷入衰退，直到现在14年过去，经济衰退仍然没有过去。根据日本不动产研究所的数据，在1990年泡沫巅峰时期，日本全国城市地价与1985年相比，5年时间里上涨了56.3%，东京、大阪等六大都市的地价，5年时间里上涨了168.6%。</p><p>再看看我国的数据，从2000年开始，我国各大城市土地交易价格出现明显上涨。从2000年底到2004年第二季度，全国平均住宅用地价格指数在不到四年的时间里上涨了44.2%，部分城市地价上涨更为惊人，天津、上海、南京、重庆等地上涨均超过50%，杭州上涨则超过了170%。虽然土地的绝对价格与日本相比还有较大差距，但从全国平均的上涨幅度看并不输给日本当年，部分明星城市的表现则更为耀眼。</p><p>日本不动产研究所的报告显示，2003年，东京地区公寓式住宅的平均单价为54.5万日元每平方米，折合人民币4.3万元，每套住宅的平均价格为4096万日元，折合人民币约为320万元，目前上海市区的商品房平均单价约为1.25万元，平均每套售价约为150万元。这两项数据上海分别达到了东京的1/3和1/2。2003年上海的人均收入约为东京的1/15。值得一提的是，日本的住房购买者均拥有所占土地的产权，而我国房价中仅包含70年的土地使用权。</p><p>另外根据2003年美国商务部的发布的报告，2003年中期美国的单栋新建住房的全国中间价格为19.5万美元，全国平均价格为24.2万美元，折合人民币分别为160万元和200万元。美国的单栋住宅与我国相对应的同类住宅就是别墅，按照上海市的当前价格，类型相当的房子价格约为300～400万元，大约是美国平均水平的2倍。</p><p>如果按照某学者的提法，上海未来的房价应该在若干年内涨若干倍，因为在1990年房地产价格最高的时候，东京一地的所有物业价值就已经超过整个美国，那么可以由此做个大胆的预测，用不了20年时间，就算上海比东京面积小一些，我们也可以卖掉一个上海，而买回来大半个美国。天底下简直找不到比这更好、更便捷的富国之计了。</p><p><strong>3. 中国真的是人多地少吗？</strong> <br />鼓吹中国房价未来仍需要大涨的人有一个论据，那就是中国人多地少，土地资源紧张，当然可以有更高的地价和房价。这个口号有很多所谓的经济学家在讲台上口沫横飞地鼓噪了不知多少次了，但遗憾的是没有一个人愿意抽出5分钟时间，拿出计算器随便算一算。</p><p>是不是人多地少需要看和谁比，如果和俄罗斯、加拿大相比，世界上大部分国家都是人多地少的。中国平均的人口密度是每平方公里132人，日本、韩国、印度、越南、德国和英国的这个数据分别为336人、478人、338人、238人、230人、247人。如果用全国平均的数据说服力不强，我们只考虑人口最密集我国的东部沿海地区，我国东部大部分是适合生活的平原地区，这样与其他国家的全国平均水平相比应该比较有说服力。从辽宁到海南，我国沿海的13省、市、自治区的平均人口密度是每平方公里407人。这个数字与上述几个国家相比并没有本质差别，如果按适宜居住的面积计算，我国东部地区的人口密度低于日本、韩国和印度，比如在日本37.7万平方公里的国土中，不适合居住的山地和丘陵占去了75%，这样按适宜居住的面积计算，日本的人口密度超过了1300人每平方公里。另外如果考虑我国城市人口大多居住在多层和高层建筑里，而德国和英国人口大多居住在低层或独栋住宅里，我国人均居住所占用的土地面积要远小于德国和英国。在考虑到适宜居住的因素后，我国东部地区的人口占地密度应该不会高于德国和英国。</p><p>日本人口密度是中国东部地区的三倍，但是日本的地价可以连跌13年，2003年日本的全国城市平均地价已经跌到上世纪70年代末的水平，那么在我国人多地少能成为地价继续大涨的理由吗？</p><p>在中国目前有人正在制造一个与当年日本相同的&ldquo;土地神话&rdquo;。战后的日本由于经济快速发展，重化工业进程和城市化进程使土地供给不能满足需求，现实中的供需缺口加上投机者的推波助澜，使日本的地价在1990年以前连年上涨，造就了所谓的&ldquo;地价不灭神话&rdquo;。但是在造就了&ldquo;地价不灭神话&rdquo;的同时，也造成了产业资本的大规模外移。应该说东亚各国，尤其是中国，是日本&ldquo;地价不灭神话&rdquo;的最大受益者。现在如果中国也准备开始一段&ldquo;神话&rdquo;的话，捧场的绝对不只是&ldquo;神话&rdquo;的鼓吹者，等着捡钱包的越南和印度早就准备好了。</p><p>如果我们的学者脑中有开放经济的意识，他们就应该明白，世界上根本就不应该有什么&ldquo;土地神话&rdquo;。因为当我们进口粮食时，我们进口的不仅仅是粮食，我们进口的实际上是土地，当我们输出资本时，我们同样是在进口土地。土地虽然是死的，但是资本、人力、商品在开放经济的条件下都是可以流动的，全世界的要素价格一定是趋于一致的，如果中国的土地价格持续上涨，意味着我们失去的是资本流入，是就业，是城市化，是社会稳定，是一系列的事。所以&ldquo;神话&rdquo;离我们越远，我们的经济就越安全。</p>'),(94,94,'<p>随着EOI的出台，澳大利亚移民局开始按照市场需要设置给具体各专业的移民配额，这个配额直接关系各类打分的技术类移民的邀请机会，也是移民局希望大家不要一窝蜂选择同一个专业的手段。</p><ol><li>总裁经理类别的差不多有7000多人，海外英文好有5年以上的经验的商业人才可以考虑</li><li>广告销售经理居然也有7740人</li><li>金融经理有3420人</li><li>计算机行业经理，2580人</li><li>会计有10440，虽然比往年减少不少，但是毕竟还是第二大的职业类别，学会计的同学抓紧冲雅思7分和工作经验，外加100%加分的职业年和澳洲5分学历，争取65-70分移民应该问题不大</li><li>工程师类别移民局进行了细分：比如土木工程2640，电气工程1260，机械工程1620</li><li>教师类别：幼儿教师1680，中学教师有7020</li><li>计算机类别：ICT商业分析师有1800，软件开发5160人，数据库2400人，网络1740人，</li><li>建筑师、测绘师和施工管理：3360人，看来缺的很严重。这个行业其实也很有前景，留学生朋友可以考虑！</li></ol><p>&nbsp;10. 护士：居然有13380，不过护士毕业进行职业评估认证要雅思4个7，除非申请人在澳洲完成高中和大学，才可以豁免。</p><p>当然，这个清单里面也很多职业其实都是大冷门，比如，Medical laboratory Scientist 有1260人。</p><p>&nbsp;</p><p>总之，这个配额分配存在不少问题，很多职业的配额根本就不会被用完，希望移民局未来可以拿多些配额到SOL清单职业里面来。</p><p>&nbsp;</p><table><tbody><tr><td><p><strong>ANZSCO code</strong></p></td><td><p><strong>Description</strong></p></td><td><p><strong>Occupation ceiling</strong></p></td></tr><tr><td><p>1111</p></td><td><p>Chief Executives and Managing Directors</p></td><td><p>4260</p></td></tr><tr><td><p>1112</p></td><td><p>General Managers</p></td><td><p>3300</p></td></tr><tr><td><p>1211</p></td><td><p>Aquaculture Farmers</p></td><td><p>120</p></td></tr><tr><td><p>1212</p></td><td><p>Crop Farmers</p></td><td><p>2640</p></td></tr><tr><td><p>1213</p></td><td><p>Livestock Farmers</p></td><td><p>5400</p></td></tr><tr><td><p>1214</p></td><td><p>Mixed Crop and Livestock Farmers</p></td><td><p>1860</p></td></tr><tr><td><p>1311</p></td><td><p>Advertising and Sales Managers</p></td><td><p>7740</p></td></tr><tr><td><p>1321</p></td><td><p>Corporate Services Managers</p></td><td><p>540</p></td></tr><tr><td><p>1322</p></td><td><p>Finance Managers</p></td><td><p>3420</p></td></tr><tr><td><p>1323</p></td><td><p>Human Resource Managers</p></td><td><p>3000</p></td></tr><tr><td><p>1324</p></td><td><p>Policy and Planning Managers</p></td><td><p>1740</p></td></tr><tr><td><p>1325</p></td><td><p>Research and Development Managers</p></td><td><p>540</p></td></tr><tr><td><p>1331</p></td><td><p>Construction Managers</p></td><td><p>4800</p></td></tr><tr><td><p>1332</p></td><td><p>Engineering Managers</p></td><td><p>960</p></td></tr><tr><td><p>1333</p></td><td><p>Importers, Exporters and Wholesalers</p></td><td><p>1560</p></td></tr><tr><td><p>1334</p></td><td><p>Manufacturers</p></td><td><p>1140</p></td></tr><tr><td><p>1335</p></td><td><p>Production Managers</p></td><td><p>3240</p></td></tr><tr><td><p>1336</p></td><td><p>Supply and Distribution Managers</p></td><t